window.LIB_DUAS=[{"id":"ziarat-ashura","cat":"Ziyārah","t":{"en":"Ziyārat ʿĀshūrāʾ","ar":"زيارة عاشوراء"},"lines":[["السَّلام عَلَيْكَ يَا أبَا عَبْدِ اللهِ ،","Peace be on you, O Abu Abdullah!"],["السَّلام عَلَيْكَ يَا ابْنَ رَسُولِ اللهِ ،","Peace be on you, O son of the Apostle of Allah!"],["السَّلام عَلَيْكَ يَا ابْنَ أمِيرِ المُؤْمِنينَ ،","Peace be on you, O son of the commander of the faithfuls,"],["وَابْنَ سَيِّدِ الوَصِيِّينَ ،","the forebear of the successors!"],["السَّلام عَلَيْكَ يَا ابْنَ فاطِمَةَ الزّهراءِ سَيِّدَةِ نِساءِ العالَمِينَ ،","Peace be on you, O son of Fatimah, the choicest among the women of the worlds!"],["السَّلام عَلَيْكَ يَا ثَارَ اللهِ وابْنَ ثارِهِ وَالْوِتْرَ المَوْتُورَ ،","Peace be on you, O the select, surpassing, chosen in preference over all good of Allah, and son of Allah's (such) good."],["السَّلام عَلَيْكَ وَعَلَى الأرواحِ الّتي حَلّتْ بِفِنائِكَ ،","Peace be on you, who was martyred while fighting heroically in the cause of Allah, the son of Allah's fearless warrior, you were isolated and had been attacked with a vengeance!"],["وَأنَاخَتْ بِرحْلِك","Peace be on you and on those souls who had gathered in your camp, and strided along with you, in your journey."],["عَلَيْكُمْ مِنّي جَميعاً سَلامُ اللهِ أبَداً ما بَقِيتُ وَبَقِيَ الليْلُ وَالنَّهارُ.","I pray and invoke Allah to keep all of you tranquil and restful, for ever; so far I am alive, this is my prayer, and till nights and days follow each other."],["يَا أبَا عَبْدِ اللهِ ،","O Abu Abdullah!"],["لَقَدْ عَظُمَتِ الرَّزِيَّةُ ، وجَلّتْ وعَظُمَتْ المُصِيبَةُ","unbearable is the sorrow, nerve-racking is the agony, you put up with,"],["بِكَ عَلَيْنا وَعَلَى جَمِيعِ أهْلِ الإسلام ،","for us and for all the (true) Muslims,"],["وَجَلَّتْ وَعَظُمَتْ مُصِيبَتُكَ فِي السَّمَوَاتِ عَلَى جَمِيعِ أهْلِ السَّمَوَاتِ ،","crimes committed against you also shocked and unnerved the dwellers of the heavens, one and all."],["فَلَعَنَ اللهُ اُمَّةً أسَّسَتْ أساسَ الظُّلْمِ وَالجَوْرِ عَلَيْكُمْ أهْلَ البَيْتِ ،","May Allah condemn and damn the people who laid the basis and set up the groundwork, to wander astray and turn aside from not only you and your family but to take liberties and bear hard upon you."],["وَلَعَنَ اللهُ اُمَّةً دَفَعَتْكُمْ عَنْ مَقامِكُمْ","May Allah condemn and damn the people who tried to obscure and deny your office and status,"],["وَأزالَتْكُمْ عَنْ مَراتِبِكُمُ الّتِي رَتَّبَكُمُ اللهُ فِيها ،","willfully neglected your rank and class Allah had made know in clear terms."],["وَلَعَنَ اللهُ اُمَّةً قَتَلَتْكُمْ ،","May Allah condemn and damn the people who killed you."],["وَلَعَنَ اللهُ الْمُمَهِّدِينَ لَهُمْ بِالتَّمْكِينِ مِنْ قِتالِكُمْ ،","May Allah condemn and damn the abettors who instigated and had a part in your murder."],["بَرِئْتُ إلى اللهِ وَإلَيْكُمْ مِنْهُمْ","I turn to you and Allah, away from them,"],["وَمِنْ أشْياعِهِمْ وَأتْباعِهِمْ وَأوْلِيائِهِمْ.","their henchmen, their followers and their friends,"],["يَا أبَا عَبْدِ اللهِ ،","O Abu Abdullah,"],["إنِّي سِلْمٌ لِمَنْ سالَمَكُمْ ،","I make peace with those who make their peace with you,"],["وَحَرْبٌ لِمَنْ حارَبَكُمْ","I make war on those who go to war against you,"],["وَوليٌ لِمَنْ والاكُم","I am his friend who is a friend of yours,"],["وعدوٌّ لِمَنْ عَاداكُمْ إلى يَوْمِ القِيامَةِ ،","And Iam his enemy who shows enemity towards you, till the Day of Judgement."],["وَلَعَنَ اللهُ آل زِيَاد وَآلَ مَرْوانَ ،","May Allah condemn and damn the family of Ziyaad and the family of Marwaan;"],["وَلَعَنَ اللهُ بَنِي اُمَيَّةَ قاطِبَةً ،","may Allah condemn and damn the group and the tribe of Umayyah, one and all, altogether;"],["وَلَعَنَ اللهُ ابْنَ مَرْجانَةَ ،","may Allah condemn and damn the son of Marjaanah;"],["وَلَعَنَ اللهُ عُمَرَ بْنَ سَعْد ،","may Allah condemn and damn Umar son of Saad;"],["وَلَعَنَ اللهُ شِمْراً ،","may Allah condemn and damn Shimr;"],["وَلَعَنَ اللهُ اُمَّةً أسْرَجَتْ وَألْجَمَتْ وَتَهيّأتْ وَتَنَقَّبَتْ لِقِتالِكَ ،","may Allah condemn and damn the people who bridled the horses and errected the saddles for your martyrdom."],["بِأبِي أنْتَ وَاُمِّي لَقَدْ عَظُمَ مُصابِي بِكَ ،","I, my father and mother are at your disposal. Profound is my sorrow for you."],["فَأسْالُ اللهَ الّذِي أكْرَمَ مَقامَكَ ، وَأكْرَمَنِي بِكَ ،","I beg Allah, who honoured you above others, to be generous towards me on account of you,"],["أنْ يَرْزُقَني طَلَبَ ثارِكَ مَعَ إمام مَنْصُور","and give me the opportunity to be with the victorious Imam, at the time of the final and decisive war against Allah's enemies."],["مِنْ أهْلِ بَيْتِ مُحَمَّد صَلّى الله عَلَيْهِ وَآلِهِ.","the descendent of Mohammad (blessings and peace be on him and on his children from Allah)"],["اللهمّ اجْعَلْني عِنْدَكَ وَجِيهاً بِالحُسَيْنِ عَلَيهِ السَّلام","O my Allah make me attend to Your cause, sincerely, in every respect following in Husayn's footsteps,"],["الدُّنْيا وَالآخِرَةِ مِنَ المقَرّبينْ .","in this world and the hereafter."],["يَا أبَا عَبْدِ اللهِ ،","O Abu Abdullah,"],["إنِّي أتَقَرَّبُ إلى اللهِ تعالى ، وَإلَى رَسُولِهِ ،","I pray and invoke Allah to send blessings on you. I come nearer and seek greater intimacy with Allah, with His Apostle,"],["وَإلى أمِيرِ المُؤْمِنينَ ، وَإلَى فاطِمَةَ ،","with Ameerul Moomineen, with Fatimah,"],["وإلى الحَسَنِ وَإلَيْكَ بِمُوالاتِكَ ،","with Hasan and with you, with the help of your love and patronage,"],["ومُوالاةِ أَوليائِك وَبِالْبَرَاءَةِ مِمَّنْ قَاتَلَكَ وَنَصبَ لَكَ الحَربَ ،","cutting off every connection with those who took up arms against you and killed you."],["وبالْبَرَاءةِ مِمَّنْ أسَّسَ أساسَ الظُّلْمِ وَالجَوْرِ عَلَيْكُمْ ،","I disconnect all links with those who, in the beginning, took the first steps to take liberties with and bear hard upon you,"],["وَعلى أشياعِكُم وَأبْرَأُ إلى اللهِ وَإلى رَسُولِهِ","I take refuge with Allah and His Apostle (blessings of Allah be on him and on his children),"],["وَبِالبراءِةِ مِمَّنْ أسَّسَ أساسَ ذلِكَ ،","free from the guilt of associating with those who laid the foundation for (your suffering),"],["وَبَنى عَلَيْهِ بُنْيانَهُ ،","devised and carried out their corrupt plan of action,"],["وَجَرَى في ظُلْمِهِ وَجَوْرِهِ عَلَيْكُمْ وَعَلَى أشْياعِكُمْ ،","boldly gave currency to reign of terror and cruelty to oppress you and your friends and followers;"],["بَرِئْتُ إلى اللهِ وَإلَيْكُمْ مِنْهُمْ ،","I detach myself from them and present myself to Allah and to you,"],["وَأتَقَرَّبُّ إلى اللهِ وَإلى رَسولِهِ","I (first) seek greater intimacy with Allah and then with you to win your love and patronage,"],["ثُمَّ إلَيْكُمْ بِمُوالاتِكُم وَمُوالاةِ وَلِيِّكُمْ ،","and to make friends with your friends,"],["وَبِالْبَرَاءَةِ مِنْ أعْدائِكُمْ ،وَالنَّاصِبِينَ لَكُم الحَرْبَ ،","cut off all links with your enemies, and with those who planted the seeds of hostility against you,"],["وَبِالبَرَاءَةِ مِنْ أشْياعِهِمْ وَأتْباعِهِمْ ،","and reject and discard their associates, their followers and their friends."],["يا أبا عَبدِ الله","O Abu Abdillah."],["إنِّي سِلْمٌ لِمَنْ سالَمَكُمْ ،","I make peace with those who made their peace with you,"],["وَحَرْبٌ لِمَنْ حارَبَكُمْ ،","I search out and confront those who waged war against you,"],["وَوَلِيٌّ لِمَنْ والاكُمْ ،","I make friends with those who stood by you,"],["وَعَدُوٌّ لِمَنْ عاداكُمْ ،","I strive against those who came in conflict with you, therefore,"],["فَأسْألُ اللهَ الّذِي أكْرَمَني بِمَعْرِفَتِكُمْ ، وَمَعْرِفَةِ أوْلِيائِكُمْ ،","I make a request to Allah to acquaint (me) with the awareness that perceives you and your friends,"],["وَرَزَقَني البَراءَةَ مِنْ أعْدائِكُمْ ،","to set me free from the corrupting influence of your enemies,"],["أنْ يَجْعَلَني مَعَكُمْ في الدُّنْيا وَالآخِرَةِ ،","to make me keep company with you in this would and in the Hereafter,"],["وَأنْ يُثَبِّتَ لي عِنْدَكُمْ قَدَمَ صِدْق في الدُّنْيا وَالآخِرَةِ ،","stand firm beside you and follow your footsteps closely in this world and in the next world."],["وَأسْألُهُ أنْ يُبَلِّغَنِي الْمقامَ الْمَحْمُودَ لَكُمْ عِنْدَ اللهِ ،","I beseech Him that he helps me to reach your highly praised station, given to you by Allah, (to meet you),"],["وَأنْ يَرْزُقَنِي طَلَبَ ثَارِي مَعَ إمَام مَهْدِيٍّ ظَاهِر نَاطِق بالحقِّ مِنْكُمْ ،","He provides me the opportunity to fight for justice and fairplay alongwith and under the leadership of the rightly guided guide (in your progeny) who surely will come and speak the truth."],["وَأسْألُ اللهَ بِحَقِّكُمْ وَبِالشَّأنِ الَّذِي لَكُمْ عِنْدَهُ","I beseech Allah in the name of your right and the purpose He assigned to you,"],["أنْ يُعْطِيَنِي بِمُصابِي بِكُمْ أفْضَلَ ما يُعْطِي مصاباً بِمُصِيبَتِهِ ،","that He overwhelms me with grief in memory of your sorrows, more than the personal grief that torments any one who is in great agony,"],["يا لَها منْ مُصِيبَة مَا أعْظَمَها وَأعْظَمَ رَزِيّتهَا فِي الإسلام","sorrows which have no parallel and overshadow all calamities that took place in the history of Islam,"],["وَفِي جَمِيعِ أهلِ السَّموَاتِ وَالارْضِ .","for that matter, through out the whole universe."],["اللهُمَّ اجْعَلْني في مَقامِي هذا مِمَّن تَنالُهُ مِنْكَ","O my Allah, in my on the spot situation, treat me like him (or her) who obtains from You"],["صَلَواتٌ وَرَحْمَةٌ وَمَغْفِرَةٌ .","(Your) blessings, mercy and forgiveness."],["اللهُمَّ اجْعَلْ مَحْيايَ مَحْيا مُحَمَّد وَآلِ مُحَمَّد ،","O my Allah, bring me to life again, after death, in the place Mohammad and his \"Aal\" (children) are dwelling,"],["وَمَماتي مَماتَ مُحَمَّد وَآل مُحَمَّد .","make me depart from this world like Mohammad and his \"Aal\" (children) had left,"],["اللهُمَّ إنَّ هَذا يَوْمٌ تَبَرَّكَتْ بِهِ بَنُو اُمَيَّةَ وَابْنُ آكِلَةِ الاكْبادِ ،","O my Allah this day is a day of rejoicing for the \"Bani Umayyah\", the herd of hardened criminals,"],["اللعِينُ بْنُ اللعِينِ عَلَى لِسانِكَ وَلِسانِ نَبِيِّكَ صَلّى الله عَلَيْهِ وَآلِهِ","the eternally damned and accursed group, a fact that had been made public by You and by Your Prophet (blessings of Allah be on him and on his children),"],["في كُلِّ مَوْطِن وَمَوْقِف وَقَفَ فِيهِ نَبيُّكَ - صَلّى الله عَلَيْهِ وَآلِهِ - .","who, in every place and at all occasions, drew attention of people to this truism."],["اللهُمَّ الْعَنْ أبَا سُفْيانَ وَمُعَاوِيَةَ","O my Allah condemn and damn Abu Sufyaan, and Muawa'awiyah,"],["وَيَزيدَ بْنَ مُعَاوِيَةَ","son of Muwa'awiyah"],["وآلَ مَرْوَانَ عَلَيْهِمْ مِنْكَ اللعْنَةُ أبَدَ الآبِدِينَ ،","and let it be an everlasting curse upon tem from You."],["وَهذا يَوْمٌ فَرِحَتْ بِهِ آلُ زِيَاد وَآلُ مَرْوانَ","Today the descendants of Ziyaad and Marwan make merry,"],["عَليهِمُ اللَّعْنةُ بِقَتْلِهِمُ الحُسَيْنَ عَلَيْهِ السَّلام ،","laugh and dance because on this day they killed Husayn (blessings of Allah be on him)."],["اللهُمَّ فَضاعِفْ عَلَيْهِمُ اللعْنَ وَالعَذابَ الأليم .","O my Allah, therefore, double up the curse You brings upon them and also the punishment You decrees for them."],["اللهُمَّ إنِّي أتَقَرَّبُّ إلَيْكَ في هذَا اليَوْمِ ،","O my Allah, I seek nearness to You today in this frame of mind,"],["وَفِي مَوْقِفِي هَذا ، وَأيَّامِ حَيَاتِي بِالبَرَاءَةِ مِنْهُمْ، وَاللعْنَةِ عَلَيْهِمْ ،","cutting off all links with them for the rest of my life, denouncing them"],["وَبِالْمُوالاةِ لِنَبِيِّكَ وَآلِ نَبِيِّكَ عَلَيِه وعَلَيْهِمُ السَّلام.","because of my love for Your Prophet and his children, peace be on him and them."],["اللهُمَّ الْعَنْ أوّلَ ظالِم ظَلَمَ حَقَّ مُحَمَّد وَآلِ مُحَمَّد ،","O my Allah condemn and damn the first tyrant who unjustly and wrongfully usurped that which rightly belonged to Mohammad and the children of Mohammad,"],["وَآخِرَ تَابِع لَهُ عَلَى ذلِكَ ،","and bring curse upon those who, after him, followed in his footsteps."],["اللهُمَّ الْعَنِ العِصابَةَ الَّتِي جاهَدَتِ الْحُسَيْنَ عَلَيْهِ السَّلام","O my Allah condemn and damn those conspirators who vexed and harassed Husayn,"],["وَشايَعَتْ وَبايَعَتْ وَتابَعَتْ عَلَى قَتْلِهِ.","eagerness, agreed mutually, and joined hands to kill him."],["اللهُمَّ الْعَنْهم جَميعاً","O my Allah bring curse upon all of them."],["السَّلام عَلَيْكَ يَا أبا عَبْدِ اللهِ","Peace be on you, O Abu Abdullah,"],["وَعلَى الأرواحِ الّتي حَلّتْ بِفِنائِكَ ،","and on those souls who came to your camp to put themselves at your disposal."],["وَأنَاخَت برَحْلِك عَلَيْكَ مِنِّي سَلامُ اللهِ","So far I am alive and the days and nights follow each other I invoke Allah to send blessings"],["أبَداً مَا بَقِيتُ وَبَقِيَ الليْلُ وَالنَّهارُ ،","on you for ever and ever. May Allah not make my this pledge of close association,"],["وَلا جَعَلَهُ اللهُ آخِرَ العَهْدِ مِنِّي لِزِيَارَتِكُمْ ،","physical as well as spiritual, with you the last fulfillment."],["السَّلام عَلَى الحُسَيْن ،","Peace be on Husayn,"],["وَعَلَى عَليِّ بْنِ الحُسَيْنِ ، وَعَلَى أوْلادِ الحُسَيْنِ ،","and on Ali son of Husayn, and on the children of Husayn,"],["وَعَلَى أصْحابِ الحُسَينِ الذينَ بَذَلُوا مُهَجَهُم دُونَ الحُسين","and on the friends of Husayn."],["اللهمَّ خُصَّ أنْتَ أوّلَ ظالم بِاللّعْنِ مِنِّي ،","O my Allah, let the curse I call down on the head of the first tyrant stick like a leech;"],["وَابْدَأْ بِهِ أوّلاً ، ثُمَّ الثَّانِي ،","and stay put for ever on the first, then the second,"],["وَالثَّالِثَ وَالرَّابِع ، اللهُمَّ الْعَنْ يزِيَدَ خامِساً ،","the third and the fourth. O my Allah damn and call down evil on the fifth, Yazid son of Mua'awyah,"],["وَالْعَنْ عُبَيْدَ اللهِ بْنَ زِيَاد وَابْنَ مَرْجانَةَ","and bring a curse upon Ubaydullah son of Ziyaad, ibna Marjanah,"],["وَعُمَرَ بْنَ سَعْد وَشِمْراً","Umar son of Saad, and Shimr,"],["وَآلَ أبي سُفْيانَ وَآلَ زِيَاد وآلَ مَرْوانَ إلَى يَوْمِ القِيامَةِ.","on the descendants of Abu Sufyaan, on the descendants of Ziyaad, on the descendants of Marwaan, till the Day of judgement."],["اللهمَّ لَكَ الحَمْدُ حَمْدَ الشَّاكِرينَ لَكَ عَلَى مُصابِهِمْ ،","O my Allah! (All) praise is for You (alone); praise of the \"Ever-thankful to You\", who glorify You whatever come to pass."],["الحَمْدُ للهِ عَلَى عَظِيمِ رَزِيّتي.","(All) praise is for Allah for my deep-felt intense grief."],["اللهُمَّ ارْزُقْني شَفاعَةَ الحُسَيْن عَلَيهِ السَّلام يَوْمَ الوُرُودِ ،","O my Allah make available for me the recommendations of Husayn on the day I present myself before You,"],["وَثَبِّتْ لي قَدَمَ صِدْق عِنْدَكَ مَعَ الحُسَيْنِ","let me stand firm in safety before You on account of my sincere attachment with Husayn,"],["وَأصْحابِ الحُسَيْن الّذِينَ بَذَلُوا مُهَجَهُمْ","alongwith him and his comrades, who sacrificed everything they had (heart, mind, soul and life)"],["دُونَ الْحُسَيْن عَلَيْهِ السَّلام.","for Husayn, peace be on him."]]},{"id":"ziarat-warith","cat":"Ziyārah","t":{"en":"Ziyārat al-Wārith","ar":"زيارة الوارث"},"lines":[["السَّلامُ عـَلَيـْكَ يا وارِثَ آدَمَ صـَفـُوةِ اللهِ","Peace be upon you, O inheritor of Adam, the chosen one of Allah"],["السَّلامُ عـَلَيْكَ يا وارِثَ نـوُحٍ نَبــِيِ اللهِ","Peace be upon you, O inheritor of Nuh, the Prophet of Allah"],["السَّلامُ عـَلَيـْكَ يـا وارِثَ إبـراهيـمَ خـَليـلِ اللهِ","Peace be upon you, O inheritor of Ibrahim, the friend of Allah"],["السَّلامُ عـَلَيـْكَ يا وارِثَ موســى كـَليِم اللهِ","Peace be upon you. O inheritor of Musa, the one who talked to Allah"],["السَّلامُ عـَلَيـْكَ يـا وارِثَ عـيـسى روُحِ الله","Peace be upon you, O inheritor of 'Isa, the spirit of Allah"],["السَّلامُ عـَلَيْكَ يا وارِثَ مـُحـَمـّدٍ حـَبـيبِ اللهِ","Peace be upon you, O inheritor of Muhammad, the beloved friend of Allah"],["السَّلامُ عـَلَيـْكَ يـا وارِثَ اَميرِ المُؤمِنينَ وَلَيِ اللهِ","Peace be upon you, O inheritor of Ali, the commander of the faithful and the friend of Allah"],["السَّلامُ عـَلَيـْكَ يَابـنَ مـُحـَمـّدٍ المـُصـطـَفـى","Peace be upon you, O son of the Muhammad mustafaa"],["السَّلامُ عـَلَيْكَ يَابـن عـلي المرتـضـى","Peace be upon you, O son of Ali Murtazaa"],["السَّلامُ عَلَيْكَ يَابـن فاطـمة الزهراء","Peace be upon you, O son of Fatema,"],["السَّلامُ عَلَيْكَ يَابـنَ خَديجَةَ الكُبـرى","Peace be upon you, O son of Khadijatul- kubra"],["السَّلام عَلَيْكَ يا ثارَ اللهِ وابـنَ ثارِِهِ والوِتـرَ المَوتـوُرَ","Peace be upon you, O he who fought in the way of Allah and the son of one who fought in the way of Allah"],["اَشـهَدُ اَنَّكَ قَد اَقَمتَ الصَّلاةَ وَآتَيتَ الزَّكاة","I bear witness that verily you established the prayers And gave the zakat (prescribed share) to the needy"],["وَاَمَرتَ بـاُلمِعروف ِوَنَهَيتَ عـَنِ المُنكرِ","And commanded to do what is right and lawful And not to do that which is wrong and unlawful"],["وَاَطـَعـتَ اللهَ وَرَسـولَهُ حـَتّى اَتيكَ اليَقـينُ","And obeyed Allah and His Messenger until the inevitable came unto you"],["فـَلَعـَنَ اللهُ اُمَةً قَتـَلَتـكَ وَلَعَنَ اللهُ اُمَةً ظَلَمَتكَ","So, Allah curse those who killed you And Allah curse those who wronged you"],["وَلَعَنَ اللهُ اُمَةً سَمِعت بـِذلك فَرَضِيَت بـه","And Allah curse those who heard the event and rested satisfied"],["يا مَولاي يا ابا عَبدِ اللهِ","O My Master, O Aboo ′Abdullah!"],["اَشهَدُ اَنّك كُنتَ نوُرا في الأصلابِ الشّامِخَةِ وَالأرحـامِ المُطَهَرَةِ","I bear witness that verily you were a light in the sublime loins and purified wombs"],["لم تـُنَجـِسـكَ الجـاهِليَّةُ بـاَنِجـاسـِها","The impurities of ignorance did not even tough you"],["وَلَم تـُلبـِسكَ مِن مُدلَهِمّاتِ ثـِيابـِها","Nor could its soiled and dirty bearing ever smear you"],["وَاَشـهَدُ أنَكَ مِن دَعائِم الدّين وَاَركانِ المُؤمِنينَ","I bear witness that, verily, you are the mainstay of the religion, and the supporter of the faithful ones"],["وَاَشهَدُ اَنّكَ الإمـام البَّرُ التَّقـيُ الرَّضـيُ الزَّكيّ الهادِي المَهدِيُ","I bear witness that, verily, you are a pious, God-fearing, favorite, wise And rightly guided (Imam)"],["وَاَشـهَدُ اَنَّ الأَئمّة مِن وُلْدِكَ كَلِمةُ التَّقـوى","I bear witness that the Imams, in your progeny, are the words of piety"],["وَاَعـلامُ الهُدى وَالعـُروةُ الوُثـقى وَالحـُجَّةُ عـَلى اَهل الدُنيـا","And the signs of guidance And the safe handle of Islam, And the decisive argument for the humankind."],["وَاُشـهِدُ اللهَ وَمـلائكـَتـَهُ وَاَنبـِيائَهُ وَرُسـُلَهُ","I call Allah to give witness, and also His Angels And His Prophets and His Messenger"],["اَنّي بـِكـمُ مُؤمِنٌ وَبـِايِابـِكم مُوقنٌ بـَشَرائِع ديني وخواتيِم عَمَلي","That, verily, I believe in (all of) you And that I am sure of your Return Joined to the divine laws of my belief and my accomplishments"],["وقَلبي لقَلبِكم سِلمٌ وَاَمري لِامْرِكـمُ مُتَّبـع","And my heart is resigned to yours And my conduct is following the example of yours"],["صـَلَوات الله عَلَيكم وَعَلى اَرواحـِكم وَعَلى اَجـسـادِكُم","Blessings of Allah be on (all of) you and on your souls And on your bodies"],["وعـَلَى اَجـسـامِكُم وَعـَلى شـاهِدِكم","and on your forms and (when) you are in view"],["وَعـَلَى غـائِبـِكم وَعـَلَى ظـاهركم وعـلى بــاطـِنـِكـم","and (when) you are out of sight and on your style and on your substance."],["بـاَبـي أَنـت وَ اُمي يَا بْن رَسـُولِ اللهِ يا ابـا عـَبـدِ اللهِ","My father and mother be sacrificed for you, O son of the Messenger of Allah! My father and mother be sacrificed for you, O Aboo Abdullah!"],["لَقَد عَظـُمتِ الرَّزيَّةُ و جـَلَتِ المُصـيبـَةُ بـِكَ عَلَينا","Verily terrible was the calamity and your suffering casts gloom upon us"],["وَعَلى جــَمــيعِ اَهل السَّمــواتِ والأرض","And upon all the people of the heavens and the earth."],["فــَلَعَنَ اللهُ اُمـةً أَسرجَت و َاَلجمـَتْ وَتـَهَيَأت و تنـقـبـت لِقـِتالِك","Therefore, curse of Allah be on the people who saddled up and gave rein to their horses and prepared to kill you."],["يا مَوْلاي ياابـا عـَبـدِ اللهِ","O my Master, O Aba ′Abdullah!"],["قَصَدْتُ حَرَمَك وَاَتَيْت اِلى مَشْهَدِك","I moved towards your sacred shrine and came to visit you"],["اَسـئَلُ اللهَ بـالِشـأن الذَي لَكَ عِندَهُ","I beseech Allah by the status that you enjoy with Him"],["وَ بـِالمَحَل الَّذي لَكَ لَدَيهِ","And in the position that you enjoy with Him"],["اَن يُصـَليَعَلَى مُحـَمّدٍ وَآلِ مُحـَمّدٍ","To send blessings on Muhammad and on the children of Muhammad"],["وَاَن يَجعَلَني مَعَكم في الدُنيا وَالآخـِرة","And keep me with you in this world and in the Hereafter"],["السّلامُ عـَلَيكَ يابــنَ رَسـوُلِ اللهِ","Peace be upon you, O son of the Messenger of Allah."],["السـّلامُ عـَلَيكَ يابـنَ نَبـِيِ اللهِ","Peace be upon you, O son of the Prophet of Allah."],["السـّلامُ عـَلَيـكَ يابـنَ اَمير المُؤمِنينَ","Peace be upon you, O son of Ameer al-Mu’mineen (the commander of the believers)."],["السـّلامُ عَلَيكَ يابـنَ الحـُسـينِ الشـهيدِ","Peace be upon you, O son of al-Husayn the shaheed (martyr)."],["السـّلامُ عَلَيكَ ايُّها الشـَهيدُ وابـن الشـهيد","Peace be upon you, O shaheed."],["السـّلامُ عـَلَيكَ ايُّها المـَظـلومُ وَابـنُ المَظـلوُمِ","Peace be upon you, O the wronged one and son of the wronged one."],["لَعَنَ اللهُ اُمةً قَتـَلَتـك وَلَعَنَ الله اُمةً ظَلَمَتـكَ","Curse of Allah be on those who killed you. Curse of Allah be on those who persecuted you."],["وَلَعَن اللهُ اُمةً سـَمِعت بـِذلِك فَرَضِيت بـِهِ","Curse of Allah be on those who heard this even but rested satisfied."],["السـّلامُ عَلَيكَ يا ياوَليَّ اللهِ وَابـنَ وَلِيهِ","Peace be upon you, O the saint of Allah and son of the saint of Allah."],["لَقَد عَظُمتِ المُصـيبـَةُ","Verily terrible was the calamity"],["وَجـَلّتِ الرَزِيةُ بـِكَ عـَلينا وَعـَلَى جـَميعِ المُسـلِمينَ","And your suffering casts gloom upon us And upon all of Muslims"],["فَلَعَنَ اللهُ اُمةً قَتَلَتك وَاَبـرءُ اِلى اللهِ وَاِليكَ مـِنهم","So, curse of Allah be on those who killed you And I disconnect all links with them and turn to Allah and you."],["السَّلامُ عـَلَيكُم يااَولياءَ اللهِ وَاَحـِبـائَهُ","Peace be upon all of you, O the saints and dears of Allah"],["السَّلام ُعـَلَيكُم يا اصـفـِياءَ اللهِ وَاوِدّائَهُ","Peace be upon all of you, O the adorers of Allah and the sincerely attached to Him"],["السَّلامُ عـَلَيكُم يا اَنصـارَ دينِ اللهِ","Peace be upon all of you, O the helpers of Allah’s religion"],["السَّلامُ عـَلَيكُم يا اَنـصـارَ رَسـُولِ اللهِ","Peace be upon all of you, O the helpers of the Messenger of Allah"],["السَّلامُ عـَلَيـكُم يـا اَنـصـارَ اَميرِ المُؤمِنـين","Peace be upon all of you, O the helpers of Ameer al-Mu’mineen"],["السَّلامُ عـَلَيكُم يا اَنـصـارَ فـاطـِمةَ الزهراء سَيدةِ نِساءِ العـالَمينَ","Peace be upon all of you, O the helpers of Fatimah the chiefess of the women of this world"],["السَّلامُ عـَلَيكُم يا اَنـصـارَ اَبـي مُحـَمَّدٍ الحـَسـَنِ بـن عـليٍّ الوَلي الناصِح","Peace be upon all of you, O the helpers of Aboo Muhammad al-Hasan ibn Ali The sincere, pure and faithful saint"],["السَّلامُ عَلَيكُم يا اَنصارَ اَبـي عَبـدِ اللهِ","Peace be upon all of you, O the helpers of Aboo Abdullah"],["بـاَبـي اَنتُم وَاُمي طِبـتُم وطابـَتِ الأرضُ الّتـي فـيها دُفـِنـتُم","My father and mother be sacrificed for you Verily, you were pure; therefore, the land wherein you are buried has been purified"],["وَفـُزتُم فـَوزاً عـَظـيماً","You also attained your end and won great fortune"],["فَيا لَيْتَني كُنْت مَعَكُم","Would that we were with you"],["فَاَفُوزَ مَعَكُمْ","So that we could also share the accomplishment with you."],["فَيالَيْتَني كُنْت مَعَكُم","Would that we were with you"],["فَاَفُوز مَعَكُمْ","So that we could also share the accomplishment with you."]]},{"id":"ziarat-ale-yaseen","cat":"Ziyārah","t":{"en":"Ziyārat Āl Yāsīn","ar":"زيارة آل يس"},"lines":[["سلام على آل يس","Peace be upon (the) progeny of Yaseen."],["السلام عليك يا داعي الله و رباني آياته","Peace be upon you, O the caller of Allah and place of manifestation of His signs."],["السلام عليك يا باب الله و ديان دينه","Peace be upon you, O the door of Allah and the devout one of His religion."],["السلام عليك يا خليفة الله و ناصر حقه","Peace be upon you, O the vicegerent of Allah and the helper of His truth."],["السلام عليك يا حجة الله و دليل إرادته","Peace be upon you, O the proof of Allah and the Guide of His intention."],["السلام عليك يا تالي كتاب الله و ترجمانه","Peace be upon you, O the reciter of Allah's book and its interpreter."],["السلام عليك في آناء ليلك و أطراف نهارك","Peace be upon you in your night and in your day."],["السلام عليك يا بقية الله في أرضه","Peace be upon you, O the remnant of Allah on His earth."],["السلام عليك يا ميثاق الله الذي أخذه و وكده","Peace be upon you, O the covenant of Allah, which He took it and He fastened it."],["السلام عليك يا وعد الله الذي ضمنه","Peace be upon you, O the promise of Allah which He guaranteed it."],["السلام عليك أيها العلم المنصوب","Peace by upon you, O the manifested flag"],["و العلم المصبوب و الغوث","and the one who is filled with knowledge and the help"],["و الرحمة الواسعة وَعْدٌ غَيْرُ مَكْذُوبٍ","and the far-reaching mercy a promise which is not a lie."],["السلام عليك حين تقوم","Peace be upon you while you are standing"],["السلام عليك حين تقعد","Peace be upon you while you are sitting."],["السلام عليك حين تقرأ و تبين","Peace be upon you when you are reading and explaining"],["السلام عليك حين تصلي و تقنت","Peace be upon you when you are praying and supplicating."],["السلام عليك حين تركع و تسجد","Peace be upon you when you are bowing and prostrating."],["السلام عليك حين تهلل و تكبر","Peace be upon you when you are saying \"There is no God except Allah' and (when) you are saying 'Allah is greater (than what He is described).'"],["السلام عليك حين تحمد و تستغفر","Peace be upon you when you are praising (Allah) and seeking forgiveness."],["السلام عليك حين تصبح و تمسي","Peace be upon you when you enter the morning and the evening."],["السلام عليك في اللَّيْلِ إِذا يَغْشى","Peace be upon you in the night when it envelops"],["وَ النَّهارِ إِذا تَجَلَّى","and the day when it becomes manifest."],["السلام عليك أيها الإمام المأمون","Peace be upon you, O the leader, the protected one."],["السلام عليك أيها المقدم المأمول","Peace be upon you, O the prior hoped one."],["السلام عليك بجوامع السلام","Peace be upon you by the collections of the salutations."],["أشهد موالي أني أشهدك يا مولاي أني","I call you as a witness, O my Master,"],["أشهد أن لا إله إلا الله وحده لا شريك له","I testify that there is no god except Allah, He is alone, there is no partner with Him."],["و أن محمدا عبده و رسوله","And indeed I testify that Mohammad is His servant and His Apostle;"],["لا حبيب إلا هو و أهله","There is no beloved except him and his progeny."],["و أشهدك أن أمير المؤمنين حجته","And I call you as a witness, O my Master certainly Ali, the commander of the believers, is His proof."],["و الحسن حجته و الحسين حجته","And Hasan is His proof. And Husayn is His proof."],["و علي بن الحسين حجته","And Ali, son of Husayn is His proof."],["و محمد بن علي حجته","And Muhammad, son of Ali is His proof."],["و جعفر بن محمد حجته","And Ja'far, son of Mohammad is His proof."],["و موسى بن جعفر حجته","And Moosa, son of Ja'far is His proof."],["و علي بن موسى حجته","And Ali, son of Moosa is His proof."],["و محمد بن علي حجته","And Muhammad, son of Ali is His proof."],["و علي بن محمد حجته","And Ali, son of Mohammad is His proof."],["و الحسن بن علي حجته","And Hasan, son of Ali is His proof."],["و أشهد أنك حجة الله","And I testify that indeed you are the proof of Allah."],["أنتم الأول و الآخر","All of you, the first and the last."],["و أن رجعتكم حق لا ريب","And surely your return is a truth, there is no doubt in it."],["فيها يوم لا يَنْفَعُ نَفْساً إِيمانُها لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ","The day when belief of none will benefit himself who previously"],["أَوْ كَسَبَتْ فِي إِيمانِها خَيْراً و أن الموت حق","did notbelieve or acquired a goodness through his belief. And indeed death is a truth."],["و أن ناكرا و نكيرا حق","And indeed Naakir and Nakeer is a truth."],["و أشهد أن النشر و البعث حق","And I testify that indeed the scattering (stage of Qiyamat) is a truth and the raising is a truth."],["و أن الصراط و المرصاد حق","And indeed the bridge (over hell) is a truth and the watching place is a truth."],["و الميزان و الحساب حق","And the balance is a truth and the gathering is a truth"],["و الحساب حق و الجنة حق","And the accounting (of deeds) is a truth and the Paradise"],["و النار حق و الوعد و الوعيد بهما حق","and the hell is a truth. And the promise (of reward) and the threat (of the punishment) in them is a truth."],["يا مولاي شقي من خالفكم و سعد من أطاعكم","O my Master, one who opposes you is unlucky. And one who obeys you is lucky."],["فاشهد على ما أشهدتك عليه","And I am a friend for you, acquitted from your enemy."],["و أنا ولي لك بري‏ء من عدوك","Then testify whatever I made you a witness upon it."],["فالحق ما رضيتموه و الباطل ما سخطتموه","So the truth is whatever you are satisfied with. And the untrue is whatever you are angry with."],["و المعروف ما أمرتم به و المنكر ما نهيتم عنه","And the goodness is whatever you ordered. And the evil is whatever you have prohibited from."],["فنفسي مؤمنة بالله وحده لا شريك له","So lam abeliever in Allah, He alone, there is no partner with Him."],["و برسوله و بأمير المؤمنين و بكم يا مولاي","And (I am a believer) in His Apostle and in the commander of the believers. And in you O my Master,"],["أولكم و آخركم و نصرتي معدة لكم","the first among you and the last among you. And my help is intended for you."],["و مودتي خالصة لكم آمين آمين .","And my love is purely for you. Amen! Amen ! (Accept! Accept!)"]]},{"id":"dua-kumayl","cat":"Duʿāʾ","t":{"en":"Duʿāʾ Kumayl","ar":"دعاء كميل"},"lines":[["بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ","In the Name of Allah, the All-merciful, the All-compassionate"],["اللَّهُمَّ إِنِّي أَسْألُكَ بِرَحْمَتِكَ الَّتِي وَسِعَتْ كُلَّ شَيٍْء","O Allah, I ask You by Your mercy, which “..embraces all things” (7:156),"],["وَبِقُوَّتِكَ الَّتِي قَهَرْتَ بِهَا كُلَّ شَيٍْء","And by Your strength, through which You dominate all things,"],["وَخَضَعَ لَهَا كُلُّ شَيٍْء","And toward which all things are humble"],["وَذَلَّ لَهَا كُلُّ شَيٍْء","And before which all things are lowly;"],["وَبِجَبرُوتِكَ الَّتِي غَلَبْتَ بِهَا كُلَّ شَيٍْء","And by Your invincibility through which You overwhelm all things,"],["وَبِعِزَّتِكَ الَّتِي لا يَقُومُ لَهَا شَيْءٌ","And by Your might, which nothing can resist;"],["وَبِعَظَمَتِكَ الَّتِي مَلَأَتْ كُلَّ شَيٍْء","And by Your tremendousness, which has filled all things;"],["وَبِسُلْطَانِكَ الَّذِي عَلاَ كُلَّ شَيٍْء","by Your force, which towers over all things;"],["وَبِوَجْهِكَ الْبَاقِي بَعْدَ فَنَاءِ كُلِّ شَيٍْء","And by Your face, which subsists after the annihilation of all things,"],["وَبِأَسْمَائِكَ الَّتِي مَلَأَتْ أَرْكَانَ كُلِّ شَيٍْء","And by Your Names, which have filled the foundations of all things;"],["وَبِعِلْمِكَ الَّذِي أَحَاطَ بِكُلِّ شَيٍْء","And by Your knowledge, which encompasses all things;"],["وَبِنُورِ وَجْهِكَ الَّذِي أَضَاءَ لَهُ كُلُّ شَيٍْء","And by the light of Your face, through which all things are illumined!"],["يَّا نُورُ يَا قُدُّوسُ","O Light! O All-holy!"],["يَا أَوَّلَ الأَوَّلِينَ","O First of those who are first"],["وَيَا آخِرَ الآخِرِينَ","And O Last of those who are last!"],["اَللَّهُمَ اغْفِرْ لِي الذُّنُوبَ الَّتِي تَهتِكُ الْعِصَمَ","O Allah, forgive me those sins which tear apart safeguards!"],["اَللَّهُمَ اغْفِرْ لِيَ الذُّنُوبَ الَّتِي تُنْزِلُ النِّقَمَ","O Allah, forgive me those sins which draw down adversities!"],["اَللَّهُمَ اغْفِرْ لِيَ الذُّنُوبَ الَّتِي تُغيِّرُ النِّعَمَ","O Allah, forgive me those sins which alter blessings!"],["اَللَّهُمَّ اغْفِرْ لِيَ الذُّنُوبَ الَّتِي تَحْبِسُ الدُّعَاءَ","O Allah forgive me those sins which hold back supplication!"],["اَللَّهُمَّ اغْفِرْ لِيَ الذُّنُوبَ الَّتِي تَقْطَعُ الرَّجَاءَ","O Allah forgive me those sins which cut down hopes!"],["اَللَّهُمَّ اغْفِرْ لِيَ الذُّنُوبَ الَّتِي تُنْزِلُ البَلآءَ","O Allah, forgive me those sins which draw down tribulation!"],["اَللَّهُمَّ اغْفِرْ لِيْ كُلَّ ذَنْبٍ أَذْنَبْتُهُ وَكُلَّ خَطِيئَةٍ أَخْطَأْتُهَا","O Allah, forgive me every sin I have committed and every mistake I have made!"],["اَللَّهُمَّ إِنِّي أَتَقَرَّبُ إِلَيْكَ بِذِكْرِكَ","O Allah, verily I seek nearness to You through remembrance of You,"],["وَأَسْتَشْفِعُ بِكَ إِلَى نَفْسِكَ","And I seek intercession from You with Yourself,"],["وَأَسْألُكَ بِجُودِكَ أَن تُدْنِيَنِي مِن قُرْبِكَ","And I ask You through Your munificence to bring me near to Your proximity,"],["وَأَن تُوزِعَنِي شُكْرَكَ","And to provide me with gratitude toward You"],["وَأَن تُلْهِمَنِي ذِكْرَكَ","And to inspire me with Your remembrance."],["اَللَّهُمَّ إِنِّي أَسْألُكَ سُؤَالَ خَاضِعٍ مُّتَذَلِّلٍ خَاشِعٍ أَن تُسَامِحَنِي وَتَرْحَمَنِي","O Allah, verily I ask You with the asking of a submissive, abased and lowly man to show me forbearance, to have mercy on me"],["وَتَجْعَلَنِي بِقَسَمِكَ رَاضِيًا قَانِعًا، وَفِي جَمِيعِ الأَحْوَاِل مُتَوَاضِعًا","And to make me satisfied and content with Your apportionment and humble in every state."],["اَللَّهُمَّ وَأَسْألُكَ سُؤَالَ مَنِ اشْتَدَّتْ فَاقَتُهُ","O Allah, I ask You with the asking of one whose indigence is extreme,"],["وَأَنْزَلَ بِكَ عِنْدَ الشَّدَائِدِ حَاجَتَهُ","And who has stated to You in difficulties his need"],["وَعَظُمَ فِيمَا عِنْدَكَ رَغْبَتُهُ","And whose desire for what is with You has become great."],["اَللَّهُمَّ عَظُمَ سُلْطَانُكَ وَعَلاَ مَكَانُكَ","O Allah, Your force is tremendous, Your place is lofty,"],["وَخَفِيَ مَكْرُكَ وَظَهَرَ أَمْرُكَ","And Your deception is hidden, Your command is manifest,"],["وَغَلَبَ قَهْرُكَ وَجَرَتْ قُدْرَتُكَ","And Your domination is overwhelming, Your power is unhindered"],["وَلا يُمْكِنُ الْفِرَارُ مِنْ حُكُومَتِكَ","And escape from Your governance is impossible."],["اَللَّهُمَّ لا أَجِدُ لِذُنُوبِي غَافِرًا","O Allah, I find no forgiver of my sins,"],["وَلا لِقَبَائِحِي سَاتِرًا","No concealer of my ugly acts,"],["وَلا لِشَيٍْء مِّنْ عَمَلِيَ الْقَبِيحِ بِالْحَسَنِ مُبَدِّلاً غَيْرَكَ","And no transformer of any of my ugly acts into good acts but You"],["لا إِلَهَ إِلا أَنْتَ","There is no god but You!"],["سُبْحَانَكَ وَبِحَمْدِكَ","Glory be to You, and Yours is the praise!"],["ظَلَمْتُ نَفْسِي","I have wronged myself,"],["وَتَجَرَّأْتُ بِجَهْلِي","And I have been audacious in my ignorance"],["وَسَكَنْتُ إِلَى قَدِيمِ ذِكْرِكَ لِي وَمَنِّكَ عَلَيَّ","And I have depended upon Your ancient remembrance of me and Your favour toward me."],["اللَّهُمَّ مَوْلايَ","O Allah! O my Protector!"],["كَمْ مِّنْ قَبِيحٍ سَتَرْتَهُ","How many ugly things You have concealed!"],["وَكَمْ مِّن فَاِدحٍ مِّنَ البَلاءِ أَقَلْتَهُ","How many burdensome tribulations You have abolished!"],["وَكَمْ مِّنْ عِثَارٍ وَّقَيْتَهُ","And how many stumbles You have prevented!"],["وَكَمْ مِّن مَّكْرُوهٍ دَفَعْتَهُ","And how many ordeals You have repelled!"],["وَكَمْ مِّنْ ثَنَاءٍ جَمِيلٍ لَّسْتُ أَهْلاً لَّهُ نَشَرْتَهُ","And how much beautiful praise, for which I was unworthy, You have spread abroad!"],["اَللَّهُمَّ عَظُمَ بَلائِي","O Allah, my tribulation is tremendous,"],["وَأَفْرَطَ بِي سُوءُ حَاِلي","And my bad state is excessive,"],["وَقَصُرَتْ بِي أَعْمَاِلي","And my acts are inadequate,"],["وَقَعَدَتْ بِي أَغْلاَلِي","And my fetters have tied me down,"],["وَحَبَسَنِي عَن نَّفْعِي بُعْدُ آمَاِلي","And my far-fetched hopes have held me back from my gain"],["وَخَدَعَتْنِي الدُّنْيَا بِغُرُورِهَا وَنَفْسِي بِجِنَايَتِهَا (بِخِيَانَتِهَا) وَمِطَاِلي","And this world with its delusions, my own soul with its offences and my delay have deceived me."],["يَا سَيِّدِي فَأَسْأَلُكَ بِعِزَّتِكَ أَن لا يَحْجُبَ عَنْكَ دُعَآئِي سُوءُ عَمَلِي وَفِعَاِلي","O my Master! So I ask You by Your might not to let my evil works and acts veil my supplication from You,"],["وَلا تَفْضَحْنِي بِخَفِيِّ مَا اطَّلَعْتَ عَلَيْهِ مِنْ سِرِّي","And not to disgrace me through the hidden things You know of my secrets"],["وَلا تُعَاجِلْنِي بِالْعُقُوبَةِ عَلَى مَا عَمِلْتُهُ فِي خَلَوَاتِي","And not to hasten me to punishment for what I have done in private:"],["مِنْ سُوءِ فِعْلِي وَإِسَاءَتِي،","My evil acts in secrecy and my misdeeds"],["وَدَوَامِ تَفْرِيطِي وَجَهَالَتِي","And my continuous negligence and my ignorance"],["وَكَثْرَةِ شَهَوَاتِي وَغَفْلَتِي","And my manifold passions and my forgetfulness."],["وَكُنِ اللَّهُمَّ بِعِزَّتِكَ لِي فِي كُلِّ الأَحْوَاِل رَؤُوفًا","And by Your might, O Allah, be kind to me in all states"],["وَّعَلَيَّ فِي جَمِيعِ الأُمُورِ عَطُوفًا","And be gracious to me in all affairs!"],["إِلَهِي وَرَبِّي مَن لِّي غَيْرُكَ أَسْأَلُهُ كَشْفَ ضُرِّي وَالْنَّظَرَ فِي أَمْرِي!","My God and my Lord! Have I any but You from whom to ask removal of my affliction and regard for my affairs!"],["إِلَهِي وَمَوْلايَ أَجْرَيْتَ عَلَيَّ حُكْمًا اتَّبَعْتُ فِيهِ هَوَى نَفْسِي،","My God and my Protector! You put into effect through me a decree in which I followed the caprice of my own soul"],["وَلَمْ أَحْتَرِسْ فِيهِ مِن تَزْيِيْنِ عَدُوِّي،","And did not remain wary of adorning my enemy."],["فَغَرَّنِي بِمَا أَهْوَى وَأَسْعَدَهُ عَلَى ذَلِكَ القَضَاءُ","So he deluded me through my soul's caprice and therein destiny favoured him"],["فَتَجَاوَزْتُ بِمَا جَرَى عَلَيَّ مِنْ ذَلِكَ بَعْضَ حُدُودِكَ","So, in what was put into effect through me in that situation, I transgressed some of Your statutes"],["وَخَالَفْتُ بَعْضَ أَوَامِرِكَ","And disobeyed some of Your commands."],["فَلَكَ الْحُجَّةُ عَلَيَّ فِي جَمِيعِ ذَلِكَ","So Yours is the argument against me in all of that"],["وَلا حُجَّةَ لِي فِيمَا جَرَى عَلَيَّ فِيهِ قَضَاؤُكَ،","I have no argument in what Your destiny put into effect through me therein"],["وَأَلْزَمَنِي حُكْمُكَ وَبَلاؤُكَ","nor in what Your decree and Your tribulation imposed upon me."],["وَقَدْ أَتَيْتُكَ يَا إِلَهِي بَعْدَ تَقْصِيرِي وَإِسْرَافِي عَلَى نَفْسِي","Now I have come to You, My God, after my shortcoming and my immoderation toward myself,"],["مُعْتَذِرًا نَّادِمًا،","Proffering my excuse, regretful,"],["مُّنْكَسِرًا مُّسْتَقِيلاً","Broken, apologizing,"],["مُّسْتَغْفِرًا مُّنِيبًا،","Asking forgiveness, repenting,"],["مُّقِرًّا مُّذْعِنًا مُّعْتَرِفًا","Acknowledging, submissive, confessing."],["لا أَجِدُ مَفَرًّا مِّمَّا كَانَ مِنِّي","I find no place to flee from what occurred through me,"],["وَلا مَفْزَعًا أَتَوَجَّهُ إِلَيْهِ في أَمْرِي","Nor any place of escape to which I may turn in my affairs,"],["غَيْرَ قَبُولِكَ عُذْرِي، وَإِدخَاِلكَ إِيَّايَ فِي سَعَةٍ مِّن رَّحْمَتِكَ","Other than Your acceptance of my excuse and Your entering me into the compass of Your mercy."],["اَللَّهُمَّ فَاقْبَل عُذْرِي","O Allah, so accept my excuse,"],["وَارْحَمْ شِدَّةَ ضُرِّي","Have mercy upon the severity of my affliction"],["وَفُكَّنِي مِنْ شَدِّ وَثَاقِي","And release me from the tightness of my fetters,"],["يَا رَبِّ ارْحَمْ ضَعْفَ بَدَنِي وَرِقَّةَ جِلْدِي وَدِقَّةَ عَظْمِي","My Lord, have mercy upon the weakness of my body, the thinness of my skin and the frailty of my bones."],["يَا مَنْ بَدَأَ خَلْقِي وَذِكْرِي وَتَرْبِيَتِي وَبِرِّي وَتَغْذِيَتِي","O Thou who gave rise to my creation, to the remembrance of me, to the nurture of me, to goodness toward me and to nourishment on me,"],["هَبْنِي لابْتِدَآءِ كَرَمِكَ وَسَاِلفِ بِرِّكَ بِي","Bestow upon me for the sake of Your having given rise [to me] with generosity and Your previous goodness to me!"],["يَا إِلَهِي وَسَيِّدِي وَرَبِّي","O Allah, my Master and my Lord!"],["أَتُرَاكَ مُعَذِّبِي بِنَارِكَ بَعْدَ تَوْحِيدِكَ","Can You see Yourself tormenting me with Your fire after I have professed Your Unity"],["وَبَعْدَ مَا انْطَوَى عَلَيْهِ قَلْبِي مِن مَّعْرِفَتِكَ","And after the knowledge of You my heart has embraced,"],["وَلَهِجَ بِهِ لِسَانِي مِنْ ذِكْرِكَ","And the remembrance of You my tongue has constantly mentioned"],["وَاعْتَقَدَهُ ضَمِيرِي مِنْ حُبِّكَ","And the love of You to which my mind has clung,"],["وَبَعْدَ صِدْقِ اعْتِرَافِي وَدُعَائِي خَاضِعًا لِّرُبُوبِيَّتِكَ","And after the sincerity of my confession and my supplication, humble before Your lordship?"],["هَيْهَاتَ أَنْتَ أَكْرَمُ مِنْ أَنْ تُضَيِّعَ مَن رَّبَّيْتَهُ","Far be it from You! You are more generous than that You should squander him whom You have nurtured,"],["أَوْ تُبْعِدَ مَنْ أَدْنَيْتَهُ","Or banish him whom You have brought nigh,"],["أَوْ تُشَرِّدَ مَنْ آوَيْتَهُ","Or drive away him whom You have given an abode"],["أَوْ تُسْلِمَ إِلىَ الْبلآءِ مَن كَفَيْتَهُ وَرَحِمْتَهُ","Or submit to tribulation him whom You have spared and shown mercy."],["وَلَيْتَ شِعْرِي يَا سَيِّدِي وَإِلَهِي وَمَوْلايَ","Would that I knew, my Master, My God and my Protector,"],["أَتُسَلِّطُ النَّارَ عَلَى وُجُوهٍ خَرَّتْ لِعَظَمَتِكَ سَاجِدَةً","Whether You will give the Fire dominion over faces fallen down prostrate before Your Tremendousness,"],["وَعَلَى أَلْسُنٍ نَّطَقَتْ بِتَوْحِيدِكَ صَادِقَةً وَّبِشُكْرِكَ مَادِحَةً","And over tongues voicing sincerely the profession of Your Unity and giving thanks to You in praise,"],["وَعَلَى قُلُوبٍ اعْتَرَفَتْ بِإِلَهِيَّتِكَ مُحَقِّقَةً","And over hearts acknowledging Your Divinity through verification,"],["وَعَلَى ضَمَائِرَ حَوَتْ مِنَ الْعِلْمِ بِكَ حَتَّى صَارَتْ خَاشِعَةً","And over minds encompassing knowledge of You until they have become humble"],["وَعَلَى جَواِرحَ سَعَتْ إِلَى أَوْطَانِ تَعَبُّدِكَ طَائِعَةً وَّأَشَارَتْ بِاسْتِغْفَارِكَ مُذْعِنَةً","And over bodily members speeding to the places of Your worship in obedience and beckoning for Your forgiveness in submission."],["مَّا هَكَذَا الظَّنُّ بِكَ وَلا أُخْبِرْنَا بِفَضْلِكَ عَنْكَ","No such opinion is held of You! Nor has such been reported - thanks to Your bounty — concerning You,"],["يَا كَرِيمُ، يَا رَبِّ","O All-generous! My Lord,"],["وَأَنْتَ تَعْلَمُ ضَعْفِي عَنْ قَلِيلٍ مِّن بَلآءِ الدُّنْيَا وَعُقُوبَاتِهَا،","And You know my weakness before a little of this world's tribulations and punishments,"],["وَمَا يَجْرِي فِيهَا مِنَ الْمَكَارِهِ عَلَى أَهْلِهَا","And before those ordeals which befall its inhabitants,"],["عَلَى أَنَّ ذَلِكَ بَلآءٌ وَّمَكْرُوهٌ قَلِيلٌ مَّكْثُهُ، يَسِيرٌ بَقَآؤُهُ، قَصِيرٌ مُّدَّتُهُ","Even though it is a tribulation and ordeal whose stay is short, whose subsistence is but little and, whose period is but fleeting."],["فَكَيْفَ احْتِمَاِلي لِبَلآءِ الآخِرَةِ وَجَلِيلِ وُقُوعِ الْمَكَارِهِ فِيهَا!","So how can I endure the tribulations of the next world and the great ordeals that occur within it?"],["وَهُوَ بَلآءٌ تَطُولُ مُدَّتُهُ، وَيَدُومُ مَقَامُهُ، وَلا يُخَفَّفُ عَنْ أَهْلِهِ","For it is a tribulation whose period is long, whose station endures and whose sufferers are given no respite,"],["لِأَنَّهُ لا يَكُونُ إِلا عَنْ غَضَبِكَ وَانْتِقَامِكَ وَسَخَطِكَ","Since it only occurs as a result of Your wrath, Your vengeance and Your anger,"],["وَهَذَا مَا لا تَقُومُ لَهُ السَّمَاوَاتُ وَالأَرْضُ","And these cannot be withstood by the heavens and the earth."],["يَا سَيِّدِي فَكَيْفَ بِي","O Master, so what about me?!"],["وَأَنَا عَبْدُكَ الضَّعِيفُ الذَّلِيلُ الْحَقِيرُ الْمِسْكِينُ الْمُسْتَكِينُ","For I am Your weak, lowly, base, wretched and miserable slave."],["يَا إِلَهِي وَرَبِّي وَسَيِّدِي وَمَوْلايَ","My God! My Lord! My Master! My Protector!"],["لِأَيِّ الأُمُورِ إِلَيْكَ أَشْكُو","For which things would I complain to You?"],["وَلِمَا مِنْهَا أَضِجُّ وَأَبْكِي","And for which of them would I lament and weep?"],["لِأَلِيمِ الْعَذَابِ وَشِدَّتِهِ!","For the pain and severity of chastisement?"],["أَمْ لِطُولِ الْبَلآءِ وَمُدَّتِهِ!","Or for the length and period of tribulation?"],["فَلَئِن صَيَّرْتَنِي لِلْعُقُوبَاتِ مَعَ أَعْدَآئِكَ","So if You take me to the punishments with Your enemies,"],["وَجَمَعْتَ بَيْنِي وَبَيْنَ أَهْلِ بَلآئِكَ","And gather me with the people of Your tribulation"],["وَفَرَّقْتَ بَيْنِي وَبَيْنَ أَحِبَّائِكَ وَأَوْلِيَائِكَ","And separate me from Your friends and saints,"],["فَهَبْنِي يَا إِلَهِي وَسَيِّدِي وَمَوْلايَ وَرَبِّي صَبَرْتُ عَلَى عَذَابِكَ،","Then suppose, My God, my Master, my Protector and my Lord that I am able to endure Your chastisement,"],["فَكَيْفَ أَصْبِرُ عَلَى فِرَاقِكَ","How can I endure separation from You?"],["وَهَبْنِي صَبَرْتُ عَلَى حَرِّ نَارِكَ،","And suppose that I am able to endure the heat of Your fire,"],["فَكَيْفَ أَصْبِرُ عَنِ النَّظَرِ إِلَى كَرَامَتِكَ","How can I endure not gazing upon Your generosity?"],["أَمْ كَيْفَ أَسْكُنُ فِي النَّارِ وَرَجَائِي عَفْوُكَ","Or how can I dwell in the Fire while my hope is Your pardon?"],["فَبِعِزَّتِكَ يَا سَيِّدِي وَمَوْلايَ أُقْسِمُ صَادِقًا، لَئِنْ تَرَكْتَنِي نَاطِقًا","So by Your might, my Master and my protector, I swear sincerely, if You leave me with speech,"],["لَأَضِجَّنَّ إِلَيْكَ بَيْنَ أَهْلِهَا ضَجِيجَ الآمِلِينَ","I will lament to You from the midst of the Fire's inhabitants with lamentation of the hopeful;"],["وَلأَصْرُخَنَّ إِلَيكَ صُرَاخَ المُسْتَصْرِخِينَ","I will cry to You with the cry of those crying for help;"],["وَلَأَبْكِيَنَّ عَلَيْكَ بُكَاءَ الفَاقِدِينَ","I will weep to You with the weeping of the bereft;"],["وَلَأُنَادِيَنَّكَ أَيْنَ كُنْتَ يَا وَلِيَّ الْمُؤْمِنِينَ","And I will call to You, Where art Thou, O Sponsor of the believers,"],["يَا غَايَةَ آمَاِل العَارِفِينَ","O Goal of the hopes of Your knowers,"],["يَا غِيَاثَ المُسْتَغِيْثِينَ","O Aid of those who seek assistance,"],["يَا حَبِيبَ قُلُوبِ الصَّادِقِينَ","O Friend of the hearts of the sincere"],["وَيَا إِلَهَ العَالَمِينَ","And O God of all the world's inhabitants!"],["أَفَتُرَاكَ، سُبْحَانَكَ يَا إِلَهِي وَبِحَمْدِكَ، تَسْمَعُ فِيهَا صَوْتَ عَبْدٍ مُّسْلِمٍ","Can You see Yourself — Glory be to You My God, and Yours is the praise — hearing within the Fire the voice of a slave surrendered to"],["سُجِنَ فِيهَا بِمُخَالَفَتِهِ","Imprisoned there because of his violations,"],["وَذَاقَ طَعْمَ عَذَابِهَا بِمَعْصِيَتِهِ","Tasting the flavour of its torment because of his disobedience,"],["وَحُبِسَ بَيْنَ أَطْبَاقِهَا بِجُرْمِهِ وَجَرِيرَتِهِ","And confined within its levels because of his sin and crime,"],["وَهُوَ يَضِجُّ إلَيْكَ ضَجِيجَ مُؤَمِّلٍ لِّرَحْمَتِكَ","While he laments to You with the lament of one hopeful for Your mercy,"],["وَيُنَادِيكَ بِلِسَانِ أَهْلِ تَوْحِيدِكَ","And calls to You with the tongue of those who profess Your Unity"],["وَيَتَوَسَّلُ إلَيْكَ بِرُبُوبِيَّتِكَ","And entreats You by Your lordship!"],["يَا مَوْلايَ فَكَيْفَ يَبْقَى فِي الْعَذَابِ وَهُوَ يَرْجُو مَا سَلَفَ مِنْ حِلْمِكَ","My Protector, so how should he remain in the chastisement, while he has hope for Your previous clemency?"],["أَمْ كَيْفَ تُؤْلِمُهُ النَّارُ وَهُوَ يَأْمَلُ فَضْلَكَ وَرَحْمَتَكَ","Or how should the Fire cause him pain while he expects Your bounty and mercy?"],["أَمْ كَيْفَ يُحْرِقُهُ لَهِيبُهَا وَأَنتَ تَسْمَعُ صَوْتَهُ وَتَرَى مَكَانَهُ","Or how should its flames burn him, while You hear his voice and see his place?"],["أَمْ كَيْفَ يَشْتَمِلُ عَلَيْهِ زَفِيرُهَا وَأَنْتَ تَعْلَمُ ضَعْفَهُ","Or how should its groaning encompass him, while You know his weakness?"],["أَمْ كَيْفَ يَتَقَلْقَلُ بَيْنَ أَطْبَاقِهَا وَأَنْتَ تَعْلَمُ صِدْقَهُ","Or how should he be convulsed among its levels, while You know his sincerity?"],["أَمْ كَيْفَ تَزْجُرُهُ زَبَانِيَتُهَا وَهُوَ يُنَادِيكَ يَا رَبَّهُ","Or how should its keepers torture him while he calls out to You, “O Lord”?"],["أَمْ كَيْفَ يَرْجُو فَضْلَكَ فِي عِتْقِهِ مِنْهَا فَتَتْرُكُهُ فِيهَا","Or how should he have hope of Your bounty in freeing him from it, while You abandon him within it?"],["هَيهَاتَ مَا ذَلِكَ الظَّنُّ بِكَ","Far be it from You! That is not what is expected of You,"],["وَلا الْمَعْرُوفُ مِنْ فَضْلِكَ","Nor what is well-known of Your bounty,"],["وَلا مُشْبِهٌ لِمَا عَامَلْتَ بِهِ الْمُوَحِّدِينَ مِنْ بِرِّكَ وَإِحْسَانِكَ","Nor it is similar to the goodness and kindness Thou hast shown to those who profess Your Unity."],["فَبِالْيَقِينِ أَقْطَعُ لَوْلا مَا حَكَمْتَ بِهِ مِن تَعْذِيبِ جَاحِدِيكَ","So I declare with certainty that were it not for what You have decreed concerning the chastisement of Your deniers"],["وَقَضَيْتَ بِهِ مِنْ إِخْلاَدِ مُعَانِدِيكَ","And what You have foreordained concerning the everlasting home of those who stubbornly resist,"],["لَجَعَلْتَ النَّارَ كُلَّهَا بَرْدًا وَّسَلاَمًا،","You would make the Fire, all of it, coolness and safety,"],["وَمَا كَانَ لأَحَدٍ فِيهَا مَقَرًّا وَّلا مُقَامًا","And no one would have a place of rest or abode within it."],["لَّكِنَّكَ تَقَدَّسَتْ أَسْمَاؤُكَ أَقْسَمْتَ أَنْ تَمْلَأَهَا مِنَ الْكَافِرِينَ،","But You —holy are Your Names—hast sworn that You will fill it with the unbelievers,"],["مِنَ الْجِنَّةِ وَالنَّاسِ أَجْمَعِينَ","Both Jinn and men together,"],["وَأَنْ تُخَلِّدَ فِيهَا الْمُعَانِدِينَ","And that You will place those who stubbornly resist therein forever."],["وَأَنْتَ جَلَّ ثَنَاؤُكَ قُلْتَ مُبْتَدِئًا، وَّتَطَوَّلْتَ بِالإِنْعَامِ مُتَكَرِّمًا:","And You — majestic is Your eulogy— said at the beginning and were gracious through kindness as a favour,"],["أَفَمَنْ كَانَ مُؤْمِنًا كَمَنْ كَانَ فَاسِقًا لَّا يَسْتَوُونَ","“What? Is he who has been believer like unto him who has been ungodly? They are not equal” (32:18)"],["إِلَهِي وَسَيِّدِي فَأَسْألُكَ بِالْقُدْرَةِ الَّتِي قَدَّرْتَهَا","My God and my Master! So I ask You by the power You have apportioned"],["وَبِالْقَضِيَّةِ الَّتِي حَتَمْتَهَا وَحَكَمْتَهَا وَغَلَبْتَ مَنْ عَلَيْهِ أَجْرَيْتَهَا","And by the decision which You have determined and imposed and through which You have overcome him toward whom it has been put into"],["أَن تَهَبَ لِي، فِي هذِهِ اللَّيْلَةِ، وَفِي هَذِهِ السَّاعَةِ","That You forgive me in this night and at this hour"],["كُلَّ جُرْمٍ أَجْرَمْتُهُ","Every offence I have committed,"],["وَكُلَّ ذَنْبٍ أَذْنَبْتُهُ","And every sin I have performed,"],["وَكُلَّ قَبِيحٍ أَسْرَرْتُهُ","And every ugly thing I have concealed"],["وَكُلَّ جَهْلٍ عَمِلْتُهُ،","And every folly I have enacted"],["كَتَمْتُهُ أَوْ أَعْلَنتُهُ،","Whether I have hidden or announced it,"],["أَخفَيْتُهُ أَوْ أَظْهَرْتُهُ","Or I have concealed it or manifested it"],["وَكُلَّ سَيِّئَةٍ أَمَرْتَ بِإِثْبَاتِهَا الْكِرَامَ الكَاتِبِينَ","And every evil act which You have commanded the Noble Writers to record,"],["الَّذِينَ وَكَّلْتَهُم بِحِفْظِ مَا يَكُونُ مِنِّي،","Those whom You have appointed to watch over what appears from me"],["وَجَعَلْتَهُمْ شُهُودًا عَلَيَّ مَعَ جَوَارِحِي،","And whom You have made, along with my bodily members, witness against me."],["وَكُنتَ أَنْتَ الرَّقِيبَ عَلَيَّ مِن وَّرَائِهِمْ،","And “You were Yourself the Watcher” (5:117) over me from behind them,"],["وَالشَّاهِدَ لِمَا خَفِيَ عَنْهُمْ،","And the Witness of what is hidden from them"],["وَبِرَحْمَتِكَ أَخْفَيْتَهُ،","But through Your mercy You concealed it"],["وَبِفَضْلِكَ سَتَرْتَهُ","And through Your bounty You veiled it."],["وَأَنْ تُوَفِّرَ حَظِّي مِن كُلِّ خَيْرٍ تُنْزِلُهُ،","[And I ask You] that You bestow upon me an abundant share of every good You send down,"],["أَوْ إِحْسَانٍ تُفْضِلُهُ","Or kindness You confer,"],["أَوْ بِرٍّ تَنْشُرُهُ،","Or goodness You unfold,"],["أَوْ رِزْقٍ تَبْسُطُهُ","Or provision You spread out,"],["أَوْ ذَنْبٍ تَغْفِرُهُ","Or sin You forgive,"],["أَوْ خَطَأٍ تَسْتُرُهُ","Or error You cover."],["يَا رَبِّ يَا رَبِّ يَا رَبِّ","My Lord! My Lord! My Lord!"],["يَا إِلَهِي وَسَيِّدِي وَمَوْلايَ وَمَاِلكَ رِقِّي","My God! My Master! My Protector! Owner of my bondage!"],["يَا مَنْ بِيَدِهِ نَاصِيَتِي","O He in whose hand is my forelock!"],["يَا عَلِيمًا بِضُرِّي وَمَسْكَنَتِي","O He who knows my affliction and my misery!"],["يَا خَبِيرًا بِفَقْرِي وَفَاقَتِي","O He who is aware of my poverty and indigence!"],["يَا رَبِّ يَا رَبِّ يَا رَبِّ","My Lord! My Lord! My Lord!"],["أَسْأَلُكَ بِحَقِّكَ وَقُدْسِكَ","I ask You by Your Truth and Your Holiness"],["وَأَعْظَمِ صِفَاتِكَ وَأَسْمَائِكَ","And the greatest of Your Attributes and Names,"],["أنْ تَجْعَلَ أَوْقَاتِي فِى اللَّيلِ وَالنَّهَارِ بِذِكْرِكَ مَعْمُورَةً،","That You make my times in the night and the day inhabited by Your remembrance,"],["وَبِخِدْمَتِكَ مَوْصُولَةً،","And joined to Your service"],["وَّأَعْمَاِلي عِنْدَكَ مَقْبُولَةً،","And my works acceptable to You,"],["حَتَّى تَكُونَ أَعْمَاِلي وَأَوْرَادِي كُلُّهَا وِرْدًا وَّاحِدًا،","So that my works and my litanies may all be a single litany"],["وَّحَاِلي فِي خِدْمَتِكَ سَرْمَدًا","And my occupation with Your service everlasting."],["يَا سَيِّدِي، يَا مَنْ عَلَيْهِ مُعَوَّلِي","My Master! O He upon whom I depend!"],["يَا مَنْ إلَيْهِ شَكَوْتُ أَحْوَاِلي","O He to whom I complain about my states!"],["يَا رَبِّ يَا رَبِّ يَا رَبِّ","My Lord! My Lord! My Lord!"],["قَوِّ عَلَى خِدْمَتِكَ جَوَارِحِي","Strengthen my bodily members in Your service,"],["وَاشْدُدْ عَلىَ الْعَزِيمَةِ جَوَانِحِي","And fortify my ribs in determination"],["وَهَبْ لِيَ الْجِدَّ فِي خَشْيَتِكَ","And bestow upon me earnestness in my fear of You"],["وَالدَّوَامَ فِي الإِتِّصَاِل بِخِدْمَتِكَ","And continuity in my being joined to Your service"],["حَتَّى أَسْرَحَ إِلَيكَ فِي مَيَادِينِ السَّابِقِينَ","So that I may move easily toward You in the battlefields of the foremost"],["وَأُسْرِعَ إلَيْكَ فِي الْمبُادِرِينَ","And hurry to You among the prominent"],["وَأَشْتَاقَ إلىَ قُرْبِكَ فِي الْمُشْتَاقِينَ","And desire fervently Your proximity among the fervently desirous"],["وَأَدْنُوَ مِنْكَ دُنُوَّ الْمُخْلِصِينَ","And move nearer to You with the nearness of the sincere"],["وَأَخَافَكَ مَخَافَةَ الْمُوقِنِينَ","And fear You with the fear of those who have certitude"],["وَأَجْتَمِعَ فِي جِوَارِكَ مَعَ الْمُؤْمنِينَ","And gather with the believers in Your vicinity."],["اَللَّهُمَّ وَمَنْ أَرَادَنِي بِسُوٍء فَأَرِدْهُ","O Allah, whoever desires evil for me, desire [it] for him!"],["وَمَنْ كَادَنِي فَكِدْهُ","whoever deceives me-deceive him!"],["وَاجْعَلْنِي مِنْ أَحْسَنِ عَبِيدِكَ نَصِيبًا عِنْدَكَ","And make me one of the most excellent of Your slaves in Portion from You,"],["وَأَقْرَبِهِم مَّنْزِلَةً مِّنْكَ","And the nearest of them in station to You"],["وَأَخَصِّهِمْ زُلْفَةً لَّدَيْكَ","And the most elect of them in proximity to You."],["فَإِنَّهُ لا يُنَالُ ذَلِكَ إِلاّ بِفَضْلِكَ","For that cannot be attained except by Your bounty."],["وَجُدْ لِي بِجُودِكَ","And grant generously to me through Your munificence,"],["وَاعْطِفْ عَلَيَّ بِمَجْدِكَ","And incline toward me with Your splendour"],["وَاحْفَظْنِي بِرَحْمَتِكَ","And protect me with Your mercy!"],["وَاجْعَل لِّسَانِي بِذِكْرِكَ لَهِجًا","And make my tongue remember You without ceasing"],["وَقَلْبِي بِحُبِّكَ مُتَيَّمًا","And my heart enthralled by Your love!"],["وَّمُنَّ عَلَيَّ بِحُسْنِ إِجَابَتِكَ","And be gracious to me by answering me favourably,"],["وَأَقِلْنِي عَثْرَتِي","And nullify my slips"],["وَاغْفِرْ زَلَّتِي","And forgive my lapses!"],["فَإِنَّكَ قَضَيْتَ عَلَى عِبَادِكَ بِعِبَادَتِكَ","For Thou hast decreed Your worship for Your servants"],["وَأَمَرْتَهُم بِدُعَائِكَ","And commanded them to supplicate You"],["وَضَمِنْتَ لَهُمُ الإِجَابَةَ","And assured them that they would be answered."],["فَإِلَيْكَ يَا رَبِّ نَصَبْتُ وَجْهِي","So toward You, my Lord, I have turned my face"],["وَإلَيْكَ يَا رَبِّ مَدَدْتُ يَدِي","And toward You, my Lord, I have extended my hand."],["فَبِعِزَّتِكَ اسْتَجِبْ لِي دُعَائِي","So by Your might, comply with my supplication"],["وَبَلِّغْنِي مُنَايَ","And make me attain my desires!"],["وَلا تَقْطَعْ مِن فَضْلِكَ رَجَائِي","Do not severe my hopes of Your favours"],["وَاكْفِنِي شَرَّ الْجِنِّ وَالإِنْسِ مِنْ أَعْدَائِي","And spare me the evil of my enemies from among the jinn and men!"],["يَا سَرِيعَ الرِّضَا","O He, whose pleasure is quickly achieved!"],["اِغْفِرْ لِمَن لا يَمْلِكُ إِلا الدُّعَاءَ","Forgive him who owns nothing but supplication"],["فَإِنَّكَ فَعَّالٌ لِّمَا تَشَاءُ","For You do what You will."],["يَا مَنْ اسْمُهُ دَوَاءٌ","O He whose Name is a remedy,"],["وَذِكْرُهُ شِفَاءٌ","And whose remembrance is a cure,"],["وَطَاعَتُهُ غِنًى","And whose obedience is wealth!"],["ارْحَم مَّن رَّأْسُ مَاِلهِ الرَّجَاءُ","Have mercy upon him whose capital is hope"],["وَسِلاَحُهُ الْبُكَاءُ","And whose weapon is tears!"],["يَا سَاِبغَ النِّعَمِ","O Ample in blessings!"],["يَا دَافِعَ النِّقَمِ","O Repeller of adversities!"],["يَا نُورَ الْمُسْتَوْحِشِينَ فِي الظُّلَمِ","O Light of those who are lonely in the darkness!"],["يَا عَالِمًا لا يُعَلَّمُ","O Knower who was never taught!"],["صَلِّ عَلَى مُحَمَّدٍ وَّآلِ مُحَمَّدٍ","Bless Muhammad and Muhammad's household!"],["وافْعَلْ بِي مَا أَنتَ أَهْلُهُ","And do with me what is worthy of You!"],["وَصَلَّى اللَّهُ عَلَى رَسُولِهِ وَالأَئِمَّةِ الْمَيَامِينَ مِنْ آلِهِ","And Allah bless His messenger and the holy Imams of his household"],["وَسَلَّمَ تَسْلِيمًا كَثِيرًا","And give them abundant peace!"]]},{"id":"dua-mashlool","cat":"Duʿāʾ","t":{"en":"Duʿāʾ al-Mashlūl","ar":"الدعاء المشلول"},"lines":[["اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ","O Allah, I beseech Thee with Thy Name;"],["بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ","the Name of Allah, the Most Merciful, the Benign."],["يا ذَا الْجَلالِ وَالاِْكرامِ يا حَىُّ يا قَيّوُمُ يا حَىُّ","O Lord of Majesty and Generosity; O Living; O Self-Subsisting, O Ever-living,"],["لا اِلـهَ اِلاّ اَنْتَ، يا هُوَ يا مَنْ لا يَعْلَمُ ما هُوَ","there is no God but Thou. O Thou that art \"He\" of whom no one knoweth what \"He\" is,"],["وَلا كَيْفَ هُوَ وَلا حَيْثُ هُوَ اِلاّ هُوَ","nor how \"He\" is, nor where \"He\" is, except \"He.\""],["يا ذَا المُلْكِ وَالْمَلَكوُتِ يا ذَا الْعِزَّةِ وَالْجَبَروُتِ","O Lord of the Great Kingdom and Supremacy. O Lord of Honour and Omnipotence:"],["يا مَلِكُ يا قُدُّوسُ، يا سَلامُ يا مُؤْمِنُ","O Sovereign Lord, O Holy One! O Peace; O Keeper of Faith;"],["يا مُهَيْمِنُ يا عَزيزُ يا جَبّارُ يا مُتَكَبِّرُ","O Guardian O Revered One; O Compeller; O Superb."],["يا خالِقُ يا بارِئُ يا مصوّر يا مُفيدُ","O Creator O Maker of all things from nothing; O Artist; O Beneficent;"],["يا مُدَبِّرُ يا شَديدُ يا مُبْدِئُ يا مُعيدُ","O Administrator; O Severe (in wrath); O Inventor; O Restorer;"],["يا مُبيدُ يا وَدُودُ يا مَحْمُودُ يا مَعْبوُدُ","O Originator; O Most Loving: O Praised; O Adored."],["يا بَعيدُ يا قَريبُ يا مجيب يا رقيب","O Thou that art distant yet near; O Answerer of prayer; O Observer; O Reckoner."],["يا حَسيبُ يا بَديعُ يا رَفيعُ يا منيعٌ","O Innovator; O Exalted; O Unassailable; O Hearer."],["يا سَميعُ يا عَليمُ يا حَليمُ يا كَريمُ","O Knower; O Wise; O Bountiful;"],["يا حَكيمُ يا قَديمُ يا عَلِىُّ يا عَظيمُ","O Forbearing; O Eternal; O Lofty; O Great."],["يا حَنّانُ يا مَنّانُ يا دَيّانُ يا مُسْتَعانُ","O most Compassionate; O Giver of all good; O most perfect Requiter of good and evil;"],["يا جَليلُ يا جَميلُ يا وَكيلُ يا كفَيلُ","O Thou whose help is sought for. O Guide; O Magnanimous."],["يا مُقيلُ يا مُنيلُ يا نَبيلُ يا دَليلُ","O Commencer; O Giver of guidance;"],["يا هادى يا بادى يا اَوَّلُ يا اخِرُ","O Giver of guidance; O Commencer; O First; O Last;"],["يا ظاهِرُ يا باطِنُ يا قآئِمُ يا دآئِمُ","O Evident; O Hidden. O Established; O Everlasting;"],["يا عالِمُ يا حاكِمُ يا قاضى يا عادِلُ","O Knowing; O Ruler; O Dispenser of justice; O Equitable;"],["يا فاصِلُ يا واصِلُ يا طاهِرُ يا مُطَهِّرُ","O Thou that disjoineth and uniteth; O Pure; O Purifier;"],["يا قادِرُ يا مُقْتَدِرُ يا كَبيرُ يا مُتَكَبِّرُ","O Powerful; O Almighty; O Great; O Magnificent."],["يا واحِدُ يا اَحَدُ يا صَمَدُ","O One; O Matchless; O Eternal;"],["يا مَنْ لَمْ يَلِدْ وَلَمْ يوُلَدْ","O Absolute; O Thou that bareth none and is born of none;"],["وَلَمْ يَكُنْ لَهُ كُفُواً اَحَدٌ","nor is there equal to Thee anyone nor hath Thee any spouse;"],["وَلَمْ يَكُنْ لَهُ صاحِبَةٌ","nor any bearer of Thy burden;"],["وَلا كانَ مَعَهُ وَزيرٌ","nor any consultant to give Thee advice;"],["وَلاَ اتَّخَذَ مَعَهُ مُشيراً","not does Thou need any supporter;"],["وَلاَ احْتاجَ اِلى ظَهير","nor is there with Thou any other deity;"],["وَلا كانَ مَعَهُ مِنْ اِلـه غَيْرُهُ","There is no God but Thou,"],["لا اِلـهَ اِلاّ اَنْتَ","and Thou art far exalted with great excellence"],["فَتَعالَيْتَ عَمّا يَقُولُ الظّالِمُونَ عُلُوّاً كَبيراً","above all that which the unjust folk do say concerning Thee"],["يا عَلِىُّ يا شامِخُ يا باذِخُ يا فَتّاحُ","O High and Lofty; O most Glorious; O Opener;"],["يا نَفّاحُ يا مُرْتاحُ يا مُفَرِّجُ يا ناصِرُ","O Diffuser of fragrance; O Tolerant; O Helper;"],["يا مُنْتَصِرُ يا مُدْرِكُ يا مُهْلِكُ يا مُنْتَقِمُ","O Victorious; O Overtaker; O Destroyer; O Avenger;"],["يا باعِثُ يا وارِثُ يا طالِبُ يا غالِبُ","O Resurrector; O Inheritor; O Seeker; O Conquerer;"],["يا مَنْ لا يَفُوتُهُ هارِبٌ","O Thou from Whom no fugitive can escape."],["يا تَوّابُ يا اَوّابُ يا وَهّابُ يا مُسَبِّبَ الاَْسْبابِ","O Acceptor of repentance; O Ever-forgiving; O Great Bestower; O Causer of all causes;"],["يا مُفَتِّحَ الاَْبْوابِ يا مَنْ حَيْثُ ما دُعِىَ اَجابَ","O Opener of doors (of relief and salvation); O Thou that answerest howsoever Thou art invoked."],["يا طَهُورُ يا شَكُورُ يا عَفُوُّ يا غَفُورُ","O Purifier; O Giver of manifold rewards; O Excuser; O Pardoner;"],["يا نُورَ النُّورِ يا مُدَبِّرَ الاُْموُرِ","O Light of all lights; O Director of all affairs."],["يا لَطيفُ يا خَبيرُ يا مُجيرُ يا مُنيرُ","O Ever Blissful; O All-Aware; O Protector; O Luminous;"],["يا بَصيرُ يا كَبيرُ يا وِتْرُ يا فَرْدُ","O Seer; O Supporter; O Great. O Lone; O Unique;"],["يا اَبَدُ يا سَنَدُ يا صَمَدُ","O Everlasting; O Upholder; O Eternal and Absolute."],["يا كافى يا شافى يا وافى يا مُعافى","O Sufficer; O Healer; O Fulfiller of promises; O Deliver."],["يا مُحْسِنُ يا مُجْمِلُ يا مُنْعِمُ يا مُفْضِلُ","O Benefactor; O Beautifier; O Bestower of grace; O Grantor of favors;"],["يا مُتَكَرِّمُ يا مُتَفَرِّدُ، يا مَنْ عَلا فَقَهَرَ","O Gracious; O Peerless. O Thou that being Exalted overwhelmest;"],["يا مَنْ مَلَكَ فَقَدَرَ، يا مَنْ بَطَنَ فَخَبَرَ","O Thou that being Master of all hast absolute power; O Thou, who being hidden art well informed;"],["يا مَنْ عُبِدَ فَشَكَرَ، يا مَنْ عُصِىَ فَغَفَرَ","O Thou that being disobeyed forgiveth;"],["يا مَنْ لا يَحْويهِ الْفِكَرُ وَلا يُدْرِكُهُ بَصَرٌ","O Thou Whom no thought can fully comprehend;"],["وَلا يَخْفى عَلَيْهِ اَثَرٌ، يا رازِقَ الْبَشَرِ يا مُقَدِّرَ كُلِّ قَدَر","nor sight perceive nor from whom any impression is hidden, O Nourisher of Mankind; O Ordainer of every destiny."],["يا عالِىَ الْمَكانِ يا شَديدَ الاَْرْكانِ","O Thou of Exalted position; O Thou Formidable in Thy foundations;"],["يا مُبَدِّلَ الزَّمانِ يا قابِلَ الْقُرْبانِ","O Changer of times; O Acceptor of sacrifice;"],["يا ذَا الْمَنِّ وَالاِْحْسانِ يا ذَا الْعِزَّةِ وَالسُّلْطانِ","O Thou full of favors and benefactions; O Lord of Honor and Supremacy"],["يا رَحيمُ يا مَنْ هُوَ كُلِّ يَوُم فى شَاْن","O All Merciful; O most Compassionate; O Thou that has each day a distinctive Glory"],["يا مَنْ لا يَشْغَلُهُ شَاْنٌ عَنْ شَاْن","while no aspect of Thy Glory is erased by the prominence of another aspect."],["يا عَظيمَ الشَّأنِ يا مَنْ هُوَ بِكُلِّ مَكان","O Thou that art present in every place."],["يا سامِعَ الاَْصْواتِ يا مُجيبَ الدَّعَواتِ","O Hearer of all voices; O Answerer of prayers;"],["يا مُنْجِحَ الطَّلِباتِ يا قاضِىَ الْحاجاتِ","O Giver of success in all requirements; O Fulfiller of all needs;"],["يا مُنْزِلَ الْبَرَكاتِ يا راحِمَ الْعَبَراتِ","O Bestower of blessings; O Thou that taketh pity on our tears."],["يا مُقيلَ الْعَثَراتِ يا كاشِفَ الْكُرُباتِ","O Thou that raiseth from the pitfalls; O Thou that relieveth agonies;"],["يا وَلِىَّ الْحَسَناتِ يا رافِعَ الدَّرَجاتِ","O thou that art the Cherisher of good deeds. O Thou that raiseth men in rank and degree;"],["يا مُؤْتِىَ السُّؤْلاتِ يا مُحْيِىَ الاَْمْواتِ","O Thou that accedeth to requests; O Thou that bringeth the dead to life;"],["يا جامِعَ الشَّتاتِ يا مُطَّلِعاً عَلَى النِّيّاتِ","O Thou that gathereth together that which is scattered. O Thou that art informed of all intentions;"],["يا رادَّ ما قَدْ فاتَ يا مَنْ لا تَشْتَبِهُ عَلَيْهِ الاَْصْواتُ","that restoreth that which has been lost; O Thou that art not confused by a multiplicity of voices;"],["يا مَنْ لا تُضْجِرُهُ الْمَسْأَلاتُ وَلا تَغْشاهُ الظُّلُماتُ","O Thou that art not harassed by a multitude of petitions; and Whom no darkness can hide or cover;"],["يا نُورَ الاَْرْضِ والسِّماواتِ","O Light of heaven and earth."],["يا سابِغَ النِّعَمِ يا دافِعَ النِّقَمِ","O Perfector of blessings; O Averter of calamaties;"],["يا بارِئَ النَّسَمِ يا جامِعَ الاُْمَمِ","O Producer of zephyrs; O Gatherer of nations;"],["يا شافِىَ السَّقَمِ يا خالِقَ النُّورِ وَالظُّلَمِ","O Healer of disease; O Creator of light and darkness;"],["يا ذَا الْجُودِ وَالْكَرَمِ يا مَنْ لا يَطَأُ عَرْشَهٌ قَدَمٌ","O Lord of generosity and munificence; O Thou (on) whose throne no one can set foot!"],["يا اَجْوَدَ الاَْجْوَدينَ يا اَكْرَمَ الاَْكْرَمينَ","O Thou more generous than the most generous; O Thou more munificent than the most munificent;"],["يا اَسْمَعَ السّامِعينَ يا اَبْصَرَ النّاظِرينَ","O Thou most keen of hearing than the most keen of hearing; O Thou more keen of vision than the most perceiving;"],["يا جارَ الْمُسْتَجيرينَ يا اَمانَ الْخائِفينَ","O Protecting neighbor of those that seek Thy neighborhood."],["يا ظَهْرَ اللاّجينَ يا وَلِىَّ الْمُؤْمِنينَ","O Refuge of the fearful; O Patron of the faithful;"],["يا غِياثَ الْمُسْتَغيثينَ يا غايَةَ الطّالِبينَ","O Helper of those that seek Thy help; O ultimate Goal of those that aspire."],["يا صاحِبَ كُلِّ غَريب يا مُؤنِسَ كُلِ وَحيد","O Companion of all strangers; O Friend of all the lonely ones;"],["يا مَلْجَاَ كُلِّ طَريد يا مَاْوى كُلِّ شَريد","O Refuge of all outcasts; O Retreat of all persecuted ones;"],["يا حافِظَ كُلِّ ضآلَّة، يا راحِمَ الشَّيْخِ الْكَبيرِ","O Guardian of all those who stray. O Thou that takest pity on the aged and decrepit;"],["يا رازِقَ الّطِفْلِ الصَّغيرِ يا جابِرَ الْعَظْمِ الْكَسيرِ","O Thou that nourisheth the little baby; O Thou that joineth together broken ones;"],["يا فاكَّ كُلِّ اَسير، يا مُغْنِىَ الْبآئِسِ الْفَقيرِ","O Liberator of all prisoners; O Enricher of the miserable poor;"],["يا عِصْمَةَ الْخائِفِ الْمُسْتَجيرِ، يا مَنْ لَهُ التَّدْبيرُ وَالتَّقْديرُ","O Protector of the frightened refugees; O Thou for Whom alone are both destiny and disposal;"],["يا مِنَ الْعَسيرُ عَلَيْهِ سَهْلٌ يَسيرٌ، يا مَنْ لا يَحْتاجُ اِلى تَفْسير","O Thou for Whom all difficult things are simple and easy; O Thou that doth not need any explanation."],["يا مَنْ هُوَ عَلى كُلِّ شْيء قَديرُ","O Thou Mighty over all things;"],["يا مَنْ هُوَ بِكُلِّ شَْيء خَبيرٌ","O Thou Knower of all things."],["يا مَنْ هُوَ بِكُلِّ شَْيء بَصيرٌ","O Thou Seer of all things."],["يا مُرْسِلَ الرِّياحِ يا فالِقَ الاِْصْباحِ","O Thou that maketh breezes blow; O Thou that cleaveth the day-break;"],["يا باعِثَ الاَْرْواحِ يا ذَا الْجُودِ وَالسَّماحِ","O Reviver of the spirits; O Lord of Generosity and Clemency;"],["يا مَنْ بِيَدِهِ كُلُّ مِفْتاح","O Thou in Whose hands are all keys."],["يا سامِعَ كُلِّ صَوْت يا سابِقَ كُلِّ فَوْت","O Hearer of all voices; O Thou earlier in time than all that have passed away;"],["يا مُحْيِىَ كُلِّ نَفْس بَعْدَ المَوْتِ","O Giver of life to every soul after death."],["يا عُدَّتى فى شِدَّتى يا حافِظىِ فى غُرْبَتى","O my Means of defense in confronting hardships; O my Guardian in strange lands;"],["يا مُؤنِسى فى وَحْدَتى يا وَلِيّى فى نِعْمَتى","O my Friend in my loneliness; O my Master in my bliss;"],["يا كَهْفى حينَ تُعْيينِى الْمَذاهِبُ","O my Refuge at the time when the journey doth tire me out"],["وَتُسَلِّمُنىِ الاَْقارِبُ وَيَخْذُلُنى كُلُّ صاحِب","and my kinsfolk hand me over to my foes and all my comrades forsake me."],["يا عِمادَ مَنْ لا عِمادَ لَهُ، يا سَنَدَ مَنْ لا سَنَدَ لَهُ","O Supporter of those who have no support; O Guarantor of those who have no guarantee;"],["يا ذُخْرَ مَنْ لا ذُخْرَ لَهُ، يا حِرْزَ مَنْ لا حِرْزَ لَهُ","O Wealth of those who have no wealth; O Means of those who have no strength;"],["يا كَهْفَ مَنْ لا كَهْفَ لَهُ، يا كَنْزَ مَنْ لا كَنْزَ لَهُ","O Refuge of those who have no refuge; O Treasure of those who have no treasure;"],["يا رُكُنَ مَنْ لا رُكْنَ لَهُ، يا غِياثَ مَنْ لا غِياثَ لَهُ","O Helper of those who have no helper;"],["يا جارَ مَنْ لا جارَ لَهُ، يا جارِىَ اللَّصيقَ","O Neighbor of those who have no neighbor. O my Neighbor that art adjacent;"],["يا رُكْنِىَ الَْوثيقَ، يا اِلـهى بِالتَّحْقيقِ","O my Support that art firm; O my God that art worshipped by virtue of positive knowledge;"],["يا رَبَّ الْبَيْتِ الْعَتيقِ، يا شَفيقُ يا رَفيقُ","O lord of the Ancient House (the Ka'ba); O Thou full of loving and kindness; O nearest Friend."],["فُكَّنى مِنْ حَلَقِ الْمَضيقِ","Liberate me from the choking fetters,"],["وَاصْرِفْ عَنّى كُلَّ هَمٍّ وَغَمٍّ وَ ضيق","Remove from me all sorrow, suffering and grief,"],["وَاكْفِنى شَرَّ ما لا اُطيقُ","Protect me from the evil that I am unable to bear,"],["وَاَعِنّى عَلى ما اُطيقُ","and help me in that which I am unable to do."],["يا رآدَّ يُوسُفَ عَلى يَعْقُوبَ","O Thou that didst restore Yusuf unto Yaqub;"],["يا كاشِفَ ضُرِّ اَيُّوبَ، يا غافِرَ ذَنْبِ داوُدَ","O Thou that didst cure Ayyub of his malady; O Thou that didst forgive the fault of Dawood;"],["يا رافِعَ عيسَى بْنِ مَرْيَمَ وَ مُنْجِيَهُ مِنْ اَيْدِى الْيَهوُدِ","O Thou that didst lift up Isa and saved him from the clutches of the Jews;"],["يا مُجيبَ نِدآءِ يُونٌسَ فِى الظُّلُماتِ","O Thou that didst answer the prayer of Yunus from the darkness;"],["يا مُصْطَفِىَ مُوسى بِالْكَلِماتِ","O Thou that didst choose Musa by means of Thine inspired words;"],["يا مَنْ غَفَرَ لاِدَمَ خَطيـئَتَهُ وَرَفَعَ اِدْريسَ مَكاناً عَلِيّاً بِرَحْمَتِهِ","O Thou that didst forgive the omission of Adam and lifted up Idris to an exalted station by Thy mercy;"],["يا مَنْ نَجّى نُوحاً مِنَ الْغَرَقِ","O Thou that didst save Nooh from drowning;"],["يا مَنْ اَهْلَكَ عاداً الاْوُلى وَثَمُودَ فَما اَبْقى وَقَوْمَ نوُح","O Thou that didst destroy the former tribe of Ad and then Thamud, so that no trade of them remained, and destroyed the people of Noah aforetime,"],["مِنْ قَبْلُ اِنَّهُمْ كانُوا هُمْ اَظْلَمَ وَاَطْغى","for verily they were the most unjust and most rebellious;"],["وَالْمُؤْتَفِكَةَ اَهْوى","overturned the ruined and deserted towns;;"],["يا مَنْ دَمَّرَ عَلى قَوْمِ لوُط وَدَمْدَمَ عَلى قَوْمِ شُعَيْب","O Thou that destroyed the people of Lot; and annihilated the people of Sho'aib;"],["يا مَنِ اتَّخَذَ اِبْراهيمَ خَليلاً","O Thou that chose Ibrahim as a friend;"],["يا مَنِ اتَّخَذَ مُوسى كَليماً","O Thou that chose Musa as one spoken unto;"],["وَاتَّخَذَ مُحَمَّداً صَلَّى اللهُ عَلَيْهِ وَآلِهِ وَعَلَيْهِمْ اَجْمَعينَ حَبيباً","and chose Muhammed (Thy blessings be upon him and his Progeny) as Thy Beloved;"],["يا مُؤْتِىَ لُقْمانَ الْحِكْمَةَ وَالْواهِبَ لِسُلَيْمانَ مُلْكاً لا يَنْبَغى لاَِحَد مِنْ بَعْدِهِ","O Thou that gavest unto Luqman wisdom; and bestowed upon Sulaiman a kingdom the like of which shall not be merited by anyone after him;"],["يا مَنْ نَصَرَ ذَا الْقَرْنَيْنِ عَلَى الْمُلُوكِ الْجَبابِرَةِ","O Thou that didst afford succour unto the two-horned one against the mighty tyrants;"],["يا مَنْ اَعْطَى الْخِضْرَ الْحَيوةَ","O Thou that didst grant unto Khizr immortality;"],["وَرَدَّ لِيٌوشَعَ بْنِ نوُن الشَّمْسَ بَعْدَ","and brought back for Yusha, the son of Nun, the sun after it had set;"],["يا مَنْ رَبَطَ عَلى قَلْبِ اُمِّ مُوسى","O Thou that gave solace unto the heart of Musa's mother;"],["وَاَحْصَنَ فَرْجَ مَرْيَمَ ابْنَتِ عِمْرانَ","and protected the chastity of Mariam, the daughter of Imran;"],["يا مَنْ حَصَّنَ يَحْيَى بْنَ زَكَرِيّا","O Thou that didst fortify Yahya, the Son of Zakaria against sin;"],["مِنَ الذَّنْبِ وَسَكَّنَ عَنْ مُوسَى الْغَضَبَ","and abated the wrath for Musa;"],["يا مَنْ بَشَّرَ زَكَرِيّا بِيَحْيى","O Thou that gave glad tidings of (the Birth of) Yahya unto Zakaria;"],["يا مَنْ فَدا اِسْماعيلَ مِنَ الذَّبْحِ بِذِبْح عَظيم","O Thou that saved Ismaeel from slaughter by substituting for him the Great Sacrifice;"],["يا مَنْ قَبِلَ قُرْبانَ هابيلَ وَجَعَلَ اللَّعْنَةَ عَلى قابيلَ","O Thou that didst accept the offering of Habeel and placed the curse upon Qabeel."],["يا هازِمَ الاَْحْزابِ لُِمحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ","O Subduer of the alien hordes for Muhammad - the blessings of Allah be upon him and his Progeny -"],["صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّدِ","bestow Thy blessings upon Muhammad and his Progeny"],["وَ عَلى جَميعِ الْمُرْسَلينَ وَمَلائِكَتِكَ الْمُقَرَّبينَ","and upon all Thy Messengers and upon the Angels that are near Thee"],["وَاَهْلِ طاعَتِكَ اَجْمَعينَ","and upon all Thine obedient servants."],["وَاَسْأَلُكَ بِكُلِّ مَسْأَلَة سَأَلَكَ بِها اَحَدٌ مِمَّنْ رَضيتَ عَنْهُ","And I beg of Thee all the requests which anyone has begged of Thee with whom Thou has been pleased"],["فَحَتَمْتَ لَهُ عَلَى الاِْجابَةِ","and unto whom Thou has assured the granting thereof,"],["يا اَللهُ يا اَللهُ يا اَللهُ","O Allah, O Allah, O Allah,"],["يا رَحْمنُ يا رَحمنُ يا رَحْمنُ","O Most Merciful, O Most Merciful, O Most Merciful, O Most Merciful."],["يا رَحيمُ يا رَحيمُ يا رَحيمُ","O Most Beneficient, O Most Beneficient, O Most Beneficient, O Most Beneficient."],["يا ذَا الْجَلالِ وَالاِْكُرامِ يا ذَا الْجَلالِ وَ الاِْكْرامِ يا ذَا الْجَلالِ وَالاِْكْرامِ","O Lord of Majesty and Grace, O Lord of Majesty and Grace, O Lord of Majesty and Grace."],["بِهِ بِهِ بِهِ بِهِ بِهِ بِهِ بِهِ اَسْأَلُكَ بِكُلِّ اسْم سَمَّيْتَ بِهِ نَفْسَكَ","Thee, Through Thee, Through Thee, Through Thee, Through Thee, Through Thee, Through Thee I beseech thee with the help of all the Names whereby Thou hast named Thyself,"],["اَوْ اَنْزَلْتَهُ فى شَْيء مِنْ كُتُبِكَ","or which Thou hast sent down in any of Thy inspired Scriptures,"],["اَوِ اسْتَأثَرْتَ بِهِ فِى عِلْمِ الْغَيْبِ عِنْدَكَ","or Which Thou hast inscribed in Thy knowledge of the unknown;"],["وَبِمَعاقِدِ الْعِزِّ مِنْ عَرْشِكَ","and (I beseech Thee) in the name of the honored and exalted positions of Thy Throne,"],["وَبِمُنْتَهَى الرَّحْمَةِ مِنْ كِتابِكَ","and in the name of the utmost extent of Thy Mercy as expressed in Thy Book (the Quran)"],["وَبِما لَوْ اَنَّ ما فِى الاَْرْضِ مِنْ شَجَرَة اَقْلامٌ وَالْبَحْرُ يَمُدُّهُ","and in the name of that which \"If all the trees on earth were to become pens and all the seven seas ink,"],["مِنْ بَعْدِهِ سَبْعَةُ اَبْحُر ما نَفِدَتْ كَلِماتُ اللهِ","Words of Allah could not be fully written down.\""],["اِنَّ اللهَ عَزيزٌ حَكيمٌ","\"Verily Allah is the Honored, the Wise\";"],["وَ اَسْأَلُكَ بِاَسْمآئِكَ الْحُسْنَى","And I beseech Thee with the help of Thy Beautiful Names"],["الَّتى نَعَتَّها فى كِتابِكَ فَقُلْتَ","which Thou has praised in Thy Book, saying,:"],["وَللهِ الاَْسْمآءُ الْحُسْنى فَادْعوُهُ بِها","Unto Allah belong the beautiful names -- so call ye Him by Them;"],["وَقُلْتَ اُدْعُونى اَسْتَجِبْ لَكُمْ","And Thou hast said \"Call unto Me and I shall answer you;"],["وَقُلْتَ وَاِذا سَأَلَكَ عِبادى عَنّى","and Thou has said, \"And when My servants ask something of Me,"],["فَانّى قَريبٌ اُجيبُ دَعْوَةَ الدّاعِ اِذا دَعانِ","lo, I am near, and I grant the prayer of the supplicant when he asks anything of Me, so pray ye unto Me and believe in Me, that ye may be made perfect;"],["وَقُلْتَ يا عِبادِىَ الّذَينَ اَسْرَفوُا عَلى اَنْفُسِهِمْ","And Thou has said, \"O My servants who have wronged yourselves,"],["لا تَقْظَوُا مِنْ رَحْمَةِ اللهِ اِنَّ اللهَ يَغْفِرُ الذُّنُوبَ جَميعاً","despair not of the Mercy of Allah; verilly Allah forgiveth all the sins;"],["اِنَّهُ هُوَ الْغَفُورُ الرَّحيمُ","verily He is the Forgiving, the Merciful.\""],["وَاَنَا اَسْاَلُكَ يا اِلـهى وَاَدْعُوكَ يا رَبِّ وَاَرْجُوكَ","Therefore I pray unto Thee, My God, and I ask Thee, My Cherisher and Sustainer,"],["يا سَيِّدى وَاَطْمَعُ فى اِجابَتى يا مَوْلاىَ كَما وَعَدْتَنى","and I hope from Thee, my Chief, and I crave Thy acceptance of my prayer, O my Protector, even as Thou hast promised me,"],["وَقَدْ دَعَوْتُكَ كَما اَمَرْتَنى فَافْعَلْ بى ما","and I call upon Thee even as Thou hast commanded me --"],["اَنْتَ اَهْلُهُ يا كَريمُ","So, do unto me what pleases Thee to do, O Generous One!"],["وَالْحَمْدُ للهِِ رَبِّ الْعالَمينَ","And all Praise be to Allah, the Cherisher and Sustainer of the worlds,"],["وَصَلَّى اللهُ عَلى مُحَمَّد وَآلِهِ اَجْمَعينَ","and the blessings of Allah be upon Muhammad and all His Holy Descendants."]]},{"id":"dua-nudbah","cat":"Duʿāʾ","t":{"en":"Duʿāʾ al-Nudbah","ar":"دعاء الندبة"},"lines":[["بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ","O Allah, I beseech Thee with Thy Name;"],["اَلْحَمْدُ للهِ رَبِّ الْعالَمينَ","Praise be to Allah, the Lord of the worlds."],["وَ صَلَّى اللهُ عَلى سَيِّدِنا مُحَمَّدٍ","And blessings of Allah and peace be on our Chief Muhammad,"],["نَبِيِّهِ وَ آلِهِ وَ سَلَّمَ تَسْليماً","His Prophet, and on his children."],["اَللّـهُمَّ لَكَ الْحَمْدُ عَلى ما جَرى بِهِ قَضاؤكَ في اَوْلِيائِكَ","O my Allah! (All) praise is for Thee for that which Thou decided upon and resolved in the matter of Thy friends,"],["الَّذينَ اسْتَخْلَصْتَهُمْ لِنَفْسِكَ وَ دينِكَ","whom Thou purified for Thyself and Thy religion."],["اِذِ اخْتَرْتَ لَهُمْ جَزيلَ ما عِنْدَكَ مِنَ النَّعيمِ الْمُقيمِ","When wisdom and high rank from Thee, prostrated themselves in adoration before them (from the Bountiful Preserving Lord),"],["الَّذي لا زَوالَ لَهُ وَ لاَ اضْمِحْلالَ","for whom neither there was any decreased, nor dispersion thereafter,"],["بَعْدَ اَنْ شَرَطْتَ عَلَيْهِمُ الزُّهْدَ في دَرَجاتِ هذِهِ الدُّنْيَا الدَّنِيَّةِ","then Thou stipulated for them piety and righteousness. While they were in this mean and crooked world,"],["وَ زُخْرُفِها وَ زِبْرِجِها","free from its pomp, vanity and false enjoyments,"],["فَشَرَطُوا لَكَ ذلِكَ وَ عَلِمْتَ مِنْهُمُ الْوَفاءَ بِهِ فَقَبِلْتَهُمْ وَ قَرَّبْتَهُمْ","Thy overreaching authority made known their identity; and equipped them with sincerity and perfection stood surety for them and communicated intimately with them,"],["وَ قَدَّمْتَ لَهُمُ الذِّكْرَ الْعَلِيَّ وَ الثَّناءَ الْجَلِىَّ","sent the news of their auspicious arrival in advance, and praised them"],["وَ اَهْبَطْتَ عَلَيْهِمْ مَلائِكَتَكَ وَ كَرَّمْتَهُمْ بِوَحْيِكَ","clear terms for the benefit of one and all. Fell down on the ground in prostration Thy Angels before them, Thou chose them to reveal Thy Words,"],["وَ رَفَدْتَهُمْ بِعِلْمِكَ","gave them Thy wisdom as a gift,"],["وَ جَعَلْتَهُمُ الذَّريعَةَ اِلَيْكَ وَ الْوَسيلَةَ اِلى رِضْوانِكَ","set them up as the (only) medium to reach Thee, the only means to the eternal land of peace and happiness."],["فَبَعْضٌ اَسْكَنْتَهُ جَنَّتَكَ اِلى اَنْ اَخْرَجْتَهُ مِنْها","One dwelled in Paradise until Thou sent him on (as the first Prophet)."],["وَ بَعْضٌ حَمَلْتَهُ في فُلْكِكَ وَ نَجَّيْتَهُ وَ مَنْ آمَنَ مَعَهُ مِنَ الْهَلَكَةِ بِرَحْمَتِكَ","One was made to cruise the \"Ark\", and had been rescued, and kept safe from destruction through Thy mercy."],["وَ بَعْضٌ اتَّخَذْتَهُ لِنَفْسِكَ خَليلاً وَ سَأَلَكَ لِسانَ صِدْقٍ","One was chosen and prepared for Thy Mission, as (Thy) Friend, (who) made a request to Thee for a good report"],["فِي الاْخِرينَ فَاَجَبْتَهُ وَ جَعَلْتَ ذلِكَ عَلِيّاً","(his) later generations, so Thou approved and complied with, exalted them and gave them authority."],["وَ بَعْضٌ كَلَّمْتَهُ مِنْ شَجَـرَةٍ تَكْليماً","One was spoken directly through the Tree,"],["وَ جَعَلْتَ لَهُ مِنْ اَخيهِ رِدْءاً وَ وَزيراً","his brother was appointed his successor and helper."],["وَ بَعْضٌ اَوْلَدْتَهُ مِنْ غَيْرِ اَبٍ","One was brought in without a father,"],["وَ آتَيْتَهُ الْبَيِّناتِ وَ اَيَّدْتَهُ بِرُوحِ الْقُدُسِ","was given clear proofs, and was supported with the Holy Spirit."],["وَ كُلٌّ شَرَعْتَ لَهُ شَريعَةً","For each Thou prescribed a Divine law,"],["وَ نَهَجْتَ لَهُ مِنْهاجاً ، وَ تَخَيَّرْتَ لَهُ اَوْصِياءَ","and set up a traced out path, each was appointed a guardian-executor,"],["مُسْتَحْفِظاً بَعْدَ مُسْتَحْفِظٍ مِنْ مُدَّةٍ اِلى مُدَّةٍ","(and each) fulfilled the duty after being kept safe and protected,"],["اِقامَةً لِدينِكَ ، وَ حُجَّةً عَلى عِبادِكَ","in the term of establishing Thy religion, a witness and argument over Thy servants (mankind),"],["وَ لِئَلّا يَزُولَ الْحَقُّ عَنْ مَقَرِّهِ وَ يَغْلِبَ الْباطِلُ عَلى اَهْلِهِ","Lest the truth staggered from its firm stand and foundation, and the falsehood conquered the hearts of the people,"],["وَ لا يَقُولَ اَحَدٌ لَوْلا اَرْسَلْتَ اِلَيْنا رَسُولاً مُنْذِراً","and might not say a single man: \"If only Thou had sent a Messenger unto us as a Warner,"],["وَ اَقَمْتَ لَنا عَلَماً هادِياً","to show us the path of wisdom and guidance,"],["فَنَتَّبِـعَ آياتِكَ مِنْ قَبْلِ اَنْ نَذِلَّ وَ نَخْزى","so that we might have followed Thy revelations before we were (thus) humbled and disgraced!\""],["اِلى اَنِ انْتَهَيْتَ بالأمْرِ اِلى حَبيبِكَ وَ نَجيبِكَ مُحَمَّدٍ صَلَّى اللهُ عَلَيْهِ وَ آلِهِ","Thou made plans to bring out the wonderful advent of Muhammad, (Send blessing on him and on his children)."],["فَكانَ كَمَا انْتَجَبْتَهُ سَيِّدَ مَنْ خَلَقْتَهُ","So Thou just as chose him master of Whosoever Thou created,"],["وَ صَفْوَةَ مَنِ اصْطَفَيْتَهُ ، وَ اَفْضَلَ مَنِ اجْتَبَيْتَهُ","made him (whom Thou Selected), pure, clean and the best, exalted and praised him (whom Thou elected),"],["وَ اَكْرَمَ مَنِ اعْتَمَدْتَهُ ، قَدَّمْتَهُ عَلى اَنْبِيائِكَ","surpassed in generosity and liberality while bestowing high-mindedness and beneficence upon him (whom Thou took in confidence and relied upon); made him leader-in-chief of (all) thy Prophets,"],["وَ بَعَثْتَهُ اِلَى الثَّقَلَيْنِ مِنْ عِبادِكَ","and sent him to the troubled world of men and jinn, among Thy servants,"],["وَ اَوْطَأتَهُ مَشارِقَكَ وَ مَغارِبَكَ ، وَ سَخَّرْتَ لَهُ الْبُراقَ","lowered and humbled before him the Easts and the Wests, under his total control was brought all affairs,"],["وَ عَرَجْتَ ( به ) بِرُوْحِهِ اِلى سَمائِكَ","exalted his soul in Thy heavens"],["وَ اَوْدَعْتَهُ عِلْمَ ما كانَ وَما يَكُونُ اِلَى انْقِضاءِ خَلْقِكَ","gave over to him the knowledge of what took place and what will happen, concerning facts and operation of creation."],["ثُمَّ نَصَرْتَهُ بِالرُّعْبِ","Then invested him with awe"],["حَفَفْتَهُ بِجَبْرَئيلَ وَ ميكائيلَ وَ الْمُسَوِّمينَ مِنْ مَلائِكَتِكَ","and majesty, Jibraeel, Meekaaeel, and distinguished Angels stood around;"],["وَ وَعَدْتَهُ اَنْ تُظْهِرَ دينَهُ عَلَى الدّينِ كُلِّهِ وَ لَوْ كَرِهَ الْمُشْرِكُونَ","him at his beck and call, gave Thy word to him that Thou would make his religion prevail over all religions, however much the idolaters may be averse."],["وَ ذلِكَ بَعْدَ اَنْ بَوَّأتَهُ مَبَوَّأَ صِدْقٍ مِنْ اَهْلِهِ","Thereafter acknowledged his atonement and provided good and perfection for his children,"],["وَ جَعَلْتَ لَهُ وَ لَهُمْ اَوَّلَ بَيْتٍ وُضِعَ لِلنّاسِ","allotted for him and his children the first sanctuary appointed for mankind,"],["لَلَّذي بِبَكَّةَ مُبارَكاً وَ هُدىً لِلْعالَمينَ","at Becca (Mecca), a blessed place, a guidance to the people"],["فيهِ آياتٌ بَيِّناتٌ مَقامُ اِبْراهيمَ وَ مَنْ دَخَلَهُ كانَ آمِناً","wherein are plain and clear signs; the place where Ibraahim stood up to pray, and whosoever enters it is safe."],["وَ قُلْتَ : { اِنَّما يُريدُ اللهُ لِيُذْهِبَ عَنْكُمُ الرِّجْسَ","Thou said: \"Allah’s wish is but to remove uncleanness"],["اَهْلَ الْبَيْتِ وَ يُطَهِّرَكُمْ تَطْهيراً }","far from you, O \"People of the House\", and purify you with a thorough purification.\""],["ثُمَّ جَعَلْتَ اَجْرَ مُحَمَّدٍ صَلَواتُكَ عَلَيْهِ وَ آلِهِ مَوَدَّتَهُمْ في كِتابِكَ","Thereupon Thou settled conclusively fee (recompense) of Muhammad (Thy blessings be on him and on his children) love for them, in Thy Holy Book."],["فَقُلْتَ: { قُلْ لا اَسْاَلُكُمْ عَلَيْهِ اَجْراً اِلاَّ الْمَوَدَّةَ فِى الْقُرْبى }","So Thou said: \"Say (O Muhammad): I ask of you no fee (recompense) therefore, save love of (my) Kinsfolk.\""],["وَ قُلْتَ : { ما سَألْتُكُمْ مِنْ اَجْرٍ فَهُو َلَكُمْ }","And Thou said: \"Whatever recompense (return) I have asked for you, (it) is only for yourselves.\""],["وَ قُلْتَ : { ما اَسْاَلُكُمْ عَلَيْهِ مِنْ اَجْرٍ الّا مَنْ شاءَ اَنْ يَتَّخِذَ اِلى رَبِّهِ سَبيلاً }","And Thou said: \"I ask of you no reward for this, save that, whoso will, chooses a way unto his Lord.\""],["فَكانُوا هُمُ السَّبيلَ اِلَيْكَ وَ الْمَسْلَكَ اِلى رِضْوانِكَ","Therefore they are the (only) means to (approach) Thee, the (only) medium to get Thy favours."],["فَلَمَّا انْقَضَتْ اَيّامُهُ اَقامَ وَلِيَّهُ عَلِيَّ بْنَ اَبي طالِب صَلَواتُكَ عَلَيْهِما وَ آلِهِما هادِياً","So Thou certainly did not let his hard work go waste, and gave authority to his successor, Ali ibne Abi Taalib, (Thy blessings be on them both, and on this children), a guide."],["اِذْ كانَ هُوَ الْمُنْذِرَ وَ لِكُلِّ قَوْمٍ هادٍ ، فَقالَ وَ الْمَلأُ اَمامَهُ :","At the time when he was made a warner and a guide for every people, said he (the Holy Prophet), their Guide, in a public meeting overflowing with people;"],["مَنْ كُنْتُ مَوْلاهُ فَعَلِيٌّ مَوْلاهُ","\"Of Whomsoever I am the Mawlaa (Lord, Master) Ali is his Mawlaa."],["اَللّـهُمَّ والِ مَنْ والاهُ وَ عادِ مَنْ عاداهُ وَ انْصُرْ مَنْ نَصَرَهُ وَ اخْذُلْ مَنْ خَذَلَهُ","O Allah! be a friend of him who is a friend of him, be an enemy of him who is an enemy of him, help that man who helps him, forsake that man who forsakes him\""],["وَ قالَ : مَنْ كُنْتُ اَنَا نَبِيَّهُ فَعَلِيٌّ اَميرُهُ","said: \"Of whosoever I am the Prophet Ali is his Chief.\""],["وَ قالَ : اَنَا وَ عَلِيٌّ مِنْ شَجَرَةٍ واحِدَةٍ وَ سائِرُالنَّاسِ مِنْ شَجَرٍ شَتّى","And said: \"I and Ali are (one basic root of) a tree, and the rest of mankind are like diverse plants,"],["وَ اَحَلَّهُ مَحَلَّ هارُونَ مِنْ مُوسى","he proclaims the position (relationship) of Haaroon to Moosaa.\""],["فَقال لَهُ : اَنْتَ مِنّي بِمَنْزِلَةِ هارُونَ مِنْ مُوسى الّا اَنَّهُ لا نَبِيَّ بَعْدي","Therefore he told him: \"I am to you as Moosaa was to Haaroon, but certainly there is no Prophet after me.\""],["وَ زَوَّجَهُ ابْنَتَهُ سَيِّدَةَ نِساءِ الْعالَمينَ","His (Ali’s) life partner was his (Muhammad’s) daughter the chief of the women of the worlds."],["وَ اَحَلَّ لَهُ مِنْ مَسْجِدِهِ ما حَلَّ لَهُ ، وَ سَدَّ الاَْبْوابَ اِلاّ بابَهُ","Lawful was for him (Ali), in \"the mosque\", that which was permitted to him (Muhammad), all doors were closed, except his door."],["ثُمَّ اَوْدَعَهُ عِلْمَهُ وَ حِكْمَتَهُ","He (Muhammad) gave his knowledge and wisdom into his (Ali’s) keeping."],["فَقالَ : اَنـَا مَدينَةُ الْعِلْمِ وَ عَلِىٌّ بابُها","He said: \"I am the city (center) of knowledge and Ali is its gate."],["فَمَنْ اَرادَ الْمَدينَةَ وَ الْحِكْمَةَ فَلْيَاْتِها مِنْ بابِها","Whoso desires to approach and dwell in the city of knowledge and wisdom should come through its door.\""],["ثُمَّ قالَ : اَنْتَ اَخي وَ وَصِيّي وَ وارِثي","Thereafter he said: \"You are my brother, successor and inheritor,"],["لَحْمُكَ مِنْ لَحْمي وَ دَمُكَ مِنْ دَمي وَ سِلْمُكَ سِلْمي وَ حَرْبُكَ حَرْبي","your flesh is my flesh, your blood is my blood, your truce is my truce, your fight is my fight,"],["وَ الإيمانُ مُخالِطٌ لَحْمَكَ وَ دَمَكَ كَما خالَطَ لَحْمي وَ دَمي","faith is blended, mixed and mingled (part and parcel) in your flesh and blood, just as it is compounded in my flesh and blood,"],["وَ اَنْتَ غَداً عَلَى الْحَوْضِ خَليفَتي","you shall take charge of the reservoir of my inheritance,"],["وَ اَنْتَ تَقْضي دَيْني وَ تُنْجِزُ عِداتي","are the fulfilment of my religion, you shall execute and keep alive my \"way of life\","],["وَ شيعَتُكَ عَلى مَنابِرَ مِنْ نُورٍ مُبْيَضَّةً وُجُوهُهُمْ حَوْلي فِي الْجَنَّةِ وَ هُمْ جيراني","your friends and followers shall speak with authority, command respect and hold the torch of good manners and refinements, their faces will be all around me in the eternal land of peace and bliss (Paradise), in my close company."],["وَ لَوْلا اَنْتَ يا عَلِيُّ لَمْ يُعْرَفِ الْمُؤْمِنُونَ بَعْدي","Were it not you O Ali, the faithfuls would not know the truth after me.\""],["وَ كانَ بَعْدَهُ هُدىً مِنَ الضَّلالِ وَ نُوراً مِنَ الْعَمى ، وَ حَبْلَ اللهِ الْمَتينَ وَ صِراطَهُ الْمُسْتَقيمَ","After him (Muhammad) be (Ali) was the guide for the wanderers, a bright light in the blind darkness, the strong rope of Allah, and the right path,"],["لا يُسْبَقُ بِقَرابَةٍ في رَحِمٍ وَ لا بِسابِقَةٍ في دينٍ","did not ever hold back kindness and compassion from the common people, nor ever made excuses or delay to give priority to the matters of religion,"],["وَ لا يُلْحَقُ في مَنْقَبَةٍ مِنْ مَناقِبِهِ","nor blew his own trumpet nor felt proud of his glory,"],["يَحْذُو حَذْوَ الرَّسُولِ صَلَّى اللهُ عَلَيْهِما وَ آلِهِما","did the same thing the Messenger used to do, (Blessing of Allah be on them both and on their children)"],["وَ يُقاتِلُ عَلَى التَّأويلِ وَ لا تَأخُذُهُ فِي اللهِ لَوْمَةُ لائِمٍ","put an end to misinterpretation, did not lose temper, for the sake of Allah, if any one turned to mud-slinging and name-calling."],["قَدْ وَتَرَ فيهِ صَناديدَ الْعَرَبِ وَ قَتَلَ اَبْطالَهُمْ وَ ناوَشَ ( ناهش ) ذُؤْبانَهُمْ","He had thrown the proud tribal chiefs of Arabia into a fright, destroyed their heroes, attacked and dispersed their cavalries,"],["فَاَوْدَعَ قُلُوبَهُمْ اَحْقاداً بَدْرِيَّةً وَ خَيْبَرِيَّةً وَ حُنَيْنِيَّةً وَ غَيْرَهُنَّ","because of which hatred and deep grudge took root in their hearts. Badr, Khaybar, and Hunain created jealousy and envy in them,"],["فَاَضَبَّتْ عَلى عَداوَتِهِ وَ اَكَبَّتْ عَلى مُنابَذَتِهِ","therefore, united they joined hands to oppose him, and came out in great number to fight against him,"],["حَتّى قَتَلَ النّاكِثينَ وَ الْقاسِطينَ وَ الْمارِقينَ","till he destroyed all deserters, who had swerved from what was right, the shameless who deviated from true religion,"],["وَ لَمّا قَضى نَحْبَهُ وَ قَتَلَهُ اَشْقَى الاْخِرينَ يَتْبَعُ اَشْقَى الاَْوَّلينَ","while he was carrying out the important mission. Killed him a malicious criminal, a contemporary, serving the interest and following the doctrine of earlier impudent villians."],["لَمْ يُمْتَثَلْ اَمْرُ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَ آلِهِ فِي الْهادينَ بَعْدَ الْهادينَ","An unparalleled and outlandish approach was applied to the directions of the Messenger of Allah, (Blessings of Allah be on him and on his children), concerning the \"Guides\" (Imaams), one after the other."],["وَ الاُْمَّةُ مُصِرَّةٌ عَلى مَقْتِهِ","The narrow-minded obstinate \"ummah\" did not care for and had ill-feelings towards him."],["مُجْتَمِعَةٌ عَلى قَطيعَةِ رَحِمِهِ وَ اِقْصاءِ وُلْدِهِ","Flocked together to pass up and deny his connection with his family, and pushed his children out of their way,"],["اِلّا الْقَليلَ مِمَّنْ وَفى لِرِعايَةِ الْحَقِّ فيهِمْ","but a handful of sincere faithfuls kept their promise and dutifully upheld the rights of his children;"],["فَقُتِلَ مَنْ قُتِلَ ، وَ سُبِيَ مَنْ سُبِيَ وَ اُقْصِيَ مَنْ اُقْصِيَ","Some were slain, some were held prisoners, some were sent to distant foreign lands, and they met face to face (when came upon) their destiny (martyrdom)."],["وَ جَرَى الْقَضاءُ لَهُمْ بِما يُرْجى لَهُ حُسْنُ الْمَثُوبَةِ","That which is given to each (of them) as reward of good deeds is the best recompense,"],["اِذْ كانَتِ الاَْرْضُ للهِ يُورِثُها مَنْ يَشاءُ مِنْ عِبادِهِ وَ الْعاقِبَةُ لِلْمُتَّقينَ","since the earth belongs to Allah, and He gives it for an inheritance to whom He wants from among His servants, and the (good) end is for the God-fearing wise;"],["وَ سُبْحانَ رَبِّنا اِنْ كانَ وَعْدُ رَبِّنا لَمَفْعُولاً","glory to our Lord! Verily the promise of our Lord must be fulfilled;"],["وَ لَنْ يُخْلِفَ اللهُ وَعْدَهُ وَ هُوَ الْعَزيزُ الْحَكيمُ","does not break His word, He is Almighty, Wise."],["فَعَلَى الاَْطائِبِ مِنْ اَهْلِ بَيْتِ مُحَمَّدٍ وَ عَلِيٍّ صَلَّى اللهُ عَلَيْهِما وَ آلِهِما","So be purified and refined by making known and remembering the choicest children of Muhammad and Ali, blessings of Allah be on them both, and on their children."],["فَلْيَبْكِ الْباكُونَ ، وَ اِيّاهُمْ فَلْيَنْدُبِ النّادِبُونَ","The heartbroken, in tears, make their hearts bleed, together with them, the deeply moved perceptive men of letters describe their wisdom and liberality,"],["وَ لِمِثْلِهِمْ فَلْتَذْرِفِ ( فَلْتًدرِ ) الدُّمُوعُ ، وَ لْيَصْرُخِ الصّارِخُونَ ، وَ يَضِجَّ الضّاجُّونَ ، وَ يَعِـجَّ الْعاجُّوَن","as they themselves used to do, eyes of sensitive and thoughtful people are full of overflowing tears, their voices choked up with emotion; they cry out to protest against the injustice done, they call up dumb and insensate souls to stir and take notice."],["اَيْنَ الْحَسَنُ اَيْنَ الْحُسَيْنُ اَيْنَ اَبْناءُ الْحُسَيْنِ","Where is Hasan? Where is Husayn? Where are the children of Husayn?"],["صالِحٌ بَعْدَ صالِـحٍ ، وَ صادِقٌ بَعْدَ صادِقٍ","whole good, one and all! The truth altogether!"],["اَيْنَ السَّبيلُ بَعْدَ السَّبيلِ","Where is the regular unbroken vital connection?"],["اَيْنَ الْخِيَرَةُ بَعْدَ الْخِيَرَةِ","Where is the on going sequence of desirable goodness?"],["اَيْنَ الشُّمُوسُ الطّالِعَةُ","Where are the clear source and spring of Light (vision and insight)?"],["اَيْنَ الاَْقْمارُ الْمُنيرَةُ","Where are the lively vivid handsome faces?"],["اَيْنَ الاَْنْجُمُ الزّاهِرَةُ","Where are the distinctly visible pioneers?"],["اَيْنَ اَعْلامُ الدّينِ وَ قَواعِدُ الْعِلْمِ","Where are the \"know all the answers\" scholars who communicated and made clear the religion of Allah?"],["اَيْنَ بَقِيَّةُ اللهِ الَّتي لا تَخْلُو مِنَ الْعِتْرَةِ الْهادِيـَةِ","The fundamentals of knowledge and wisdom! Where is the ‘Everlasting legacy of God\"? (never ever is the \"family of Guides\" without One)."],["اَيـْنَ الـْمُعَدُّ لِـقَطْعِ دابِرِ الظَّلَمَةِ","Where is the impenetrable defense who broke the back of the oppressive tyrants?"],["اَيْنَ الْمُنْتَظَرُ لاِِقامَةِ الاَْمْتِ وَ اْلعِوَجِ","Where is the \"awaited saviour\" who will set the have-nots and the depressed on their feet?"],["اَيْنَ الْمُرْتَجى لاِزالَةِ الْجَوْرِ وَ الْعُدْوانِ","Where is the \"The Hope\" who will put and end to tyranny and oppression?"],["اَيْنَ الْمُدَّخَرُ لِتَجْديدِ الْفَرآئِضِ و َالسُّنَنِ","Where is the \"preserved guaranty\" who shall give new life to rule of law and refined way of life?"],["اَيْنَ الْمُتَخَيَّرُ لاِِعادَةِ الْمِلَّةِ وَ الشَّريعَةِ","Where is the \"Chosen in preference good\" who shall raise the spirits of the people and give currency to justice and fairplay?"],["اَيْنَ الْمُؤَمَّلُ لاِِحْياءِ الْكِتابِ وَ حُدُودِهِ","Where is the \"hope-giving confidante\" who shall make full use of the \"Book\" and define the sphere of action?"],["اَيْنَ مُحْيي مَعالِمِ الدّينِ وَ اَهْلِهِ","Where is he who shall blot out dogma in the matter of religion and his (Muhammad’s) children?"],["اَيْنَ قاصِمُ شَوْكَةِ الْمُعْتَدينَ","Where is he who shall break up meddlesome trouble and tampering?"],["اَيْنَ هادِمُ اَبْنِيَةِ الشِّرْكِ وَ النِّفاقِ","Where is he who shall pull down the foundations of confusion (polytheists) and hypocrisy?"],["اَيْنَ مُبيدُ اَهْلِ الْفُسُوقِ وَ الْعِصْيانِ وَ الطُّغْيانِ","Where is he who shall stamp out corruption, vice, reaction and injustice?"],["اَيْنَ حاصِدُ فُرُوعِ الْغَيِّ وَ الشِّقاقِ ( النِفاقِ )","Where is he who shall trim the outgrowth of despair, longing and hardships?"],["اَيْنَ طامِسُ آثارِ الزَّيْغِ وَ الاَْهْواء","Where is he who shall erase the traces of unfairness and self-seeking conceit?"],["اَيْنَ قاطِعُ حَبائِلِ الْكِذْبِ ( الكَذِبِ ) وَ الاِْفْتِراءِ","Where is he who shall untie the twisted knotes of falsehood and disruption?"],["اَيْنَ مُبيدُ الْعُتاةِ وَ الْمَرَدَةِ","Where is he who shall separate senselessness and insolence from the people?"],["اَيْنَ مُسْتَأصِلُ اَهْلِ الْعِنادِ وَ التَّضْليلِ وَ الاِْلْحادِ","Where is he who shall tear up by the roots obstinacy, corruption and apostasy?"],["اَيْنَ مُـعِزُّ الاَْوْلِياءِ وَ مُذِلُّ الاَْعْداءِ","Where is he who shall love dearly the favourites of Allah and take pains to tame and train the trangressors?"],["اَيْنَ جامِعُ الْكَلِمَةِ ( الكَلِمِ ) عَلَى التَّقْوى","Where is he who shall make people familiar with \"words of wisdom\"?"],["اَيْنَ بابُ اللهِ الَّذى مِنْهُ يُؤْتى","Where is the ultimate (Divine) source of plenty and prosperity?"],["اَيْنَ وَجْهُ اللهِ الَّذى اِلَيْهِ يَتَوَجَّهُ الاَْوْلِياءُ","Where is the \"Divine aspect\" the God-fearing may look up to? Where is the link that connects the cosmic complex?"],["اَيْنَ السَّبَبُ الْمُتَّصِلُ بَيْنَ الاَْرْضِ وَ السَّماءِ","Where is the authority who shall communicate and make known the true point of view?"],["اَيْنَ صاحِبُ يَوْمِ الْفَتْحِ وَ ناشِرُ رايَةِ الْهُدى","Where is the author of the conception of peace, fairplay and welfare?"],["اَيْنَ مُؤَلِّفُ شَمْلِ الصَّلاحِ وَ الرِّضا","Where is the author of the conception of peace, fairplay and welfare?"],["اَيْنَ الطّالِبُ بِذُحُولِ الاَْنْبِياءِ وَ اَبْناءِ الاَْنْبِياءِ","Where is the defender of the traditions of the Prophets and their children?"],["اَيْنَ الطّالِبُ ( المُطالِبُ ) بِدَمِ الْمَقْتُولِ بِكَرْبَلاءَ","Where is the investigator of the blood of the Martyrs of Karbalaa?"],["اَيْنَ الْمَنْصُورُ عَلى مَنِ اعْتَدى عَلَيْهِ وَ افْتَرى","Where is he who shall get the upper hand over the perpetrators of crime and greed?"],["اَيْنَ الْمُضْطَرُّ الَّذي يُجابُ اِذا دَعا","Where is he who shall not rest until he answers the cries of help when called upon?"],["اَيْنَ صَدْرُ الْخَلائِقِ ذُوالْبِرِّ وَ التَّقْوى","Where is the foremost leader of the people – the just, the truthful and the wise?"],["اَيْنَ ابْنُ النَّبِىِّ الْمُصْطَفى ، وَ ابْنُ عَلِيٍّ الْمُرْتَضى","Where is the son of the chosen Prophet? The son of Ali Al-Murtaza!"],["وَ ابْنُ خَديجَةَ الْغَرّآءِ ، وَ ابْنُ فاطِمَةَ الْكُبْرى","The son of Khadeejah, the resplendent! The son of Faatimah, the great!"],["بِاَبي اَنْتَ وَ اُمّي وَ نَفْسي لَكَ الْوِقاءُ وَ الْحِمى","My father, my mother, and I turn to you for protection and sanctuary."],["يَا بْنَ السّادَةِ الْمُقَرَّبينَ","O son of the favourite Leaders!"],["يَا بْنَ النُّجَباءِ الاَْكْرَمينَ","O Son of the distinguished nobles!"],["يَا بْنَ الْهُداةِ الْمَهْدِيّينَ ( المُهْتَدينَ )","O son of the rightly guided Guides!"],["يَا بْنَ الْخِيَرَةِ الْمُهَذَّبينَ","O Son of the most refined high-minded liberals!"],["يَا بْنَ الْغَطارِفَةِ الاَْنْجَبينَ","O Son of the select generous Guardians!"],["يَا بْنَ الاَْطائِبِ الْمُطَهَّرينَ ( المُتَطَهْريِِنَ )","O son of the polite and pure purifiers!"],["يَا بْنَ الْخَضارِمَةِ الْمُنْتَجَبينَ","O Son of the impartial judges!"],["يَا بْنَ الْقَماقِمَةِ الاَْكْرَمينَ (الأكْبَرينَ )","O Son of the openhanded hosts!"],["يَا بْنَ الْبُدُورِ الْمُنيرَةِ","O Son of the mature teachers!"],["يَا بْنَ السُّرُجِ الْمُضيئَةِ","O Son of the brilliant fulfillers!"],["يَا بْنَ الشُّهُبِ الثّاقِبَةِ","O Son of the clear and precise arguments who penetrated deep (into the domain of mind)!"],["يَا بْنَ الاَْنْجُمِ الزّاهِرَةِ","O inheritor of the made known prophesy!"],["يَا بْنَ السُّبُلِ الْواضِحَةِ","O inheritor of the clear preaching!"],["يَا بْنَ الاَْعْلامِ الّلائِحَةِ","O inheritor of the evident signs!"],["يَا بْنَ الْعُلُومِ الْكامِلَةِ","O inheritor of the exact science!"],["يَا بْنَ السُّنَنِ الْمَشْهُورَةِ","O inheritor of the widely sought after culture and customs!"],["يَا بْنَ الْمَعالِمِ الْمَأثُورَةِ","O inheritor of the milestones of glory and greatness!"],["يَا بْنَ الْمُعْجِزاتِ الْمَوْجُودَةِ","O inheritor of the extraordinary events!"],["يَا بْنَ الدَّلائِلِ الْمَشْهُودَةِ ( المَشْهُورَةِ )","O inheritor of the reason that had been put to experiment!"],["يَا بْنَ الصـِّراطِ الْمُسْتَقيمِ","O inheritor of the Right Path!"],["يَا بْنَ النَّبَأِ الْعَظيمِ","O inheritor of the Message that made deep impression on mankind!"],["يَا بْنَ مَنْ هُوَ في اُمِّ الْكِتابِ لَدَى اللهِ عَلِيٌّ حَكيمٌ","O Son of him who is in the \"Mother of the Book\" kept with Allah, the Highest High, the All-wise."],["يَا بْنَ الآياتِ وَ الْبَيِّناتِ","O inheritor of the convincing proofs!"],["يَا بْنَ الدَّلائِلِ الظّاهِراتِ","O inheritor of the genuine evidence!"],["يَا بْنَ الْبَراهينِ الْواضِحاتِ الْباهِراتِ","O inheritor of the distinctly visible demonstration!"],["يَا بْنَ الْحُجَجِ الْبالِغاتِ","O inheritor of the decisive information!"],["يَا بْنَ النِّعَمِ السّابِغاتِ","O inheritor of the absolute joy and happiness!"],["يَا بْنَ طه وَ الْـمُحْكَماتِ","O inheritor of \"T’aa-haa\" and clear wisdom!"],["يَا بْنَ يس وَ الذّارِياتِ","O inheritor of \"Yaa seen\" and \"Zaariyaat\""],["يَا بْنَ الطُّورِ وَ الْعادِياتِ","O inheritor of \"T’oor\" and \"A’adiyaat\""],["يَا بْنَ مَنْ دَنا فَتَدَلّى فَكانَ قابَ قَوْسَيْنِ اَوْ اَدْنى دُنُوّاً وَ اقْتِراباً مِنَ الْعَلِيِّ الاَْعْلى","O Son of him who \"drew near and came down till he was two bows’ length or nearer.\" (The Highest High came near and received him gladly)."],["لَيْتَ شِعْري اَيْنَ اسْتَقَرَّتْ بِكَ النَّوى","If I but knew the destination of your purposeful journey!"],["بَلْ اَيُّ اَرْضٍ تُقِلُّكَ اَوْ ثَرى ، اَبِرَضْوى اَوْ غَيْرِها اَمْ ذي طُوى","To which isolated land did you go? Good, pleasant and satisfying? Or otherwise? Or in well guarded concealment?"],["عَزيزٌ عَلَيَّ اَنْ اَرَى الْخَلْقَ وَ لا تُرى","It breaks my heart (when) I look at all that has been created, but cannot see you,"],["وَ لا اَسْمَعُ لَكَ حَسيساً وَ لا نَجْوى","nor hear a whisper about your whereabouts, nor any secret communication!"],["عَزيزٌ عَلَيَّ اَنْ ( لا تُحِيطَ بِِيَ دُونكَ ) تُحيطَ بِكَ دُونِيَ الْبَلْوى وَ لا يَنالُكَ مِنّي ضَجيجٌ وَ لا شَكْوى","It is disheartening to know that you are attending to and watching over the disorder and confusion, and I, in the thick of violent turmoil, am far away, unable to give report of injustice."],["بِنَفْسي اَنْتَ مِنْ مُغَيَّبٍ لَمْ يَخْلُ مِنّا","I eagerly long for you who is out of sight, but has not forsaken us."],["بِنَفْسي اَنْتَ مِنْ نازِحٍ ما نَزَحَ ( يَنْزِحُ ) عَنّا","I eagerly long for you who has departed and is invisible, but is not far from us."],["بِنَفْسي اَنْتَ اُمْنِيَّةُ شائِقٍ يَتَمَنّى ، مِنْ مُؤْمِن وَ مُؤْمِنَةٍ ذَكَرا فَحَنّا","I eagerly long for you who inspires love and deep affection, and the faithful men and women take delight in your memorable glory. So we are excited with a longing desire."],["بِنَفْسي اَنْتَ مِنْ عَقيدِ عِزٍّ لايُسامى","I eagerly long for you who is worthy of acceptance and lawful driving force of belief and conviction, never weary or annoyed."],["بِنَفْسي اَنْتَ مِنْ اَثيلِ مَجْدٍ لا يُجارى","I eagerly long for you who is the root of praise and distinction, never can be uprooted."],["بِنَفْسي اَنْتَ مِنْ تِلادِ نِعَمٍ لا تُضاهى","I eagerly long for you who is always tender, gentle and comforting, never makes one’s affairs worse instead of better."],["بِنَفْسي اَنْتَ مِنْ نَصيفِ شَرَفٍ لا يُساوى","I eagerly long for you who is just and equitable beyond a trace of doubt, does not take severe action until misbehaviour trespasses the limit."],["اِلى مَتى اَحارُ فيكَ يا مَوْلايَ وَ اِلى مَتي ، وَ اَىَّ خِطابٍ اَصِفُ فيكَ وَ اَيَّ نَجْوى","O Master! How long and unto what is to be directed (my) request for friendly attention concerning you? And what is the message?"],["عَزيزٌ عَلَيَّ اَنْ اُجابَ دُونَكَ وَ اُناغى","It makes me sad to get favourable reply from anyone other than you, but to be duped and cheated in the end."],["عَزيزٌ عَلَيَّ اَنْ اَبْكِيَكَ وَ يَخْذُلَكَ الْوَرى","It casts a gloom upon me that you suffered hardships and the chicken hearted deserters left you alone."],["عَزيزٌ عَلَيَّ اَنْ يَجْرِيَ عَلَيْكَ دُونَهُمْ ما جَرى","It is painful for me what took place for you from them and that which had happened."],["هَلْ مِنْ مُعينٍ فَاُطيلَ مَعَهُ الْعَويلَ وَ الْبُكاءَ","Is there a helper with whom I may cooperate and take pains?"],["هَلْ مِنْ جَزُوعٍ فَاُساعِدَ جَزَعَهُ اِذا خَلا","Is there a restless with whom I may share when action is taken?"],["هَلْ قَذِيَتْ عَيْنٌ فَساعَدَتْها عَيْني عَلَى الْقَذى","Is there a faint twinkle of evidence to make me willingly take up the trouble?"],["هَلْ اِلَيْكَ يَا بْنَ اَحْمَدَ سَبيلٌ فَتُلْقى","Do you O Son of Ahmed have means and ways to arrange our meeting?"],["هَلْ يَتَّصِلُ يَوْمُنا مِنْكَ بِعِدَةٍ فَنَحْظى","Can you once cleverly guide the course of time, so that we may obtain our wish?"],["مَتى نَرِدُ مَناهِلَكَ الرَّوِيَّةَ فَنَرْوى","When shall we abridge the gap that separate us from the vision so that we may refer to the authority?"],["مَتى نَنْتَقِعُ مِنْ عَذْبِ مائِكَ فَقَدْ طالَ الصَّدى","How long shall we keep waiting for your pleasing satisfying essence and quality?"],["مَتى نُغاديكَ وَ نُراوِحُكَ فَنُقِرَّ عَيْناً ( فَتَقُرُ عًُيًُوننا )","Already the period of expectation has lasted too long! When shall we receive our share from you and have our minds set at rest?"],["مَتى تَرانا وَ نَراكَ وَ قَدْ نَشَرْتَ لِواءَ النَّصْرِ تُرى","For we have fixed our eyes upon you and strive with perseverance. When shall we be happy, and see your beautiful form and fine aspect?"],["اَتَرانا نَحُفُّ بِكَ وَ اَنْتَ تَاُمُّ الْمَلاََ وَ","Groups of cheerful willing disciplined helpers, in great numbers, gathering around you to carry out one work after the other! You fulfilling (every promise) and giving joy, heart and confidence (to the faithfuls);"],["قَدْ مَلأْتَ الاَْرْضَ عَدْلاً وَ اَذَقْتَ اَعْداءَكَ هَواناً وَ عِقاباً","filling the earth with justice; making your enemies follow the law and accept the revolution;"],["وَ اَبَرْتَ الْعُتاةَ وَ جَحَدَةَ الْحَقِّ","taking the wind out of the haughty and the boastful, and those who knew but denied the truth;"],["وَ قَطَعْتَ دابِرَ الْمُتَكَبِّرينَ ، وَ اجْتَثَثْتَ اُصُولَ الظّالِمينَ","breaking the back of the proud and the arrogant; uprooting the roots of the unjust;"],["وَ نَحْنُ نَقُولُ الْحَمْدُ للهِ رَبِّ الْعالَمينَ","and we-singing the praise of Allah, the Lord of the worlds."],["اَللّـهُمَّ اَنْتَ كَشّافُ ْالكُرَبِ وَ الْبَلْوى ، وَ اِلَيْكَ اَسْتَعْدى فَعِنْدَكَ الْعَدْوى","O my Allah! Thou disperses the clouds of sorrows and hardships. Unto Thee we turn to ask for help against the enemy; for Thou (alone) helps and guides."],["وَ اَنْتَ رَبُّ الاْخِرَةِ وَ الدُّنْيا ( الاُولي ) ، فَاَغِثْ يا غِياثَ الْمُسْتَغيثينَ عُبَيْدَكَ الْمُبْتَلى","Thou (alone) puts into good order affairs of this world and shall make better the Hereafter. So come to help! O He Who is called to help the helpless, Thy servants, surrounded by calamities."],["وَ اَرِهِ سَيِّدَهُ يا شَديدَ الْقُوى ، وَ اَزِلْ عَنْهُ بِهِ الاَْسى وَ الْجَوى","Show them the face of their Leader. O the Mightiest Almighty. Allow him to put an end to evil and corruption,"],["وَ بَرِّدْ غَليلَهُ يا مَنْ عَلَى الْعَرْشِ اسْتَوى ، وَ مَنْ اِلَيْهِ الرُّجْعى وَ الْمُنْتَهى","and satisfy his Love (for the faithfuls) and dislike (for the sinners). O He Who, from the \"Arsh directs and controls all creation, and unto Him is the return, final and ultimate."],["اَللّـهُمَّ وَ نَحْنُ عَبيدُكَ التّائِقُونَ ( الشائقون ) اِلى وَلِيِّكَ الْمُذَكِّرِ بِكَ وَ بِنَبِيِّكَ","O my Allah! We are Thy servants, longing for Thy friend (appointed authority), who reminds us of Thee, and Thy Prophet,"],["وَ اَقَمْتَهُ لَنا قِواماً وَ مَعاذاً ، وَ جَعَلْتَهُ لِلْمُؤْمِنينَ مِنّا اِماماً","who was created as a refuge and asylum for us, established as a foundation and spring of truthfulness for us, and was made the Leader-Guide of the faithfuls."],["فَبَلِّغْهُ مِنّا تَحِيَّةً وَ سَلاماً ، وَ زِدْنا بِذلِكَ يارَبِّ اِكْراماً","Convey to him our heartfelt congratulations and welcome. Make us feel more deeply for him."],["وَ اجْعَلْ مُسْتَقَرَّهُ لَنا مُسْتَقَرّاً وَ مُقاماً ، وَ اَتْمِمْ نِعْمَتَكَ بِتَقْديمِكَ اِيّاهُ اَمامَنا","O Lord! Very Kindly, make his headquarters our place of domicile and dwelling abode, and fulfill Thy promise by returning him to us as our Leader Guide, so that he takes us to the eternal land of peace and bliss,"],["حَتّى تُورِدَنا جِنانَكَ ( جَنّاتِكَ ) وَ مُرافَقَةَ الشُّهَداءِ مِنْ خُلَصائِكَ","where we shall rub elbows with Thy sincere servants who shed blood to pronounce the Faith."],["اَللّـهُمَّ صَلِّ عَلى مُحَمَّدٍ وَ آلِ مُحَمَّدٍ","O Allah send Thy blessings on Muhammad and on the children of Muhammad."],["وَ صَلِّ عَلى مُحَمَّدٍ جَدِّهِ وَ رَسُولِكَ السَّيِّدِ الاَكْبَرِ ، وَ عَلى اَبيهِ السَّيِّدِ الاَصْغَرِ","Bless his ancestor Muhammad, the Messenger, the foremost Leader, and bless his progenitor, the succeeding Leader,"],["وَ جَدَّتِهِ الصِّدّيقَةِ الْكُبْرى فاطِمَةَ بِنْتِ مُحَمَّدٍ صَلَّى اللهُ عَلَيْهِ وَ آلِهِ ، وَ عَلى مَنِ اصْطَفَيْتَ مِنْ آبائِهِ الْبَرَرَةِ","and his great grandmother, the ever truthful, Faatimah daughter of Muhammad, and his chosen virtuous forefathers, and send blessings on him,"],["وَ عَلَيْهِ اَفْضَلَ وَ اَكْمَلَ وَ اَتَمَّ وَ اَدْوَمَ وَ اَكْثَرَ وَ اَوْفَرَ","superior, whole, conclusive, staying, numerous, and full,"],["ما صَلَّيْتَ عَلى اَحَدٍ مِنْ اَصْفِيائِكَ وَ خِيَرَتِكَ مِنْ خَلْقِكَ","not ever bestowed (even) on any of Thy sincerely attached and pious friends from among Thy creation."],["وَ صَلِّ عَلَيْهِ صَلاةً لا غايَةَ لِعَدَدِها وَ لا نِهايَةَ لِمَدَدِها وَ لا نَفادَ لاَِمَدِها","Bless him with blessings, (that) cannot be counted in numbers, cannot be \"proximated\" in space of time, cannot be consumed in terms of having nothing remaining."],["اَللّـهُمَّ وَ اَقِمْ بِهِ الْحَقَّ وَ اَدْحِضْ بِهِ الْباطِلَ وَ اَدِلْ بِهِ اَوْلِياءَكَ وَ اَذْلِلْ بِهِ اَعْداءَكَ","Let us be friends with his ancestors. Give us courage to disperse those who oppose and try to prevent him, and make them stay in their shame and disgrace for ever."],["وَ صِلِ اللّهُمَّ بَيْنَنا وَ بَيْنَهُ وُصْلَةً تُؤَدّى اِلى مُرافَقَةِ سَلَفِهِ","Help us to discharge the duties made incumbent upon us by him, and make every effort to obey him,"],["وَ اجْعَلْنا مِمَّنْ يَأخُذُ بِحُجْزَتِهِمْ ، وَ يَمْكُثُ في ظِلِّهِمْ","keep from that which is declared unlawful by him, rely upon him to get his approval."],["وَ اَعِنّا عَلى تَأدِيَةِ حُقُوقِهِ اِلَيْهِ ، وَ الاْجْتِهادِ في طاعَتِهِ ، وَ اجْتِنابِ مَعْصِيَتِهِ","Help us to discharge the duties made incumbent upon us by him, and make every effort to obey him, keep from that which is declared unlawful by him, rely upon him to get his approval."],["وَ امْنُنْ عَلَيْنا بِرِضاهُ ، وَهَبْ لَنا رَأَفَتَهُ وَ رَحْمَتَهُ وَ دُعاءَهُ وَ خَيْرَهُ","Let us be with him when he makes peace, and frees mankind from fear, gives currency to love are kindness, brings bliss and happiness, spreads good and virtue,"],["مانَنالُ بِهِ سَعَةً مِنْ رَحْمَتِكَ وَ فَوْزاً عِنْدَكَ","so that we may do our best to promote his cause through Thy mercy, and win victory for Thee."],["وَ اجْعَلْ صَلاتَنا بِهِ مَقبُولَةً ، وَ ذُنُوبَنا بِهِ مَغْفُورَةً ، وَ دُعاءَنا بِهِ مُسْتَجاباً","Accept our prayers, forgive our sins, fulfil our desires,"],["اَرْزاقَنا بِهِ مَبْسُوطَةً ، وَ هُمُومَنا بِهِ مَكْفِيَّةً ، وَ حَوآئِجَنا بِهِ مَقْضِيَّةً","give us means of livelihood, unrestricted, make less our hardships, meet our demands in full (through him)."],["وَ اَقْبِلْ اِلَيْنا بِوَجْهِكَ الْكَريمِ وَ اقْبَلْ تَقَرُّبَنا اِلَيْكَ","Turn towards us Thy kindness and loving aspects, and bring us close to Thee."],["وَ انْظُرْ اِلَيْنا نَظْرَةً رَحيمَةً نَسْتَكْمِلُ بِهَا الْكَرامَةَ عِنْدَكَ ، ثُمَّ لا تَصْرِفْها عَنّا بِجُودِكَ","Turn the eyes of Thy mercy upon us, to bring to fullness Thy kind favours, and after that do not ever let them disappear in the name of Thy generosity,"],["وَ اسْقِنا مِنْ حَوْضِ جَدِّهِ صَلَّى اللهُ عَلَيْهِ وَ آلِهِ بِكَأسِهِ وَ بِيَدِهِ","and give us the opportunity to quench our thirst from the spring of his great grandfather (Kawsar), (blessing of Allah be on him and on his children),"],["رَيّاً رَوِيّاً هَنيئاً سائِغاً لا ظَمَاَ بَعْدَهُ يا اَرْحَمَ الرّاحِمين","using his cup, filled by him, fresh and pure, sufficient, wholesome, clear and cool, not leaving any desire thereafter, O the Most Merciful."]]},{"id":"dua-sabah","cat":"Duʿāʾ","t":{"en":"Duʿāʾ al-Ṣabāḥ","ar":"دعاء الصباح"},"lines":[["بِسْمِ اللهِ الرَّحْمنِ الرَّحِيمِِ","In the Name of Allah, the Beneficent, the Merciful."],["أَللَّهُمَّ صَلِّ عَلى مُحَمَّدٍ وَّ آلِ مُحَمَّد","O Allah! Bless Muhammad and his progeny."],["اَللّـهُمَّ يا مَنْ دَلَعَ لِسانَ الصَّباحِ بِنُطْقِ تَبَلُّجِهِ","Oh God, Oh He who extended the morning's tongue in the speech of its dawning"],["وَ سَرَّحَ قِطَعَ الّلَيْلِ الْمُظْلِمِ بِغَياهِبِ تَلَجْلُجِهِ","And dispatched the fragments of the dark night into the gloom of its stammering"],["وَ اَتْقَنَ صُنْعَ الْفَلَكِ الدَّوّارِ في مَقاديرِ تَبَرُّجِهِ","And made firm the structure of the turning spheres in the measures of its display"],["وَ شَعْشَعَ ضِياءَ الشَّمْسِ بِنُورِ تَاَجُّجِهِ","And beamed forth the brightness of the sun through the light of its blazing!"],["يا مَنْ دَلَّ عَلى ذاتِهِ بِذاتِهِ","Oh He who demonstrates His Essence by His Essence"],["وَ تَنَزَّهَ عَنْ مُجانَسَةِ مَخْلُوقاتِهِ","And transcends congeneity with His creatures"],["وَ جَلَّ عَنْ مُلاءَمَةِ كَيْفِيّاتِهِ","And is exalted beyond conformity with His qualities!"],["يا مَنْ قَرُبَ مِنْ خَطَراتِ الظُّنُونِ","Oh He who is near to the passing thoughts of opinions"],["وَ بَعُدَ عَنْ لَحَظاتِ الْعُيُونِ","And far from the regards of eyes"],["وَ عَلِمَ بِما كانَ قَبْلَ اَنْ يَكُونَ","And knows what will be before it comes to be!"],["يا مَنْ اَرْقَدَني في مِهادِ اَمْنِهِ وَ اَمانِهِ","Oh He who has put me at ease in the cradle of His security and sanctuary"],["وَ اَيْقَظَني إلى ما مَنَحَني بِهِ مِنْ مِنَنِهِ وَ اِحْسانِهِ","And awakened me to the favors and kindness that He has bestowed upon me"],["وَ كَفَّ اَكُفَّ السُّوءِ عَنّي بِيَدِهِ وَ سُلْطانِهِ","And held me from the claws of evil with His hand and His force!"],["صَلِّ اللّـهُمَّ عَلَى الدَّليلِ اِلَيْكَ فِي اللَّيْلِ الأَلْيَلِ","Bless, oh God, the guide to Thee in the darkest night"],["وَ الْماسِكِ مِنْ اَسْبَابِكَ بِحَبْلِ الشَّرَفِ الأَطْوَلِ","And him who, of Thy ropes, clings to the cord of the longest nobility"],["وَ النّاصِعِ الْحَسَبِ في ذِرْوَةِ الْكاهِلِ الأَعْبَلِ","And him whose glory is evident at the summit of stout shoulders"],["وَ الثّابِتِ الْقَدَمِ عَلى زَحاليفِها فِي الزَّمَنِ الأَوَّلِ","And whose feet were entrenched in spite of slippery places in ancient time"],["وَ عَلى آلِهِ الأَخْيارِ الْمُصْطَفِيْنَ الأَبْرارِ","And [bless] his household, the good, the chosen, the pious"],["وَ افْتَحِ اللّـهُمَّ لَنا مَصاريعَ الصَّباحِ","And open for us, oh God, the leaves of morning's door"],["بِمَفاتيحِ الرَّحْمَةِ وَ الْفَلاحِ","With the keys of mercy and prosperity!"],["وَ اَلْبِسْنِي اللّـهُمَّ مِنْ اَفْضَلِ خِلَعِ الْهِدايَةِ وَ الصَّلاحِ","And clothe me, oh God, with the most excellent robes of guidance and righteousness!"],["وَ اَغْرِسِ اللّـهُمَّ بِعَظَمَتِكَ في شِرْبِ جَناني يَنابيعَ الخُشُوعِ","And plant, oh God, through Thy tremendousness, the springs of humility in the watering place of my heart!"],["وَ اَجْرِ اللّـهُمَّ لِهَيْبَتِكَ مِنْ آماقي زَفَراتِ الدُّمُوعِ","And cause to flow, oh God, because of Thy awesomeness, tears of moaning from the corner of my eyes!"],["وَ أَدِّبِ اللّـهُمَّ نَزَقَ الْخُرْقِ مِنّي بِاَزِمَّةِ الْقُنُوعِ","And chastise, oh God, the recklessness of my clumsiness with the reins of contentment!"],["اِلـهي اِنْ لَمْ تَبْتَدِئنِي الرَّحْمَةُ مِنْكَ بِحُسْنِ التَّوْفيقِ","My God, if mercy from Thee does not begin with fair success for me"],["فَمَنِ السّالِكُ بي اِلَيْكَ في واضِحِ الطَّريقِ","Then who can take me to Thee upon the evident path?"],["وَ اِنْ اَسْلَمَتْني اَناتُكَ لِقائِدِ الأَمَلِ وَالْمُنى","If Thy deligerateness would turn me over to the guide of hope and wishes"],["فَمَنِ الْمُقيلُ عَثَراتي مِنْ كَبَواتِ الْهَوى","Then who will annul my slips from the stumbles of caprice?"],["وَ اِنْ خَذَلَني نَصْرُكَ عِنْدَ مُحارَبَةِ النَّفْسِ وَ الشَّيْطانِ","If Thy help should forsake me in the battle with the soul and Satan"],["فَقَدْ وَكَلَني خِذْلانُكَ إلى حَيْثُ النَّصَبُ وَ الْحِرْمانُ","Then Thy forsaking will have entrusted me to where there is hardship and deprivation"],["اِلـهي اَتَراني ما اَتَيْتُكَ إلاّ مِنْ حَيْثُ الآمالِ","My God, dost Thou see that I have only come to Thee from the direction of hopes"],["عَلِقْتُ بِاَطْرافِ حِبالِكَ إلاّ حينَ باعَدَتْني ذُنُوبي عَنْ دارِ الْوِصالِ","Or clung to the ends of Thy cords when my sins have driven me from the house of union?"],["فَبِئْسَ الْمَطِيَّةُ الَّتي امْتَطَتْ نَفْسي مِنْ هَواهـا","So what an evil mount upon which my soul has mounted - its caprice!"],["فَواهاً لَها لِما سَوَّلَتْ لَها ظُنُونُها وَ مُناها","Woe upon it for being seduced by its own opinions and wishes!"],["وَ تَبّاً لَها لِجُرْاَتِها عَلى سَيِّدِها وَ مَوْلاها","And destruction be upon it for its audacity toward its Master and Protector!"],["اِلـهي قَرَعْتُ بابَ رَحْمَتِكَ بِيَدِ رَجائي","My God, I have knocked upon the door of Thy mercy with the hand of my hope"],["وَ هَرَبْتُ اِلَيْكَ لاجِئاً مِنْ فَرْطِ اَهْوائي","And fled to Thee seeking refuge from my excessive caprice"],["وَ عَلَّقْتُ بِاَطْرافِ حِبالِكَ اَنامِلَ وَلائي","And fixed the fingers of my love to the ends of Thy cords"],["فَاْصْفَحِ اللّـهُمَّ عَمّا كُنْتُ اَجْرَمْتُهُ مِنْ زَلَلي وَ خَطائي","So pardon, oh God, the slips and errors I have committed"],["وَ اَقِلْني مِنْ صَرْعَةِ رِدائي","And release me from the foot-tangling of my robe"],["فَاِنَّكَ سَيِّدي وَ مَوْلاي وَ مُعْتَمَدي وَ رَجائي","For Thou art my Master, my Protector, my Support and my Hope"],["وَ اَنْتَ غايَةُ مَطْلُوبي وَ مُناي في مُنْقَلَبي وَ مَثْواىَ","And Thou art the object of my search and my desire in my ultimate end and stable abode"],["اِلـهي كَيْفَ تَطْرُدُ مِسْكيناً الْتَجَأَ اِلَيْكَ مِنَ الذُّنُوبِ هارِباً","My God, how couldst Thou drive away a poor beggar who seeks refuge in Thee from sins, fleeing?"],["اَمْ كَيْفَ تُخَيِّبُ مُسْتَرْشِداً قَصَدَ إلى جَنابِكَ ساعِياً","Or how couldst Thou disappoint one seeking guidance who repairs to Thy threshold, running?"],["اَمْ كَيْفَ تَرُدُّ ظَمآناً وَرَدَ إلى حِياضِكَ شارِباً","Or how could You reject a thirsty man who comes to Your wells to drink?"],["كَلاّ وَحِياضُكَ مُتْرَعَةٌ في ضَنْكِ الُْمُحُولِ","Never! For Thy pools are full in the hardship of drought"],["وَ بابُكَ مَفْتُوحٌ لِلطَّلَبِ وَ الْوُغُولِ","Thy door is open for seeking and penetration"],["وَ اَنْتَ غايَةُ الْمَسْؤولِ وَ نِهايَةُ الْمَأمُولِ","And Thou art the goal of requests and the object of hopes"],["اِلـهي هذِهِ اَزِمَّةُ نَفْسي عَقَلْتُها بِعِقالِ مَشِيَّتِكَ","My God, these are the reins of my soul I have bound them with the ties of Thy will"],["وَ هذِهِ اَعْباءُ ذُنُوبي دَرَأتُها بِعَفْوِكَ وَ رَحْمَتِكَ","These are the burdens of my sins I have averted them with Thy pardon and mercy"],["وَ هذِهِ اَهْوائِي الْمُضِلَّةُ وَكَلْتُها إلى جَنابِ لُطْفِكَ وَ رَأفَتِكَ","these are my caprices that lead astray - I have entrusted them to the threshold of Thy gentleness and kindliness"],["فَاجْعَلِ اللّـهُمَّ صَباحي هذا ناِزلاً عَلَي بِضِياءِ الْهُدى","So make this morning of mine, oh God, descend upon me with the radiance of guidance"],["وَ بِالسَّلامَة فِي الدّينِ وَ الدُّنْيا","and with safety in religion and this world!"],["وَ مَسائي جُنَّةً مِنْ كَيْدِ الْعِدى","And [make] my evening a shield against the deception of enemies"],["وَ وِقايَهً مِنْ مُرْدِياتِ الْهَوى","And a protection against the destructive blows of caprice!"],["اِنَكَ قادِرٌ عَلى ما تَشاءُ","Thou art able over what Thou wilt!"],["تُؤتِي الْمُلْكَ مَنْ تَشاءُ ، وَ تَنْزِعُ الْمُلْكَ مِمَّنْ تَشاءُ","Thou givest the kingdom to whom Thou wilt, and Thou seizest the kingdom from whom Thou wilt"],["وَ تُعِزُّ مَنْ تَشاءُ ، وَ تُذِلُّ مَنْ تَشاءُ","Thou exaltest whom Thou wilt, and Thou abasest whom Thou wilt"],["بِيَدِكَ الْخَيْرُ اِنَّـكَ عَلى كُلِّ شَيْء قَديرٌ","In Thy hand is the good, Thou art powerful over all things"],["تُولِجُ اللَيْلَ في النَّهارِ ، وَ تُولِجُ النَّهارَ فِي اللَّيْلِ","Thou makest the night to enter into the day, and Thou makest the day to enter into the night"],["وَ تُخْرِجُ الْحَيَّ مِنَ الْمَيِّتِ ، وَ تُخْرِجُ الْمَيِّتَ مِنَ الْحَي","Thou bringest forth the living from the dead, and Thou bringest forth dead from the living"],["وَ تَرْزُقُ مَنْ تَشاءُ بِغَيْرِ حِساب","and Thou providest whomsoever Thou wilt without reckoning"],["لا اِلـهَ إلاّ اَنْتَ سُبْحانَكَ اللّـهُمَّ وَ بِحَمْدِكَ","There is no god but Thou! Glory be to Thee, oh God, and Thine is the praise!"],["مَنْ ذا يَعْرِفُ قَدْرَكَ فَلا يَخافُكَ","Who knows Thy measure without fearing Thee?"],["وَ مَن ذا يَعْلَمُ ما اَنْتَ فَلا يَهابُكَ","Who knows what Thou art without awe of Thee?"],["اَلَّفْتَ بِقُدْرَتِكَ الْفِرَقَ","Through Thy power Thou hast joined disparate things"],["وَ فَلَقْتَ بِلُطْفِكَ الْفَلَقَ","And through Thy gentleness Thou hast cleaved apart the daybreak"],["وَ اَنَرْتَ بِكَرَمِكَ دَياجِي الْغَسَقِ","And through Thy generosity Thou hast illumined the dark shrouds of night"],["وَ اَنْهَرْتَ الْمِياهَ مِنَ الصُّمِّ الصَّياخيدِ عَذْباً وَ اُجاجاً","Thou hast made waters, sweet and salt, flow forth from hard shining stones"],["وَ اَنْزَلْتَ مِنَ الْمُعْصِراتِ ماءً ثَجّاجاً","And sent down out of rain-clouds water cascading"],["وَ جَعَلْتَ الشَّمْسَ وَ الْقَمَرَ لِلْبَرِيَّةِ سِراجاً وَهّاجاً","And appointed the sun and moon a blazing lamp for the creatures"],["مِنْ غَيْرِ اَنْ تُمارِسَ فيما ابْتَدَأتَ بِهِ لُغُوباً وَ لا عِلاجاً","Without experiencing in that which Thou originated either weariness or effort"],["فَيا مَنْ تَوَحَّدَ بِالْعِزِّ وَ الْبَقاءِ","So, oh He who is alone in might and subsistence"],["قَهَرَ عِبادَهُ بِالْمَوْتِ وَ الْفَناءِ","And dominates His slaves with death and annihilation"],["صَلِّ عَلى مُحَمَّد وَ آلِهِ الاَْتْقِياءِ","Bless Muhammad and his household, the godfearing"],["وَ اسْمَعْ نِدائي ، وَ اسْتَجِبْ دُعائي","And answer my supplication hear my call"],["وَ حَقِّقْ بِفَضْلِكَ اَمَلي وَ رَجائي","And actualize through Thy bounty my hope and desire"],["يا خَيْرَ مَنْ دُعِي لِكَشْفِ الضُّرِّ","Oh best of those who is called to remove affliction"],["وَ الْمَأمُولِ لِكُلِّ عُسْر وَ يُسْر","And object of hope in every difficulty and ease!"],["بِكَ اَنْزَلْتُ حاجَتي فَلا تَرُدَّني مِنْ سَنِيِّ مَواهِبِكَ خائِباً","I have stated my need, so do not reject me, oh my master, despairing of Thy exalted gifts"],["يا كَريمُ ، يا كَريمُ ، يا كَريمُ","Oh All-generous! Oh All-generous! Oh All-generous!"],["بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ","By Thy mercy, oh Most Merciful of the merciful!"],["وَ صَلَّى اللهُ عَلى خَيْرِ خَلْقِهِ مُحَمَّد وَ آلِهِ اَجْمَعينَ","And God bless the best of His creatures, Muhammad, and all his household!"],["ثمّ اسجد و قل : اِلـهي قَلْبي مَحْجُوبٌ","Then prostrate and say: My God, my heart is veiled"],["وَ نَفْسي مَعْيُوبٌ","My soul is deficient"],["وَ عَقْلي مَغْلُوبٌ","My intelligence is defeated"],["وَ هَوائي غالِبٌ","My caprice is triumphant"],["وَ طاعَتي قَليلٌ","My obedience is little"],["وَ مَعْصِيَتي كَثيرٌ","My disobedience is much"],["وَ لِساني مُقِرٌّ بِالذُّنُوبِ","And my tongue acknowledges sins"],["فَكَيْفَ حيلَتي يا سَتّارَ الْعُيُوبِ","So what am I to do? Oh He who covers defects!"],["وَ يا عَلاّمَ الْغُيُوبِ","Oh He who knows the unseen things!"],["وَ يا كاشِفَ الْكُرُوبِ","Oh He who removes troubles"],["اِغْفِرْ ذُنُوبي كُلَّها بِحُرْمَةِ مُحَمَّد وَ آلِ مُحَمَّد","Forgive my sins, all of them, by the sacredness of Muhammad and the household of Muhammad!"],["يا غَفّارُ ، يا غَفّارُ ، يا غَفّارُ","Oh All-forgiver! Oh All-forgiver! Oh All-forgiver!"],["بِرَحْمَتِكَ يا اَرْحَمَ الرّاحِمينَ","By Thy mercy, oh Most Merciful of the mercifull!"]]},{"id":"dua-simaat","cat":"Duʿāʾ","t":{"en":"Duʿāʾ al-Simāt","ar":"دعاء السمات"},"lines":[["بِسْمِ اللهِ الرَّحْمنِ الرَّحيمِ","O Allah, I beseech Thee with Thy Name;"],["اَللّـهُمَّ اِنّى اَسْأَلُكَ بِاسْمِكَ الْعَظيمِ الاَْعْظَمِ","Allah! I beseech Thee through Thy Name, the most great,"],["الاَْعَزِّ الاَْجَلِّ الاَْكْرَمِ الَّذى اِذا دُعيتَ بِهِ","the most majestic, the most magnificent and the most noble. If Thou art requested therewith"],["عَلى مَغالِقِ اَبْوابِ السَّمآءِ لِلْفَتْحِ بِالرَّحْمَةِ انْفَتَحَتْ","to open the closed doors of the sky these will open with Thy mercy."],["وَاِذا دُعيتَ بِهِ عَلى مَضآئِقِ اَبْوابِ الاَْرْضِ لِلْفَرَجِ انْفَرَجَتْ","If Thou art requested thereby to remove the narrowness of the doors of the heaven, they will be opened wide."],["وَاِذا دُعيتَ بِهِ عَلَى العُسْرِ لِلْيُسْرِ تَيَسَّرَتْ","If Thou art requested thereby to make easy the difficulty, it will be easy."],["وَاِذا دُعيتَ بِهِ عَلَى الاَْمْواتِ لِلنُّشُورِ انْتَشَرَتْ","If Thou art requested thereby to restore the dead to life, they will wise from their graves."],["وَاِذا دُعيتَ بِهِ عَلى كَشْفِ الْبَأسآءِ وَالضَّرّاءِ انْكَشَفَتْ","If Thou art requested thereby to remove misery and adversity, they will be removed."],["وَبِجَلالِ وَجْهِكَ الْكَريمِ اَكْرَمِ الْوُجُوهِ وَاَعَزِّ الْوُجُوهِ","I beseech Thee through the Majesty of Thy person, the Most Generous and the Most Honoured One,"],["الَّذى عَنَتْ لَهُ الْوُجُوهُ وَخَضَعَتْ لَهُ الرِّقابُ","before Whom everybody bows down in submission and all necks bend down in reverence"],["وَخَشَعَتْ لَهُ الاَْصْواتُ وَوَجِلَتْ لَهُ الْقُلُوبُ مِنْ مَخافَتِكَ","and through fear of Whom all voices become humbled and all hearts tremble;"],["وَبِقُوَّتِكَ الَّتى بِها تُمْسِكُ السَّمآءَ اَنْ تَقَعَ عَلَى الاَْرْضِ إلاّ بِاِذْنِكَ","and I beseech Thee through Thy Might, which prevents the sky from falling on the earth except with Thy permission,"],["وَتُمْسِكُ السَّماواتِ وَالاَْرْضَ اَنْ تَزُولا","and which controls all the heavens and the earth so closely"],["وَبِمَشِيَّتِكَ الَّتى دانَ (كانَ) لَهَا الْعالَمُونَ","that they cannot move away from their positions; and I beseech Thee through they Will, which the whole world obeys,"],["وَبِكَلِمَتِكَ الَّتى خَلَقْتَ بِهَا السَّماواتِ وَالاَْرْضَ","and through Thy Word. By which Thou hath created the heaven and the earth,"],["وَبِحِكْمَتِكَ الَّتى صَنَعْتَ بِهَا الْعَجآئِبَ وَخَلَقْتَ بِهَا الظُّلْمَةَ","and through Thy Wisdom, with which Thou hath created wonderful, and with which Thou created Darkness"],["وَجَعَلْتَها لَيْلاً وَجَعَلْتَ اللَّيْلَ سَكَناً (مَسْكَناً) وَخَلَقْتَ بِهَا النُّورَ","and made it Night, and made night the time of quiet and rest; and with which Thou created Light"],["وَجَعَلْتَهُ نَهاراً وَجَعَلْتَ النَّهارَ نُشُوراً مُبْصِراً","and made it Day, and made day the time of movement and observation;"],["وَخَلَقْتَ بِهَا الشَّمْسَ وَجَعَلْتَ الشَّمْسَ ضِيآءً","and with which Thou hath created the Sun, and made the sun of light."],["وَخَلَقْتَ بِهَا الْقَمَرَ وَجَعَلْتَ الْقَمَرَ نُوراً","And with which Thou hath created the Moon, and made the moon of light;"],["وَخَلَقْتَ بِهَا الْكَواكِبَ وَجَعَلْتَها نُجُوماً وَبُرُوجاً وَمَصابيحَ وَزينَةً وَرُجُوماً","and with which Thou hath created heavenly bodies, and made them fixed stars and planets, and lamps for guidance at night, and as a means of decoration, and missiles for driving away the devils,"],["وَجَعَلْتَ لَها مَشارِقَ وَمَغارِبَ وَجَعَلْتَ لَها مَطالِعَ وَمَجارِىَ","and hath created for them east and west, and hath created for them the places of ascendancy and orbits,"],["وَجَعَلْتَ لَها فَلَكاً وَمَسابِـحَ وَقَدَّرْتَها فِى السَّمآءِ مَنازِلَ فَاَحْسَنْتَ تَقْديرَها","and created for them a firmament and sphere, and fixed for them stages in the heaven"],["وَصَوَّرْتَها فَاَحْسَنْتَ تَصْويرَها وَاَحْصَيْتَها بِاَسْمآئِكَ اِحْصآءً","and how beautiful the stages - and shaped the stars - and how beautiful the shapes - and made them stable through Thy Name;"],["وَدَبَّرْتَها بِحِكْمَتِكَ تَدْبيراً فأحْسَنْتَ تَدْبيرَها","and Thy Wisdom Thou designed a system for them - and what a good system,"],["وَسَخَّرْتَها بِسُلْطانِ اللَّيْلِ وَسُلْطانِ النَّهارِ وَالسّاعاتِ وَعَدَدَ السِّنينَ وَالْحِسابِ","and controlled the heavenly bodies through the king of the night and the king of day, and through hours, making them a means for the reckoning of years and counting,"],["وَجَعَلْتَ رُؤْيَتَها لِجَميعِ النّاسِ مَرْئً واحِداً","making appearance of heavenly bodies regular and universal."],["وَاَسْأَلُكَ اللّهُمَّ بِمَجْدِكَ الَّذى كَلَّمْتَ بِهِ عَبْدَكَ وَرَسُولَكَ مُوسَى بْنَ عِمْرانَ عَلَيْهِ السَّلامُ","And I beseech Thee, O Allah, through Thy Glory, with which Thou addressed Thy slave and Thy Messenger, Moses son of 'Imran peace be on him,"],["فِى الْمُقَدَّسينَ فَوْقَ اِحْساسِ الْكَرُّوبينَ (الْكَرُّوبِيّينَ)","while he was in the company of angels - which address even the favourite cherubin could not ever hear,"],["فَوْقَ غَمآئِمِ النُّورِ فَوْقَ تابُوتِ الشَّهادَةِ فى عَمُودِ النّارِ","above the clouds of light, above the box of evidence, with in the pillar of fire"],["وَفى (وَاِلى) طُورِ سَيْنآءَ وَفى جَبَلِ حُوريثَ فِى الْوادِ الْمُقَدَّسِ فِى الْبُقْعَةِ الْمُبارَكَةِ","on Mount Sinai, and on Mount Hurith in the Holy Vale in the sacred tract of land"],["مِنْ جانِبِ الطُّورِ الاَْيْمَنِ مِنَ الشَّجَرَةِ وَفى اَرْضِ مِصْرَ بِتِسْعِ ايات بَيِّنات","to the right of Taurus Mountain-through a tree; and again addressed him on the soil of Egypt, after showing nine clear signs"],["وَيَوْمَ فَرَقْتَ لِبَنى اِسْرآئيلَ الْبَحْرَ وَفِى الْمُنْبَجِساتِ الَّتى صَنَعْتَ بِهَا الْعَجآئِبَ فى بَحْرِ سُوف","and on the day Thou split the sea for the Children of Israel, and caused springs to flow from a stone, thereby displaying wonders of Thy might in a deep sea;"],["وَعَقَدْتَ مآءَ الْبَحْرِ فى قَلْبِ الْغَمْرِ كَالْحِجارَةِ","and on the day when Thou solidified the water of the sea in the midst of the storm,"],["وَجاوَزْتَ بِبَنى اِسْرائيلَ الْبَحْرَ وَتَمَّتْ كَلِمَتُكَ الْحُسْنى عَلَيْهِمْ بِما صَبَرُوا","and caused the Children of Israel to pass by it, and fulfilled Thy excellent promises made to them"],["وَاَوْرَثْتَهُمْ مَشارِقَ الاَْرْضِ وَمَغارِبَهَا الَّتى بارَكْتَ فيها لِلْعالَمينَ","because of their calmly endurance, and made them the master of the East and the West in the earth, wherein there are blessings for all the worlds;"],["وَاَغْرَقْتَ فِرْعَوْنَ وَجُنُودَهُ وَمَراكِبَهُ فِى الْيَمِّ","and Thou drowned Pharaoh and his armies and boats in the water."],["و بِاسْمِكَ الْعَظيمِ الاَْعْظَمِ الاَْعَزِّ الاَْجَلِّ الاَْكْرَمِ","And (I beseech Thee) through Thy name, which is the most great, the most majestic, and the most holy;"],["وَبِمَجْدِكَ الَّذى تَجَلَّيْتَ بِهِ لِمُوسى كَليمِكَ عَلَيْهِ السَّلامُ فى طُورِ سَيْناءَ","and through Thy glory, with which Thou revealed light to Moses, Thy addressee, peace be on him, on Mount Sinal;"],["وَلاِِبْراهيمَ عَلَيْهِ السَّلامُ خَليلِكَ مِنْ قَبْلُ فى مَسْجِدِ الْخَيْفِ","and earlier radiated the light for Abraham, Thy sincere friend peace be on him, in the mosque of al-Khayf;"],["وَلاِِسْحقَ صَفِيِّكَ عَلَيْهِ السَّلامُ فى بِئْرِ شِيع","and for Isaac, Thy chosen Prophet, peace be on him, in Bi-ri shiay',"],["وَلِيَعْقُوبَ نَبِيِّكَ عَلَيْهِ السَّلاَمُ فِى بَيْتِ إِيل (سبْع)","and for Thy Prophet Jacob, peace be on him, in Bayt iil and through Thy Glory,"],["وَاَوْفَيْتَ لاِِبْراهيمَ عَلَيْهِ السَّلامُ بِميثاقِكَ وَلاِِسْحقَ بِحَلْفِكَ","with which Thou fulfilled Thy promise to Abraham, peace be on him; and through Thy Oath in favour of Isaac;"],["وَلِيَعْقُوبَ بِشَهادَتِكَ وَلِلْمُؤْمِنينَ بِوَعْدِكَ وَلِلدّاعينَ بِاَسْمائِكَ فَاَجَبْتَ","and through Thy witnessing favouring Jacob; and through the fulfillments of Thy promise to the faithful: and through Thy Names with which Thou accepted the prayers of supplications;"],["وَبِمَجْدِكَ الَّذى ظَهَرَ لِمُوسَى بْنِ عِمْرانَ عَلَيْهِ السَّلامُ","and through Thy Glory, which appeared to Moses, son of Imran, Peace be upon Him"],["عَلى قُبَّةِ الرُّمّانِ (الزَّمانِ) وَبِاياتِكَ الَّتى وَقَعَتْ عَلى اَرْضِ مِصْرَ","in Qubbat al-Rumman; and through Thy Signs, which appeared on the soil of Egypt"],["بِمَجْدِ الْعِزَّةِ وَالْغَلَبَةِ بِايات عَزيزَة وَ بِسُلْطانِ الْقُوَّةِ وَبِعِزَّةِ الْقُدْرَةِ وَبِشَأْنِ الْكَلِمَةِ التّآمَّةِ","with great might and victory, with powerful signs and with the display of full command and great power; and with the affair of the perfect word;"],["وَبِكَلِماتِكَ الَّتى تَفَضَّلْتَ بِها عَلى اَهْلِ السَّماواتِ وَالاَْرْضِ وَاَهْلِ الدُّنْيا وَاَهْلِ الاْخِرَةِ","and with Thy words with which Thou doth a favor for the people of the skies and the earth and the people of here and the hereafter;"],["وَبِرَحْمَتِكَ الَّتى مَنَنْتَ بِها عَلى جَميعِ خَلْقِكَ","and through Thy Mercy with which Thou bestowth upon all Thy creatures:"],["وَبِاسْتِطاعَتِكَ الَّتى اَقَمْتَ بِها عَلَى الْعالَمينَ","and through thy Power with which Thou dominateth the worlds;"],["وَبِنُورِكَ الَّذى قَدْ خَرَّ مِنْ فَزَعِهِ طُورُ سَيْنآءَ","and (I beseech Thee) through Thy Light, through fear of which Mount Sinai collapsed,"],["وَبِعِلْمِكَ وَجَلالِكَ وَكِبْرِيآئِكَ وَ عِزَّتِكَ وَجَبَرُوتِكَ الَّتى لَمْ تَسْتَقِلَّهَا الاَْرْضُ","through Thy Knowledge, and Thy Greatness and Majesty, and Thy Unique Magnificence and Thy honour, and (through) Thy might, which the earth could not bear,"],["وَانْخَفَضَتْ لَهَا السَّماواتُ وَانْزَجَرَ لَهَا الْعُمْقُ الاَْكْبَرُ","and, for which the heavens and earth bent down, and the great depths restrained themselves,"],["وَرَكَدَتْ لَهَا الْبِحارُ وَالاَْنْهارُ","and the seas and rivers became stable,"],["وَ خَضَعَتْ لَهَا الْجِبالُ وَسَكَنَتْ لَهَا الاَْرْضُ بِمَناكِبِها","and to which the mountains made submission, and due to which the earth became firm on its shoulders,"],["وَاسْتَسْلَمَتْ لَهَا الْخَلائِقُ كُلُّها","and to which all creatures submitted,"],["وَ خَفَقَتْ لَهَا الرِّياحُ فى جَرَيانِها","and due to which the winds breathed,"],["وَخَمَدَتْ لَهَا النّيرانُ فى اَوْطانِها","and the flaming fires were extinguished in their places."],["وَبِسُلْطانِكَ الَّذى عُرِفَتْ لَكَ بِهِ الْغَلَبَةُ دَهْرَ الدُّهُورِ وَحُمِدْتَ بِهِ فِى السَّماواتِ وَالاَْرَضينَ","And I beseech Thee through Thy might, through which Thou hath been known to be All-powerful for ever and ever, and for which Thou hath been praised in the heavens and the earth;"],["وَبِكَلِمَتِكَ كَلِمَةِ الصِّدْقِ الَّتى سَبَقَتْ لاَِبينا ادَمَ عَلَيْهِ السَّلامُ وَذُرِّيَّتِهِ بِالرَّحْمَةِ","and I beseech Thee through Thy word, the Word of Truth, which became a blessing for our father Adam and his generation;"],["وَاَسْأَلُكَ بِكَلِمَتِكَ الَّتى غَلَبَتْ كُلَّ شَىْء","and I beseech Thee through Thy word, by which Thou overcame everything;"],["وَبِنُورِ وَجْهِكَ الَّذى تَجَلَّيْتَ بِهِ لِلْجَبَلِ فَجَعَلْتَهُ دَكّاً و خَرَّ مُوسى صَعِقاً","and I beseech thee through the light of Thy Face, which when it flased on Mount Sinai crushed it to pieces, whereby Moses fainted and fell down,"],["وَبِمَجْدِكَ الَّذى ظَهَرَ عَلى طُورِ سَيْنآءَ فَكَلَّمْتَ بِهِ عَبْدَكَ وَرَسُولَكَ مُوسَى بْنَ عِمْرانَ","and through Thy Glory, which appeared on Mount Sinai, and through which Thou addressed Thy slave and Thy Mesenger; Moses, son of 'Imran,"],["وَبِطَلْعَتِكَ فى ساعيرَ وَظُهُورِكَ فى جَبَلِ فارانَ بِرَبَواتِ الْمُقَدَّسينَ","and through Thy appearance in Sa'ir and on Mount Faran near Rabawat, which are clean and holy places,"],["وَجُنُودِ الْمَلائِكَةِ الصّافّينَ وَخُشُوعِ الْمَلائِكَةِ الْمُسَبِّحينَ","when troops of heavenly angels were in rows, and with the sumissiveness of the angels praising Thee,"],["وَبِبَرَكاتِكَ الَّتى بارَكْتَ فيها عَلى اِبْراهيمَ خَليلِكَ عَلَيْهِ السَّلامُ","and with Thy blessings with which Thou honoured Abraham, Thy sincere friend, peace be upon him,"],["فى اُمَّةِ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ","among the followers of Muhammad, Thy blessings be upon him and his Progeny"],["وَبارَكْتَ لاِِسْحقَ صَفِيِّكَ فى اُمَّةِ عيسى عَلَيْهِمَا السَّلامُ","and Thou honoured Isaac, Thy chosen prophet, among the followers of Jesus, peace be on them both,"],["وَبارَكْتَ لِيَعْقُوبَ اِسْرآئيلِكَ فى اُمَّةِ مُوسى عَلَيْهِمَا السَّلامُ","and honoured Jacob, Thy favoured slave, by including him among the followers of Moses, peace be on them both,"],["وَبارَكْتَ لِحَبيبِكَ مُحَمَّد صَلَّى اللهُ عَلَيْهِ وَآلِهِ فى عِتْرَتِهِ وَذُرِّيَّتِهِ وَاُمَّتِهِ","and honoured Thy intimate friend Muhammad, may the blessings of Allah be upon him and his Progeny, and peace be upon his offspring and seed, and his people."],["اَللّـهُمَّ وَكَما غِبْنا عَنْ ذلِكَ وَلَمْ نَشْهَدْهُ وَآمَنّا بِهِ وَلَمْ نَرَهُ صِدْقاً وَعَدْلاً","O Allah! Just as we believe in the turth and justice of these manifestations of Thy glory, without having been present at the time, and without having been eyewitnesses."],["اَنْ تُصَلِّىَ عَلى مُحَمَّد وَآلِ مُحَمَّد وَاَنْ تُبارِكَ عَلى مُحَمَّد","So we beseech Thee to send Thy blessings upon Muhammad and the Progeny of Muhammad, and honour Muhammad and the Progeny of Muhamamd, and honour Muhammad"],["وَآلِ مُحَمَّد وَتَرَحَّمَ عَلى مُحَمَّد وَآلِ مُحَمَّد","and the Progeny of Muhammad and have mercy on Muhammad and the Progeny of Muhammad,"],["كَاَفْضَلِ ما صَلَّيْتَ وَبارَكْتَ وَتَرَحَّمْتَ عَلى اِبْراهيمَ وَآلِ اِبْراهيمَ اِنَّكَ حَميدٌ مَجيدٌ","with the blessings, honour, and mercy Thou sent and bestowed on and meted out to Abraham and the posterity of Abraham. Surely Thou art Praiseworthy, Glorious,"],["فَعَّالٌ لِّمَا تُرِيدُ وَأَنتَ عَلَى كُلِّ شَيٍْء (شَهيد) قَدِيرٌ","the Doer of what Thou willeth. Thou art Powerful over all things."],["اَللّـهُمَّ بِحَقِّ هذَا الدُّعآءِ","O Allah! For the sake of this prayer,"],["وَبِحَقِّ هذِهِ الاَْسْمآءِ الَّتى لا يَعْلَمُ تَفْسيرَها وَلا يَعْلَمُ باطِنَها غَيْرُكَ","and for the sake of these Names which no one can interpret, the inner meaning of which no one other than Thyself knows."],["صَلِّ عَلى مُحَمَّد وَآلِ مُحَمَّد وَافْعَلْ بى ما اَنْتَ اَهْلُهُ","Send Thy blessing upon Muhammad and the Progeny of Muhammad; and give me the good of here and the hereafter; and do to me what suits Thee"],["وَلا تَفْعَلْ بى ما اَنَا اَهْلُهُ وَاغْفِرْ لى مِنْ ذُنُوبى ما تَقَدَّمَ مِنْها وَما تَأَخَّرَ","and do not do to me what I deserve and exact vengeance from…(enemy of progeny of Holy Prophet (s.a.w.a.), and forgive my sins past and future, and forgive my parents and all faithful men and women,"],["وَوَسِّعْ عَلَىَّ مِنْ حَلالِ رِزْقِكَ وَاكْفِنى مَؤُنَةَ اِنْسانِ سَوْء","and increase Thy lawful sustenance for me, and save me from the help of wicked men,"],["وَجارِ سَوْء ، وَقَرينِ سَوْء، وَسُلْطانِ سَوْء","wicked neighbours, wicked rulers, wicked companions,"],["اِنَّكَ عَلى ما تَشآءُ قَديرٌ وَبِكُلِّ شَيْء عَليمٌ آمينَ رَبَّ الْعالَمينَ","Verily Thou art able to do whatever Thou wileth, and Thou knowest everything. Amen, O Lord of the worlds."],["اللَّهُمَّ بِحَقِّ هذَا الدُّعَآءِ","O Allah! For the sake of this prayer"],["تَفَضَّلْ عَلَى فُقَرَآءِ الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ بِالْغِنَى وَالثَّرْوَةِ","Grant wealth and affluence to indigent faithful men and women"],["وَعَلَى مَرْضَى الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ بِالشِّفَآءِ وَالصِّحَّةِ","And recovery and sound health to the sick faithful men and women"],["وَعَلَى أَحْيَآءِ الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ بِاللُّطْفِ وَالْكَرَامَةِ","And bliss and clemency to the living faithful men and women"],["وَعَلَى أَمْوَاتِ الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ بِالْمَغْفِرَةِ وَالرَّحْمَةِ","And remit the sins of, and have mercy on, the deceased faithful men and women"],["وَعَلَى مُسَافِرِى الْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ بِالرَّدِّ إِلَى أَوْطَانِهِمْ سَالِمِينَ غَانِمِينَ","And arrange the return home of all faithful travellers with safety and gain."],["بِرَحْمَتِكَ يَآ أَرْحَمَ الرَّاحِمِينَ","Through Your mercy, O Most Merciful of all the merciful"],["وَصَلَّى اللَّهُ عَلَى سَيِّدِنَا مُحَمَّدٍ خَاتَمِ النَّبِيِّينَ وَعِتْرَتِهِ الطَّاهِرِينَ","May Allah send blessings upon our master Muhammad, the last of the prophets, and upon his Progeny, the purified."],["وَسَلَّمَ تَسْلِيمًا كَثِيرًا","And send peace [upon them] in abundant measure."]]},{"id":"dua-tawbah","cat":"Duʿāʾ","t":{"en":"Duʿāʾ al-Tawbah","ar":"دعاء التوبة"},"lines":[["بِسْمِ اللهِ الرَّحْمنِ الرَّحِيمِِ","In the Name of Allah, the Beneficent, the Merciful."],["اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَآلِ مُحَمَّد","O God, bless Muhammad and the family of Muhammad"],["اللَّهُمَّ يَا مَنْ لاَ يَصِفُهُ نَعْتُ الْوَاصِفِينَ","O God, O He whom the depiction of the describers fails to describe!"],["وَيَا مَنْ لاَ يُجَاوِزُهُ رَجَاءُ الرَّاجِينَ","O He beyond whom passes not the hope of the hopers!"],["وَيَا مَنْ لاَ يَضِيعُ لَدَيْهِ أَجْرُ الْمُحْسِنِينَ","O He with whom is not lost the wage of the good-doers!"],["وَيَا مَنْ هُوَ مُنْتَهَى خَوْفِ الْعَابِدِيْنَ","O He who is the ultimate object of the fear of the worshipers!"],["وَيَا مَنْ هُوَ غَايَةُ خَشْيَةِ الْمُتَّقِينَ","O He who is the utmost limit of the dread of the god-fearing!"],["هَذا مَقَامُ مَنْ تَدَاوَلَتْهُ أَيْدِي الذُّنُوبِ","This is the station of him whom sins have passed from hand to hand."],["وَقَادَتْهُ أَزِمَّةُ الْخَطَايَا","Offenses' reins have led him on"],["وَاسْتَحْوَذَ عَلَيْهِ الشَّيْطَانُ","And Satan has gained mastery over him."],["فَقَصَّرَ عَمَّا أَمَرْتَ بِهِ تَفْرِيطَاًِ","He fell short of what Thou hast commanded through neglect"],["وَتَعَاطى مَا نَهَيْتَ عَنْهُ تَغْرِيراًَ","And he pursued what Thou hast prohibited in delusion"],["كَالْجاهِلِ بِقُدْرَتِكَ عَلَيْهِِ","Like one ignorant of Thy power over him"],["أَوْ كَالْمُنْكِرِ فَضْلَ إحْسَانِكَ إلَيْهِِ","Or one who denies the bounty of Thy beneficence toward him"],["حَتَّى إذَا انْفَتَحَ لَهُ بَصَرُ الْهُدَىِ","Until, when the eye of guidance was opened for him"],["وَتَقَشَّعَتْ عَنْهُ سَحَائِبُ الْعَمَىِ","And the clouds of blindness were dispelled"],["أَحْصَى مَا ظَلَمَ بِهِ نَفْسَهُِ","He reckoned that through which he had wronged himself"],["وَفَكَّرَ فِيمَا خَالَفَ بِهِ رَبَّهُ","And reflected upon that in which he had opposed his Lord."],["فَرَأَى كَبِيْرَ عِصْيَانِهِ كَبِيْراًِ","He saw his vast disobedience as vast"],["وَجَلِيلَ مُخالَفَتِهِ جَلِيْلاً","And his great opposition as great."],["فَأَقْبَلَ نَحْوَكَ مُؤَمِّلاً لَكَ","So turned to Thee, hoping in Thee"],["مُسْتَحْيِيَاً مِنْكَ","And ashamed before Thee"],["وَوَجَّهَ رَغْبَتَهُ إلَيْكَ ثِقَةً بِكَ","And he directed his beseeching toward Thee, having trust in Thee"],["فَأَمَّكَ بِطَمَعِهِ يَقِيناًِ","He repaired to Thee in his longing with certitude"],["وَقَصَدَكَ بِخَوْفِهِ إخْلاَصَاً","And he went straight to Thee in fear with sincerity."],["قَدْ خَلاَ طَمَعُهُ مِنْ كُلِّ مَطْمُوعٍ فِيهِ غَيْرَكَ","His longing was devoid of every object of longing but Thee"],["وَأَفْرَخَ رَوْعُهُ مِنْ كُلِّ مَحْذُورٍ مِنْهُ سِوَاكَ","And his fright departed from every object of fear but Thee"],["فَمَثَلَ بَيْنَ يَدَيْـكَ مُتَضَرِّعـاًِ","So he stood before Thee pleading"],["وَغَمَّضَ بَصَرَهُ إلَى الأرْضِ مُتَخَشِّعَاًى","His eyes turned toward the ground in humbleness"],["وَطَأطَأَ رَأسَهُ لِعِزَّتِكَ مُتَذَلِّلاً","His head bowed before Thy might in lowliness"],["وَأَبَثَّكَ مِنْ سِرِّهِ مَا أَنْتَ أَعْلَمُ بِهِ مِنْهُ خُضُوعاًِ","He revealed to Thee in meekness those secrets of his which Thou knowest better than he"],["وَعَدَّدَ مِنْ ذُنُوبِهِ مَا أَنْتَ أَحْصَى لَهَا خُشُوعاً","He numbered for Thee in humility those sins of his which Thou countest better than he"],["وَاسْتَغَاثَ بِكَ مِنْ عَظِيمِ مَا وَقَعَ بِهِ فِي عِلْمِكَ","He sought help from Thee before the dreadful into which he has fallen in Thy knowledge"],["وَقَبِيحِ مَا فَضَحَهُ فِي حُكْمِكَِ","And the ugly which has disgraced him in Thy judgement"],["مِنْ ذُنُوبٍ أدْبَرَتْ لَذَّاتُهَا فَذَهَبَتْ","The sins whose pleasures have turned their backs and gone"],["وَأَقَامَتْ تَبِعَاتُهَا فَلَزِمَتْ","And whose evil consequences have stayed and stuck fast"],["لاَ يُنْكِرُ يَا إلهِي عَدْلَكَ إنْ عَاقَبْتَهُ","He will not deny Thy justice, my God, if Thou punishest him"],["وَلاَ يَسْتَعْظِمُ عَفْوَكَ إنْ عَفَوْتَ عَنْهُ وَرَحِمْتَهُ","Nor will he consider Thy pardon great if Thou pardonest him and hast mercy upon him"],["لأَنَّكَ الرَّبُّ الْكَرِيمُ الَّذِي لاَ يَتَعَاظَمُهُ غُفْرَانُ الذَّنْبِ الْعَظِيم","For Thou art the Generous Lord for whom the forgiveness of great sins is nothing great!"],["اللَّهُمَّ فَهَا أَنَا ذَا قَدْ جِئْتُكَ","O God, so here I am: I have come to Thee"],["مُطِيعاً لأَِمْرِكَ فِيمَا أَمَرْتَ بِهِ مِنَ الدُّعَاءِ","Obeying Thy command, for Thou hast commanded supplication"],["مَتَنَجِّزاً وَعْدَكَ فِيمَا وَعَدْتَ بِهِ مِنَ الإِجَابَةِ","And asking the fulfillment of Thy promise, for Thou hast promised to respond"],["إِذْ تَقُولُ :اُدْعُونى أَسْتَجِبْ لَكُمْ","Thou hast said, \"Supplicate Me and I will respond to you\""],["اللَّهُمَّ فَصَلِّ عَلَى مُحَمَّدٍ وَآلِهِ","O God, so bless Muhammad and his Household"],["وَالْقَنِي بِمَغْفِـرَتِكَ كَمَا لَقِيتُكَ بِـإقْرَارِي","Meet me with Thy forgiveness just as I have met Thee with my confession"],["وَارْفَعْنِي عَنْ مَصَارِعِ الذُّنُوب كَمَا وَضَعْتُ لَكَ نَفْسِي","Lift me up from the fatal infirmities of sins just as I have let myself down before Thee"],["وَاسْتُرْنِي بِسِتْرِكَ كَمَا تَأَنَّيْتَنِي عَنِ الانْتِقَامِ مِنِّي","And cover me with Thy covering just as Thou hast shown no haste to take vengeance on me"],["اللَّهُمَّ وَثَبِّتْ فِي طَاعَتِكَ نِيَّتِيِْ","O God, make firm my intention to obey Thee"],["وَأَحْكِمْ فِي عِبَادَتِكَ بَصِيـرَتِي","Strengthen my insight in worshipping Thee"],["وَوَفِّقْنِي مِنَ الأَعْمَالِ لِمَا تَغْسِلُ بِهِ دَنَسَ الْخَطَايَا عَنِّي","Give me the success of works which will wash away the defilement of offenses"],["وَتَوَفَّنِي عَلَى مِلَّتِكَ وَمِلَّةِ نَبِيِّكَ مُحَمَّدٍ عَلَيْهِ السَّلاَمُ إذَا تَوَفَّيْتَنِي","And take me when Thou takest me in the creed of Thy prophet Muhammad (upon him be peace)."],["اللَّهُمَّ إنِّي أَتُـوبُ إلَيْـكَ فِي مَقَامِي هَذَا مِنْ كَبَائِرِ ذُنُوبِي وَصَغَائِرِهَاَ","O God, I repent to Thee in this my station from my sins, great and small"],["وَبَوَاطِنِ سَيِّئاتِي وَظَوَاهِرِهَا","My evil deeds, inward and outward"],["وَسَوَالِفِ زَلاَّتِي وَحَوَادِثِهَا","My lapses, past and recent"],["تَوْبَةَ مَنْ لا يُحَدِّثُ نَفْسَهُ بِمَعْصِيَةٍٍ","With the repentance of one who does not tell himself that he might disobey"],["وَلاَ يُضْمِرُ أَنْ يَعُودَ فِي خَطِيئَةٍ","Or secretly think that he might return to an offense"],["وَقَدْ قُلْتَ يَا إلهِي فِي مُحْكَمِ كِتابِكَ","Thou hast said, my God, in the firm text of Thy Book"],["إنَّكَ تَقْبَلُ التَّوْبَةَ عَنْ عِبَادِكَ","That Thou acceptest repentance from Thy servants"],["وَتَعْفُو عَنِ السَّيِّئاتِ","Pardonest evil deeds"],["وَتُحِبُّ التَّوَّابِينَ","And lovest the repenters"],["فَاقْبَلْ تَوْبَتِي كَمَا وَعَدْتَ","So accept my repentance as Thou hast promised"],["وَاعْفُ عَنْ سَيِّئاتِي كَمَا ضَمِنْتَ","Pardon my evil deeds as thou hast guaranteed"],["وَأَوْجِبْ لِي مَحَبَّتَكَ كَمَا شَـرَطْتَ","And make obligatory toward me Thy love as Thou hast stipulated"],["وَلَـكَ يَـا رَبِّ شَـرْطِي أَلاَّ أَعُودَ فِي مَكْرُوهِكَ","To Thee, my Lord, belongs my stipulation that I will not return to what is disliked by Thee"],["وَضَمَانِي أَنْ لاَّ أَرْجِعَ فِي مَذْمُومِكَ","My guarantee that I will not go back to what Thou blamest"],["وَعَهْدِي أَنْ أَهْجُرَ جَمِيعَ مَعَاصِيكََ","And my covenant that I will stay away from acts of disobedience to Thee"],["اللَّهُمَّ إنَّكَ أَعْلَمُ بِمَا عَمِلْتُ","O God, Thou knowest better what I have done"],["فَاغْفِرْ لِي مَا عَلِمْتَ","So forgive me what Thou knowest"],["وَاصْرِفْنِي بِقُدْرَتِكَ إلَى مَا أَحْبَبْتََ","And turn me through Thy power to what Thou lovest!"],["اللَّهُمَّ وَعَلَيَّ تَبِعَاتٌ قَدْ حَفِظْتُهُنَّ","O God, counted against me are claims that stay in my memory"],["وَتَبِعَاتٌ قَدْ نَسيتُهُنَّ","And claims that I have forgotten"],["وَكُلُّهُنَّ بِعَيْنِكَ الَّتِي لاَ تَنَـامُ","While all of them remain in Thy eye that does not sleep"],["وَعِلْمِكَ الَّذِي لاَ يَنْسَى","And Thy knowledge that does not forget!"],["فَعَوِّضْ مِنْهَا أَهْلَهَاً","So compensate their owners"],["وَاحْطُطْ عَنِّيْ وِزْرَهَاً","Lighten their load upon me"],["وَخَفِّفْ عَنِّيْ ثِقْلَهَاِ","Lift up their weight from me"],["وَاعْصِمْنِي مِنْ أَنْ أُقَارِفَ مِثْلَهَا","And preserve me from approaching their like!"],["اللَّهُمَّ وَإنَّهُ لاَ وَفَاءَ لِي بِالتَّوْبَةِ إلاَّ بِعِصْمَتِكَِ","O God, but I can not be faithful to my repentance without Thy preservation"],["وَلاَ اسْتِمْسَاكَ بِي عَنِ الْخَطَايَا إلاَّ عَنْ قُوَّتِكَ","Nor can I refrain from offenses without Thy strength"],["فَقَوِّنِي بِقُوَّةٍ كَافِيَةٍ","So strengthen me with a sufficient strength"],["وَتَوَلَّنِي بِعِصْمَةٍ مَانِعَةٍِّ","And attend to me with a defending preservation!"],["اللَّهُمَّ أَيُّما عَبْدٍ تَابَ إلَيْكَ","O God, if any servant repents to Thee"],["وَهُوَ فِي عِلْمِ الْغَيْبِ عِنْدَكَ فَاسِخٌ لِتَوْبَتِهِ","While in Thy knowledge of the Unseen he will break his repentance"],["وَعَائِدٌ فِي ذَنْبِهِ وَخَطِيئَتِهِ","And return to his sin and offense"],["فَإنِّي أَعُوذُ بِكَ أنْ أَكُوْنَ كَذلِكَ","I seek refuge in Thee lest I be like that!"],["فَاجْعَلْ تَوْبَتِي هَذِهِ تَوْبَةً لاَ أَحْتَاجُ بَعْدَهَا إلَى تَوْبَةٍ","So make this my repentance a repentance after which I will need no repentance"],["تَوْبَةً مُوجِبَةً لِمَحْوِ مَا سَلَفَ","And a repentance which will obligate the erasing of what has gone by"],["وَالسَّلاَمَةِ فِيمَـا بَقِيَ","And safety in what remains!"],["اللَّهُمَّ إنِّي أَعْتَـذِرُ إلَيْـكَ مِنْ جَهْلِي","O God, I ask pardon from Thee for my ignorance"],["وَأَسْتَـوْهِبُـكَ سُوْءَ فِعْلِيٌ","And I ask Thee to disregard my evil acts!"],["فَـاضْمُمْنِي إلَى كَنَفِ رَحْمَتِكَ تَطَوُّلاً","So join me to the shelter of Thy mercy through graciousness"],["وَاسْتُرْنِي بِسِتْرِ عَافِيَتِكَ تَفَضُّلاً","And cover me with the covering of Thy well-being through bounteousness!"],["اللَّهُمَّ وَإنِّي أَتُوبُ إلَيْكَ مِنْ كُلِّ مَا خَالَفَ إرَادَتَكَ","O God, I repent to Thee from everything opposed to Thy will"],["أَوْ زَالَ عَنْ مَحَبَّتِـكَ مِنْ خَـطَرَاتِ قَلْبِي","Or far from Thy love - the thoughts of my heart"],["وَلَحَـظَاتِ عَيْنِي، وَحِكَايَاتِ لِسَانِي","The glances of my eye, the tales of my tongue"],["تَوْبَةً تَسْلَمُ بِهَا كُلُّ جَارِحَةٍ عَلَى حِيَالِهَا مِنْ تَبِعَاتِكَ","With a repentance through which each bodily part will by itself stay safe from ill consequences with Thee"],["وَتَأْمَنُ مِمَّا يَخَافُ الْمُعْتَدُونَ مِنْ أَلِيْمِ سَطَوَاتِكَ","And remain secure from Thy painful penalties feared by transgressors!"],["اللَّهُمَّ فَارْحَمْ وَحْدَتِي بَيْنَ يَدَيْكَ","O God, so have mercy on my being alone before Thee"],["وَوَجِيبَ قَلْبِي مِنْ خَشْيَتِكَ","The pounding of my heart in dread of Thee"],["وَاضْطِرَابَ أَرْكَانِي مِنْ هَيْبَتِكَ","The trembling of my limbs in awe of Thee!"],["فَقَدْ أَقَامَتْنِي يَا رَبِّ ذُنُوبِي مَقَامَ الْخِزْيِ بِفِنَائِكَ","My sins, my God, have stood me in the station of degradation in Thy courtyard"],["فَإنْ سَكَتُّ لَمْ يَنْطِقْ عَنِّيْ أَحَدٌ","If I remain silent, none will speak for me"],["وَإنْ شَفَعْتُ فَلَسْتُ بِأَهْلِ الشَّفَاعَةِ","If I seek an intercessor, I am not worthy for intercession"],["اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَآلِهِ","O God, bless Muhammad and his Household"],["وَشَفِّعْ فِي خَطَايَـايَ كَرَمَكََ","Make Thy generosity intercede for my offenses"],["وَعُدْ عَلَى سَيِّئاتِي بِعَفْوِكَ","Follow up my evil deeds with Thy pardon"],["وَلاَ تَجْزِنِي جَزَائِي مِنْ عُقُوبَتِكََ","Repay me not with the punishment that is my proper repayment"],["وَابْسُطْ عَلَيَّ طَوْلَكََ","Spread over me Thy graciousness"],["وَجَلِّلْنِي بِسِتْرِكَ","Wrap me in Thy covering"],["وَافْعَلْ بِي فِعْلَ عَزِيزٍ تَضَرَّعَ إلَيْهِ عَبْدٌ ذَلِيلٌ فَرَحِمَهُ","And do with me what is done by a mighty man, when a lowly slave pleads to him and he shows him mercy"],["أَوْ غَنِيٍّ تَعَرَّضَ لَهُ عَبْدٌ فَقِيرٌ فَنَعَشَهُ","Or a rich man, when a poor slave submits himself and he raises him to wealth!"],["اللَّهُمَّ لاَ خَفِيرَ لِي مِنْكَ فَلْيَخْفُرْنِيْ عِزُّكَ","O God, I have no protector against Thee, so let Thy might be my protector!"],["وَلاَ شَفِيعَ لِيْ إلَيْكَ فَلْيَشْفَعْ لِي فَضْلُكَ","I have no intercessor with Thee, so let Thy bounty be my intercessor!"],["وَقَدْ أَوْجَلَتْنِي خَطَايَايَ فَلْيُؤْمِنِّي عَفْوُكَ","My offenses have set me quaking, so let Thy pardon give me security!"],["فَمَا كُلُّ مَا نَطَقْتُ بِهِ عَنْ جَهْلٍ مِنِّي بِسُوْءِ أَثَرِي","Not all that I have said rises up from my ignorance of my evil footsteps"],["وَلاَ نِسيَانٍ لِمَا سَبَقَ مِنْ ذَمِيمِ فِعْلِي","Or forgetfulness of my blameworthy acts in the past"],["وَلكِنْ لِتَسْمَعَ سَمَاؤُكَ وَمَنْ فِيْهَـا","But in order that Thy heaven and those within it"],["وَأَرْضُكَ وَمَنْ عَلَيْهَا مَا أَظْهَرْتُ لَكَ مِنَ النَّدَمَِِ","And Thy earth and those upon it may hear the remorse which I have professed to Thee"],["وَلَجَـأْتُ إلَيْكَ فِيـهِ مِنَ التَّوْبَـةِ","And the repentance through which I have sought asylum with Thee"],["فَلَعَـلَّ بَعْضَهُمْ بِرَحْمَتِكَ يَرْحَمُنِي لِسُوءِ مَوْقِفِيَ","Then perhaps one of them, through Thy mercy, may show mercy upon my evil situation"],["أَوْ تُدْرِكُهُ الرِّقَّةُ عَلَيَّ لِسُوءِ حَالِي","Or be seized by tenderness for my evil state"],["فَيَنَالَنِي مِنْهُ بِدَعْوَة هِيَ أَسْمَعُ لَدَيْكَ مِنْ دُعَائِي","There may come from him for my sake a supplication to which Thou givest ear more than to my supplication"],["أَوْ شَفَاعَـةٍ أَوْكَدُ عِنْـدَكَ مِنْ شَفَاعَتِي","Or an intercession surer with Thee than my intercession"],["تَكُونُ بِهَا نَجَاتِي مِنْ غَضَبِكَ وَفَوْزَتِي بِرِضَاكََ","Through which I may be delivered from Thy wrath and attain to Thy good pleasure!"],["اللَّهُمَّ إنْ يَكُنِ النَّدَمُ تَوْبَةً إلَيْكَ","O God, if remorse is a repentance toward Thee"],["فَأَنَا أَنْدَمُ اْلنَّادِمِينَ","Then I am the most remorseful of the remorseful!"],["وَإنْ يَكُنِ التَّرْكُ لِمَعْصِيَتِكَ إنَابَةًَ","If refraining from disobedience is a turning back to Thee"],["فَأَنَا أَوَّلُ الْمُنِيبينََ","Then I am the first of those who turn back!"],["وَإنْ يَكُنِ الاسْتِغْفَارُ حِطَّةً لِلذُّنُوبِ","If praying for forgiveness alleviates sins"],["فَإنِّي لَكَ مِنَ الْمُسْتَغْفِرِينَ","Surely I am one of those who pray for Thy forgiveness!"],["اللَّهُمَّ فَكَمَا أَمَرْتَ بِالتَّوْبَةِ","O God, as Thou hast commanded repentance"],["وَضَمِنْتَ الْقَبُولَ","And guaranteed acceptance"],["وَحَثَثْتَ عَلَى الدُّعَـاءِ، وَوَعَدْتَ الإجَابَةََ","As Thou hast urged supplication, and promised to respond"],["فَصَلِّ عَلَى مُحَمَّدٍ وَآلِهِ وَاقْبَلْ تَوْبَتِيَ","So also bless Muhammad and his Household, accept my repentance,"],["وَلاَ تَرْجِعْنِي مَرْجِعَ الخَيْبَةِ مِنْ رَحْمَتِكَ","And return me not to the returning place of disappointment in Thy mercy!"],["إنَّكَ أَنْتَ التَّوَّابُ عَلَى الْمُذْنِبِينَ","Surely Thou art Ever-turning toward the sinners"],["وَالرَّحِيمُ لِلْخَاطِئِينَ الْمُنِيبِينَ","All-compassionate toward the offenders who turn back!"],["اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَآلِهِ كَمَا هَدَيْتَنَا بِهِ","O God, bless Muhammad and his Household just as Thou hast guided us by him!"],["وَصَلِّ عَلَى مُحَمَّدٍ وَآلِهِ كَمَا اسْتَنْقَذْتَنَا بِهِ","Bless Muhammad and his Household just as Thou hast rescued us through him!!"],["وَصَلِّ عَلَى مُحَمَّدٍ وَآلِهِ","Bless Muhammad and his Household"],["صَلاَةً تَشْفَعُ لَنَا يَوْمَ الْقِيَامَةِ","With a blessing that will intercede for us on the Day of Resurrection"],["وَيَوْمَ الْفَاقَةِ إلَيْكَ","The day of neediness toward Thee!"],["إنَّكَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ","Thou art powerful over everything"],["وَهُوَ عَلَيْكَ يَسِيرٌ","And that is easy for Thee!"]]},{"id":"dua-yastasheer","cat":"Duʿāʾ","t":{"en":"Duʿāʾ al-Yastashīr","ar":"دعاء الاستشارة"},"lines":[["بِسْمِ اللهِ الرَّحْمنِ الرَّحِيمِِ","In the Name of Allah, the Beneficent, the Merciful."],["اَلْحَمْدُ للهِ الَذى لا اِلـهَ اِلاّ هُوَ الْمَلِكُ الْحَقُّ الْمُبي","All praise is due to Allah. There is no god but He, the Living, the Just, the Manifest."],["الْمُدَبِرُّ بِلا وَزير وَلا خَلْق مِنْ عِبادِهِ يَسْتَشيرُ","He is the Administrator without any minister and without consultation with any of his slaves."],["الأَوَّلُ غَيْرُ (مَصْرُوفٍ) مَوْصُوفٍ","He is the First, who cannot be described."],["وَالْباقى بَعْدَ فَنآءِ الْخَلْقِ، الْعَظيمُ الرُّبُوبِيَّةِ","He is Eternal and will live forever, (even) after the annihilation of all creatures. He is the greatest Cherisher"],["نُورُ السَّماواتِ وَالاَْرَضينَ وَفاطِرُهُما وَمُبْتَدِعُهُما بِغَيْرِ عَمَد خَلَقَهُما وَفَتَقَهُما","and Sustainer and the Light of the earths and heavens and their Creator and Maker out of nothing. He created both of them and separated them"],["فَتْقاً فَقامَتِ السَّماواتُ طآئِعات بِاَمْرِهِ وَاسْتَقَرَّتِ الاَْرضَوُنَ (الاَْرْضِ) بِاَوْتادِها فَوْقَ الْمآءِ","– a proper separation. The heavens became stable in obedience to His commandment and the earths became fixed on the surface of the water with their pegs."],["ثُمَّ عَلا رَبُّنا فِى السَماواتِ الْعُلى اَلَّرحْمنُ عَلَى الْعَرْشِ اسْتَوى","Then our Lord the All-Merciful subdued the high heavens and ruled from the Throne."],["لَهُ ما فِى السَّماواتِ وَما فِى الاَْرْضِ وَما بَيْنَهُما وَما تَحْتَ الثَّرى","Everything that is in heaven and in the earth and in between them and what is below the earth belongs to Him."],["فَاَنَا اَشْهَدُ بِاَنَّكَ اَنْتَ اللهُ لا رافِعَ لِما وَضَعْتَ","So, I bear witness that verily You are Allah. There is none to elevate what You hath lowered"],["وَلا واضِعَ لِما رَفَعْتَ، وَلا مُعِزَّ لِمَنْ اَذْلَلْتَ","and no one to exalt him whom You leaves in disgrace and no one to bring into disgrace him whom You exalts"],["وَلا مُذِلَّ لِمَنْ اَعْزَزْتَ، وَلا مانِعَ لِما اَعْطَيْتَ","and no one to prevent him upon whom You bestoweth Thy favour and no one to bestow anything,"],["وَلا مُعْطِىَ لِما مَنَعْتَ","which You hath withheld."],["وَاَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ كُنْتَ اِذْ لَمْ تَكُنْ سَمآءٌ مَبْنِيَّةٌ","You are Allah, there is no god but Thee. Who existed when there was neither the stable sky"],["وَلا اَرْضٌ مَدْحِيَّةٌ وَلا شَمْسٌ مُضيـئَةٌ وَلا لَيْلٌ مُظْلِمٌ","nor the broad earth nor the brilliant sun nor the dark night,"],["وَلا نَهارٌ مُضيـىءٌ، وَلا بَحْرٌ لُجِّىٌّ وَلا جَبَلٌ راس","nor the bright day, nor the vast and stormy sea, nor any sublime and stable mountain,"],["وَلا نَجْمٌ سار، وَلا قَمَرٌ مُنيرٌ، وَلا ريحٌ تَهُبُّ","nor any revolving planet, nor the luminous moon, nor any blowing wind,"],["وَلا سَحابٌ يَسْكُبُ، وَلا بَرْقٌ يَلْمَعُ، وَلا رَعْدٌ يُسَبِّحُ","nor any raining cloud, nor flashing lightning, nor any praising thunder,"],["وَلا رُوحٌ تَنَفَّسُ، وَلا طآئِرٌ يَطيرُ، وَلا نارٌ تَتَوَقَّدُ","nor any breathing soul, nor any flying bird, nor any blazing fire,"],["وَلا مآءٌ يَطَّرِدُ كُنْتَ قَبْلَ كُلِّ شَْيء وَكَوَّنْتَ كُلَّ شَْيء","nor any flowing water. You existed before the existence of everything and You created everything"],["وَقَدَرْتَ عَلى كُلِّ شَْيء وَابْتَدَعْتَ كُلَّ شَْيء","and controlled everything and originated everything."],["وَاَغْنَيْتَ وَاَفْقَرْتَ وَ اَمَتَّ وَاَحْيَيْتَ","You enriched some and reduced others to poverty, caused some to die and brought others to life,"],["وَاَضْحَكْتَ وَاَبْكَيْتَ وَعَلَى الْعَرشِ اسْتَوَيْتَ فَتَبارَكْتَ","and made some people glad and other weep. Verily You rules from the Throne. You are of vast blessing,"],["يا اَللهُ وَ تَعالَيْتَ، اَنْتَ اللهُ الَّذى لا اِلـهَ اِلاّ اَنْتَ","O Allah You are Great and Supreme. You are Allah and there is no god other than Thee."],["الْخَلاّقُ الْمُعينُ (الْعَليمُ) اَمْرُكَ غالِبٌ وَعِلْمُكَ نافِذٌ","You are the Creator and Supporter. Thy Decree is everpowering and Thy Knowledge is operative."],["وَكَيْدُكَ غَريبٌ، وَوَعْدُكَ صادِقٌ","Thy strategy is wonderful; Thy promise is true;"],["وَقَوْلُكَ حَقٌّ وَحُكْمُكَ عَدْلٌ","Thy word is right; Thy command is just;"],["وَكَلامُكَ هُدىً، وَوَحْيُكَ نوُرٌ","Thy utterance is right guidance; Thy Revelation is light;"],["وَرَحْمَتُكَ واسِعَةٌ، وَعَفْوُكَ عَظيمٌ","Thy mercy is vast and abundant; Thy forgiveness is superb;"],["وَفَضْلُكَ كَثيرٌ، وَعَطاؤُكَ جَزيلٌ، وَحَبْلُكَ مَتينٌ","Thy grace is excessive; Thy gift is most respectable Thy cord is strong;"],["وَاِمْكانُكَ عَتيدٌ، وَجارُكَ عَزيزٌ، وَبَاْسُكَ شَديدٌ، وَمَكْرُكَ مَكيدٌ","Thy might is ever ready Thy protégé is powerful; Thy wrath is severe; and Thy stratagem is entrapping"],["اَنْتَ يا رَبِ مَوْضِعُ كُلِّ شَكْوى حاضِرُ كُلِّ مَلاَء وَشاهِدُ كُلِّ نَجْوى","O Lord! With Thee are lodged all complaints. You are present in all gatherings, and are the witness of all secrets,"],["مُنْتَهى كُلِّ حاجَة مُفَرِّجُ كُلِّ حُزْن (حَزين) غِنى كُلِّ مِسْكين","and the ultimate goal of all supplications, the expeller of all sorrows, the affluence of every needy person,"],["حِصْنُ كُلِّ هارِب اَمانُ كُلِّ خآئِف، حْرِزُ الضُّعَفآءِ كَنْزُ الْفُقَرآءِ","the stronghold for every refugee, security for everyone who is terror-stricken, a shield for the weak a treasure for the indigent,"],["مُفَرِّجُ الْغَمّآءِ مُعينُ الصّالِحينَ، ذلِكَ اللهُ رَبُّنا لا اِلـهَ اِلاّ هُوَ","the destroyer of griefs, the helper of the virtuous. Such is Allah, our Lord. There is no god but He."],["تَكْفى مِنْ عِبادِكَ مَنْ تَوَكَّلَ عَلَيْكَ وَاَنْتَ جارُ","You satisfieth such of Thy slaves as trust unto Thee. You are the protector of him"],["مَنْ لاذَ بِكَ وَتَضَرَّعَ اِلَيْكَ عِصْمَةُ مَنِ اعْتَصَمَ بِكَ ناصِرُ","who is firmly attached to Thee and humiliates himself before Thee, a shield for him who seeks refuge with Thee, the help of him"],["مَنِ انْتَصَرَ بِكَ تَغْفِرُ الذُّنُوبَ لِمَنِ اسْتَغْفَرَكَ","who looks up to Thee for help, the forgiver of sins for him who begs Thy pardon,"],["جَبّارُ الْجَبابِرَةِ، عَظيمُ الْعُظَمآءِ كَبيرُ الْكُبَرآءِ","the complier of the tyrant, the most grand of the grand, the most great of the great,"],["سَيِّدُ السّاداتِ مُوْلَى الْمَوالى صَريخُ الْمُسْتَصْرِخينَ مُنَفِّسٌ عَنِ الْمَكْروُبينَ","the master of masters, the Lord of lords, the Succour of the grieved, the Helper of those crying for help,"],["مُجيبُ دَعْوَةِ الْمُضْطَرِّينَ اَسْمَعُ السّامِعينَ اَبْصَرُ النّاظِرينَ","the Responder to the call of the distressed, the best of all listeners, the best of all observers,"],["اَحْكَمُ الْحاكِمينَ اَسْرَعُ الْحاسِبينَ اَرْحَمُ الرّاحِمينَ خَيْرُ الغافِرينَ","the best of all judges, the quickest of all reckoners, the most merciful of all the merciful the best of all forgivers,"],["قاضى حَوآئِج الْمُؤْمِنينَ مُغيثُ الصّالِحينَ","the satisfier of the needs of the faithful, and the hearer of the appeals of the virtuous."],["اَنْتَ اللهُ لا اِلـهَ اِلاّ اَنْتَ رَبُّ الْعالَمينَ","You are Allah, there is no god but Thee. You are the Cherisher and Sustainer of all the worlds"],["اَنْتَ الْخالِقُ وَاَنَا الَْمخْلوُقُ وَاَنْتَ الْمالِكُ وَاَنَا الْمَمْلوُكُ","You are the Creator and I am a creature. You are the Master and I am a servant,"],["وَاَنْتَ الرَّبُّ وَاَنَا الْعَبْدُ وَاَنْتَ الرّازِقُ وَاَنَا الْمَرْزُوقُ","You are the Creator and I am a creature. You are the Master and I am a servant,"],["وَاَنْتَ الْمُعْطى وَاَنَا السّآئِلُ وَاَنْتَ الْجَوادُ وَاَنَا الْبَخيلُ","You are the Giver while I am a beggar, You are the Generous while I am a miser."],["وَاَنْتَ الْقَوِىُّ وَاَنَا الضَّعيفُ وَاَنْتَ الْعَزيزُ وَاَنَا الذَّليلُ","You are the Mighty while I am weak, You are the Noble while I am humble."],["وَاَنْتَ الْغَنِىُّ وَاَنَا الْفَقيرُ، وَاَنْتَ السَّيِّدُ وَاَنَا الْعَبْدُ","You are the independent while I am needy. You are the Master while I am slave."],["وَاَنْتَ الْغافِرُ وَاَنَا الْمُسـيئُ وَاَنْتَ الْعالِمُ وَاَنَا الْجاهِلُ","You are the Forgive of sins while I am sinful. You are the Omniscient while I am ignorant."],["وَاَنْتَ الْحَليمُ وَاَنَا الْعَجُولُ، وَاَنْتَ الرَّحْمنُ وَاَنَا الْمَرْحُومُ","You are the forbearing while I am hasty. You are the All-Merciful and I have been treated with mercy."],["وَاَنْتَ الْمُعافى وَاَنَا الْمُبْتَلى، وَاَنْتَ الُْمجيبُ وَاَنَا الْمُضْطَرُّ","You are the Provider of safety but I am involved in suffering. You are the Responder and I am the distressed."],["وَاَنَا اَشْهَدُ بِانَّكَ اَنْتَ اللهُ لا اِلـهَ اِلاّ","And I bear witness that verily You are Allah, there is no god but thee"],["اَنْتَ الْمُعْطى عِبادَكَ بِلا سُؤال","thou bestoweth favours upon Thy slaves even without their asking."],["وَاَشْهَدُ بَاِنَّكَ اَنْتَ اللهُ الْواحِدُ الاَْحَدُ","And I bear witness that verily You are Allah, the One, the Peerless,"],["الْمُتَفَرِّدُ الصَّمَدُ الْفَرْدُ وَاِلَيْكَ الْمَصيرُ","the Unique, the independent, the Single, and verily to Thee we must return."],["وَصَلَّى اللهُ عَلى مُحَمَّد وَاَهْلِ بَيْتِهِ الطَّيِّبينَ الطّاهِرينَ","May the blessings of Allah be upon Muhammad and his family the holy and pure."],["وَاغْفِرْ لى ذُنُوبى وَاسْتُرْ عَلَىَّ عيُوُبى","O Lord, forgive my sins and keep my faults concealed"],["وَافْتَحْ لى مِنْ لَدُنْكَ رَحْمَةً وَرِزْقاً واسِعاً","and extend to me Thy special mercy and bounteous sustenance"],["يا اَرْحَمَ الرّاحِمينَ وَالْحَمْدُ للهِ رَبِّ الْعالَمينَ","O the All-merciful! All praise is due to Allah the Cherisher and sustainer of all the worlds"],["وَحَسْبُنَا اللهُ وَنْعِمَ الْوَكيلُ","And for us Allah is the Sufficiency and the excellent Protector."],["وَلا حَوْلَ وَلا قُوَّةَ اِلاّ بِاللهِ الْعَلِىِّ الْعَظيم","There is neither might nor power but with Allah the Great, the Exalted."]]},{"id":"hadith-kisa","cat":"Ḥadīth","t":{"en":"Ḥadīth al-Kisāʾ","ar":"حديث الكساء"},"lines":[["بِسْمِ اللَّهِ الرَّحْمَن الرَّحِيمِ","In the name of Allah, the All-Merciful, the All-Compassionate"],["عَن فَاطِمَةَ الزَّهْرَآءِ ع بِنتِ رَسُولِ اللَّهِ ص أَنَّهَا قَالَتْ:","Fatimah al-Zahra, the daughter of the Prophet, peace be on them, is to have thus related (an event):-"],["دَخَلَ عَلَيَّ أَبِى رَسُولُ اللَّهِ ص فِى بَعْضِ الأَيَّامِ فَقَالَ: السَّلاَم عَلَيْكِ يَا فَاطِمَةُ","My father, the Prophet of Allah, came to my house one day and said to me: \"Peace be on you, Fatimah\""],["فَقُلْتُ: عَلَيْكَ السَّلاَمُ","I replied: \"And upon you be peace\""],["قَالَ: إِنِّى أَجِدُ فِى بَدَنِى ضُعْفَاً","Then he said: \"I feel weakness in my body\""],["فَقُلْتُ لَهُ : أُعِيذُكَ بِالِلَّهِ يَآ أَبَتَاهُ مِنَ الضُّعْفِ","I said:\" Allah protects you from weakness, father\""],["فَقَالَ: يَا فَاطِمَةُ إِيْتِينِى بِالْكِسَآءِ الْيَمَانِى فَغَطِّينِى بِهِ","He said: \"Fatimah, please bring the Yemeni cloak and cover me with it\""],["فَأَتَيْتُهُ بِالْكِسَآءِ الْيَمَانِى فَغَطَّيْتُهُ بِهِ","So, I brought the Yemeni cloak and covered him with it."],["وَصُرْتُ أَنظُرُ إِلَيْهِ وَإِذَا وَجْهُهُ يَتَلْاَلَؤُ كَأَنَّهُ الْبَدْرُ فِى لَيْلَةِ تَمَامِهِ وَكَمَاِلهِ","Then, I looked at him and saw that his face was shining like a full moon with its glory and splendor."],["فَمَا كَانَتْ إِلا سَاعَةً وَّإِذَا بِوَلَدِىَ الْحَسَنِ قَدْ أَقْبَلَ وَقَالَ: السَّلاَمُ عَلَيْكِ يَآ أُمَّاهُ","After a while, my son Hasan came in and said: \"Peace be on you, mother\""],["فَقُلْتُ: وَعَلَيْكَ السَّلاَمُ يَا قُرَّةَ عَيْنِى وَثَمَرَةَ فُؤَادِى","I replied: \"And upon you peace, O light of my eyes, and the delight of my heart\""],["فَقَالَ: يَآ أُمَّاهُ إِنِّى أَشُمُّ عِندَكِ رَآئِحَةً طَيِّبَةً كَأَنَّهَا رَآئِحَةُ جَدِّى رَسُولِ اللَّهِ","He then said:\" Mother! I smell a fragrance so sweet and so pure as that of my grandfather, the Prophet of Allah\""],["فَقُلْتُ: نَعَمْ إِنَّ جَدَّكَ تَحْتَ الْكِسَآءِ","I replied: \"Yes. Your grandfather is lying underneath the cloak\""],["فَأَقْبَلَ الْحَسَنُ نَحْوَ الْكِسَآءِ وَقَالَ: السَّلاَمُ عَلَيْكَ يَا جَدَّاهُ يَارَسُولَ اللَّهِ، أَتَأْذَنُ لِى أَنْ أَدْخُلَ مَعَكَ تَحْتَ الْكِسَآءِ","Hasan went near the cloak and said: \"Peace be on you, my grandfather, the Prophet of Allah; May I enter the cloak with you?\""],["فَقَالَ: وَعَلَيْكَ السَّلاَمُ يَا وَلَدِى وَيَا صَاحِبَ حَوْضِي، قَدْ أَذِنتُ لَكَ","He replied: \"And upon you peace, my son and the master of my fountain (Kauthar), you are given the permission to enter\""],["فَدَخَلَ مَعَهُ تَحْتَ الْكِسَآءِ","So, Hasan entered the cloak with him."],["فَمَا كَانَتْ إِلا سَاعَةً وَّإِذَا بِوَلَدِىَ الْحُسَيْنِ قَدْ أَقْبَلَ وَقَالَ: السَّلاَمُ عَلَيْكِ يَآ أُمَّاهُ","After a while, my son Husain came in and said: \"Peace be on you, mother\""],["فَقُلْتُ: وَعَلَيْكَ السَّلاَمُ يَا وَلَدِيْ وَيَا قُرَّةَ عَيْنِى وَثَمَرَةَ فُؤَادِى","I replied: \"And upon you peace, O light of my eyes, and the delight of my heart\""],["فَقَالَ لِي: يَآ أُمَّاهُ إِنِّى أَشُمُّ عِندَكِ رَآئِحَةً طَيِّبَةً كَأَنَّهَا رَآئِحَةُ جَدِّى رَسُولِ اللَّهِ","He then said: \"Mother! I smell a sweet fragrance like that of my grandfather, the Prophet of Allah\""],["فَقُلْتُ: نَعَمْ إِنَّ جَدَّكَ وَأَخَاكَ تَحْتَ الْكِسَآءِ","I replied: \"Yes. Your grandfather and your brother are lying underneath the cloak\""],["فَدَنَى الْحُسَيْنُ نَحْوَ الْكِسَآءِ وَقَالَ:السَّلاَمُ عَلَيْكَ يَا جَدَّاهُ، السَّلاَمُ عَلَيْكَ يَا مَنِ اخْتَارَهُ اللَّهُ ، أَتَأْذَنُ لِى أَنْ أَكُونََ مَعَكُمَا تَحْتَ الْكِسَآءِ","Husain stepped towards the cloak and said: \"Peace be on you, my grandfather, the chosen of Allah; May I enter the cloak with you?\""],["فَقَالَ: وَعَلَيْكَ السَّلاَمُ يَا وَلَدِيْ وَيَا شَافِعَ أُمَّتِى قَدْ أَذِنتُ لَكَ","He replied: \"And upon you peace, my son and the interceder of my followers, you are given the permission to enter\""],["فَدَخَلَ مَعَهُمَا تَحْتَ الْكِسَآءِ","So, Husain entered the cloak with them."],["فَأَقْبَلَ عِندَ ذَلِكَ أَبُو الْحَسَنِ عَلِّيُّ ابْنُ أَبِى طَاِلبٍ وَّقَالَ: السَّلاَمُ عَلَيْكِ يَابِنتَ رَسُولِ اللَّهِ","After a while, Abul Hasan, Ali bin Abi Talib came in and said: \"Peace be on you, O daughter of the Prophet of Allah\""],["فَقُلْتُ: وَعَلَيْكَ السَّلاَمُ يَآ أَبَا الْحَسِن وَيَآ أَمِيرَ الْمُؤمِنِينَ","I replied: \"And upon you peace, O father of Hasan, and the Commander of the faithful\""],["فَقَالَ يَا فَاطِمَةُ إِنِّى أَشُمُّ عِندَكِ رَآئِحَةً طَيِّبَةً كَأَنَّهَا رَآئِحَةُ أَخِى وَابْنِ عَمِّى رَسُولِ اللَّهِ","He then said: \"Fatimah! I smell a sweet fragrance like that of my bother, (my cousin), the Prophet of Allah\""],["فَقُلْتُ نَعَمْ هَا هُوَ مَعَ وَلَديْكَ تَحْتَ الْكِسَآءِ","I replied: \"Yes. He is underneath the cloak with your two sons\""],["فَأَقْبَلَ عَلِّيٌّ نَّحْوَ الْكِسَآءِ وَقَالَ: السَّلاَمُ عَلَيْكَ يَارَسُولَ اللَّهِ، أَتَأْذَنُ لِى أَنْ أَكُوْنَ مَعَكُمْ تَحْتَ الْكِسَآءِ","So, Ali went near the cloak and said: \"Peace be on you, Prophet of Allah; May I enter the cloak with you?\""],["قَالَ لَهُ: وَعَلَيْكَ السَّلاَمُ يَآ أَخِى وَيَا وَصِيِّى وَخَلِيْفَتِى وَصَاحِبَ لِوَآئِي، قَدْ أَذِنتُ لَكَ","He replied: \"And upon you peace, my brother, my legatee, my successor, and my standard bearer, you are given the permission to enter\""],["فَدَخَلَ عَلِيٌّ تَحْتَ الْكِسَآءِ","So, Ali entered the cloak with them."],["ثُمَّ أَتَيْتُ نَحْوَ الْكِسَآءِ وَقُلْتُ: السَّلاَمُ عَلَيْكَ يَآ أَبَتَاه يَا رَسُوْلَ اللَّهِ، أَتَأْذَنُ لِى أَنْ أَكُوْنَ مَعَكُمْ تَحْتَ الْكِسَآءِ","Then I stepped forward and said: \"Peace be on you, my father, O Prophet of Allah; May I enter the cloak with you?\""],["قَالَ: وَعَلَيْكِ السَّلاَمُ يَا بِنتِى وَيَا بَضْعَتِي، قَدْ أَذِنتُ لَكِ","He replied: \"And upon you peace, my daughter, O part of my self; you are given the permission to enter\""],["فَدَخَلْتُ تَحْتَ الْكِسَآءِ","So, I entered the cloak with them."],["فَلَّمَا اكْتَمَلْنَا جَمِيْعاً تَحْتَ الْكِسَآءِ أَخَذَ أَبِى رَسُولُ اللَّهِ بِطَرَفَيِ الْكِسَآءِ وَأَوْمَئَ بِيَدِهِ الْيُمْنَى إِلَى السَّمَآءِ وَقَالَ:","Getting together underneath the cloak, my father, the Prophet of Allah, held the two ends of the cloak and raised his right hand towards the heavens and prayed:"],["اللَّهُمَّ إِنَّ هَؤُلاءِ أَهْلُ بَيْتِى وَخَآصَّتِى وَحَآمَّتِي،","\"O Allah, these are the people of my Household (Ahlul-Bayt). They are my confidants and my supporters."],["لَحْمُهُمْ لَحْمِي، وَدَمُهُمْ دَمِي،","Their flesh is my flesh and their blood is my blood."],["يُؤْلِمُنِى مَا يُؤْلِمُهُمْ،","Whoever hurts them, hurts me too."],["وَيَحْزُنُنِيْ مَا يَحْزُنُهُمْ،","Whoever displeases them, displeased me too."],["أَنَا حَرْبٌ لِّمَنْ حَارَبَهُمْ،","I am at war with those at war with them."],["وَسِلْمٌ لِّمَن سَالَمَهُمْ،","I am at peace with those at peace with them."],["وَعَدُوُّ لِّمَنْ عَادَاهُمْ،","I am the enemy of their enemies"],["وَمُحِبٌّ لِّمَنْ أَحَبَّهُمْ،","And I am the friend of their friends."],["إِنَّهُم مِّنِّي، وَأَنَا مِنْهُمْ،","They are from me and I am from them."],["فَاجْعَلْ صَلَوَاتِكَ وَبَرَكَاتِكَ وَرَحْمَتِكَ وَغُفْرَانِكَ وَرِضْوَانِكَ عَلَيَّ وَعَلَيْهِمْ وَأَذْهِبْ عَنْهُمُ الرِّجْسَ وَطَهِّرهُمْ تَطْهِيراً","O Allah! Bestow Your Blessings, Benevolence, Forgiveness and Your pleasure upon me and upon them. And remove impurity from them and keep them thoroughly pure\""],["فَقَالَ اللَّهُ عَزَّ وَجَلَّ:","Then the Lord, Almighty Allah said:"],["يَا مَلآئِكَتِى وَيَا سُكَّانَ سَمَاوَاتِى إِنِّى مَا خَلَقْتُ سَمَآءً مَّبْنِيَّةً وَّلا أَرْضاً مَّدْحِيَّةً وَّلا قَمَراً مُّنِيراً وَّلا شَمْساً مُّضِيئَةً وَّلا فَلَكاً يَّدُوْرُ وَلا بَحْراً يَّجْرِى وَلا فُلْكاً يَّسْرِى إِلا فِى مَحَبَّةِ هَؤُلاءِ الْخَمْسَةِ الَّذِيْنَ هُمْ تَحْتَ الْكِسَآءِ","\"O My angles! O Residents of My Heavens, verily, I have not created the erected Sky, the stretched earth, the illuminated moon, the bright sun, the rotating planets, the flowing seas and the sailing ships, but for the love of these Five lying underneath the cloak\""],["فَقَالَ الأَمِينُ جِبْرَآئِيْلُ: يَا رَبِّ وَمَن تَحْتَ الْكِسَآءِ","Gabriel, the trusted angle, asked: \"Who are under the cloak?\""],["فَقَالَ عَزَّ وَجَلَّ: هُمْ أَهْلُ بَيْتِ النُّبُوَّةِ وَمَعْدِنُ الرِّسَالَةِ، هُمْ فَاطِمَةُ وَأَبُوهَا وَبَعْلُهَا وَبَنُوْهَا","The Almighty answered: \"They are the Household of the Prophet and the assets of Prophethood. They are: Fatimah, his daughter, her husband and her two sons\""],["فَقَالَ جِبْرَآئِيْلُ: يَا رَبِّ أَتَأْذَنُ لِى أَنْ أَهْبِطَ إِلَى الأَرْضِ لأَكُوْنَ مَعَهُمْ سَادِساً","Gabriel said:\" O Lord, May I fly to earth to be the sixth of them?"],["فَقَالَ اللَّهُ : نَعَمْ قَدْ أَذِنتُ لَكَ","Allah replied:\" Yes. You are given the permission\""],["فَهَبَطَ الأَمِينُ جِبْرَآئِيْلُ وَقَالَ : السَّلاَمُ عَلَيْكَ يَا رَسُولَ اللَّهِ، الْعَلِيُّ الأَعْلَى يُقْرِئُكَ السَّلاَمَ وَيَخُصُّكَ بِالتَّحِيَّةِ وَالإِكْرَامْ وَيَقُوْلُ لَكَ:","Gabriel, the trusted, landed near them and said: \"Peace be on you, O Prophet of Allah. The All-Highest conveys His peace on you and His greetings and says:"],["وَعِزَّتِى وَجَلاَلِى إِنِّى مَا خَلَقْتُ سَمَآءً مَّبْنِيَّةً وَّلا أَرْضاً مَّدْحِيَّةً وَّلا قَمَراً مُّنِيراً وَلا شَمْساً مُّضِيئَةً وَّلا فَلَكاً يَّدُوْرُ وَلا بَحْراً يَّجْرِى وَلا فُلْكاً يَّسْرِى إِلا لأَجْلِكُمْ وَمَحَبَّتِكُمْ،","\"By My Honor and Glory, \"O My angles! O Residents of My Heavens, verily, I have not created the erected Sky, the stretched earth, the illuminated moon, the bright sun, the rotating planets, the flowing seas and the sailing ships, but for your sake and love\""],["وَقَدْ أَذِنَ لِى أَنْ أَدْخُلَ مَعَكُمْ، فَهَلْ تَأْذَنُ لِى يَا رَسُولَ اللَّهِ","God has given me permission to enter the cloak with you. May I join you, O Prophet of Allah?\""],["فَقَالَ رَسُولُ اللَّهِ : وَعَلَيْكَ السَّلاَمُ يَآ أَمِيْنَ وَحْيِ اللَّهِ، نَعَمْ قَدْ أَذِنتُ لَكَ","The Prophet replied: \"And peace be on you, O trusted bearer of Allah's Revelations!, you are granted the permission\""],["فَدَخَلَ جِبْرَآئِيْلُ مَعَنَا تَحْتَ الْكِسَآءِ فَقَالَ لأَبِي: إِنَّ اللَّهَ قَدْ أَوْحَى إِلَيْكُمْ يَقُولُ:","So, Gabriel entered the cloak with us and said to my father: \"Allah sends His Revelations to you"],["إِنَّمَا يُرِيدُ ٱللَّهُ لِيُذۡهِبَ عَنڪُمُ ٱلرِّجۡسَ أَهۡلَ ٱلۡبَيۡتِ وَيُطَهِّرَكُمۡ تَطۡهِيرً۬ا","\" Verily Allah's desire is to remove blemish from you, O People of Household (Ahlul-Bayt) and purify you with a perfect purification\""],["فَقَالَ عَلِيٌّ لأَبِي: يَا رَسُولَ اللَّهِ أَخْبِرْنِي، مَا لِجُلُوسِنَا هَذَا تَحْتَ الْكِسَآءِ مِنَ الْفَضْلِ عِندَ اللَّهِ","Then Ali said to my father:\" O Prophet of Allah, tell me, what significance has Allah given for getting together underneath this cloak?\""],["فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَآلِهِ: وَالَّذِى بَعَثَنِى باِلْحَقِّ نَبِيَّاً وَّاصْطَفَانِى بِالرِّسَالَةِ نَجِّيًّا","The Prophet replied: \"By Him who rightfully appointed me a Prophet and chose me a Messenger for the salvation of the mankind,"],["مَّا ذُكِرَ خَبرُنَا هَذَا فِى مَحْفَلٍ مِّن مَّحَافِلِ أَهْلِ الأَرْضِ وَفِيْهِ جَمْعٌ مِّن شِيْعَتِنَا وَمُحِبِّيْنَا إِلا","whenever and wherever an assembly of our followers and friends mention this event,"],["وَنَزَلَتْ عَلَيْهِمُ الرَّحْمَةُ","Allah will bestow on them His Blessings and Mercy;"],["وَحَفَّتْ بِهِمُ الَمَلآئِكَةُ وَاسْتَغْفَرَتْ لَهُمْ إِلَى أَن يَّتَفَرَّقُوا","angles will encircle them asking Allah the remission of their sins until the assembly disperse"],["فَقَالَ عَلِيٌّ عَلَيْهِ السَّلاَمُ: إِذًا وَّ اللَّهِ فُزْنَا وَفَازَ شِيْعَتُنَا وَرَبِّ الْكَعْبَةِ","So Ali said:\" Verily, by the Lord of Kaaba!, we and our followers are the winners\""],["فَقَالَ أَبِيْ رَسُوْلُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَآلِهِ: يَا عَلِيُّ وَ الَّذِى بَعَثَنِى بِالْحَقِّ نَبِيًّا وَّاصْطَفَانِى باِلرِّسَالَةِ نَجِيًّا","Then my father replied: \"By Him who rightfully appointed me a Prophet and chose me a Messenger for the salvation of the mankind,"],["مَّا ذُكِرَ خَبرُنَا هَذَا فِى مَحْفَلٍ مِّن مَّحَافِلِ أَهْلِ الأَرْضِ وَفِيْهِ جَمْعٌ مِّن شِيْعَتِنَا وَمُحِبِّيْنَا وَفِيْهِم","whenever and wherever an assembly of our followers and friends mention this event,"],["مَّهْمُوْمٌ إِلا وَفَرَّجَ اللَّهُ هَمَّهُ وَلاَ","there shall remain none grieved but Allah will remove his grief,"],["مَغْمُوْمٌ إِلا وَكَشَفَ اللَّهُ غَمَّهُ","there shall remain none distressed but Allah will dispel his distress,"],["وَلا طَاِلبُ حَاجَةٍ إِلا وَقَضَى اللَّهُ حَاجَتَهُ","there shall remain none wish-seeker but Allah will grant his wish."],["فَقَالَ عَلِيٌّ عَلَيْهِ السَّلاَمُ: إِذًا وَّاللَّهِ فُزْنَا وَسُعِدْنَا وَكَذَلِكَ شِيْعَتُنَا فَازُوا وَسُعِدُوا فِى الدُّنيَا وَالآخِرَةِ وَرَبِّ الْكَعْبَةِ","Ali happily said: \"Verily, by the Lord of Kaaba! we and our followers are the winners and the blessed, in this world and the next.\""]]}];